INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('e7c47a3e-22ac-4162-9405-b2b0c7a86740','句  其四','楊徽之','宋','宋诗','song-poetry','','[]','廢宅寒塘水，荒墳宿草烟。',12,'全唐诗/poet.song.0.json','["廢宅寒塘水，荒墳宿草烟。"]'),
('b389a0b9-585e-4dfc-beb6-25012cdcfb2c','句  其五','楊徽之','宋','宋诗','song-poetry','','[]','青帝已教春不老，素娥何惜月長圓。',16,'全唐诗/poet.song.0.json','["青帝已教春不老，素娥何惜月長圓。"]'),
('ab1107be-0a19-4d8f-b8ca-07d3d43a9d3f','句  其六','楊徽之','宋','宋诗','song-poetry','','[]','浮花水入瞿塘峽，带雨雲歸越嶲州。',16,'全唐诗/poet.song.0.json','["浮花水入瞿塘峽，带雨雲歸越嶲州。"]'),
('5252b7fa-bbf7-4ce9-bb2f-b4be23dc11e6','句  其七','楊徽之','宋','宋诗','song-poetry','','[]','春歸萬年樹，月滿九重城。',12,'全唐诗/poet.song.0.json','["春歸萬年樹，月滿九重城。"]'),
('287c2d90-4a1a-4998-8cd8-f3f30ab259aa','句  其八','楊徽之','宋','宋诗','song-poetry','','[]','開盡菊花秋色老，落殘桐葉雨聲寒。',16,'全唐诗/poet.song.0.json','["開盡菊花秋色老，落殘桐葉雨聲寒。"]'),
('ad0af24e-189c-4507-9ba3-098fd217a87f','句  其九','楊徽之','宋','宋诗','song-poetry','','[]','少年牢落今何幸，叨遇君王問姓名。',16,'全唐诗/poet.song.0.json','["少年牢落今何幸，叨遇君王問姓名。"]'),
('533e13df-9eb8-4101-9288-067f5efb5ef0','句  其一○','楊徽之','宋','宋诗','song-poetry','','[]','杳杳烟蕪何處盡，摇摇風柳不勝垂。',16,'全唐诗/poet.song.0.json','["杳杳烟蕪何處盡，摇摇風柳不勝垂。"]'),
('c2d7709d-5979-48ec-be6a-a51de19dfaec','句  其一一','楊徽之','宋','宋诗','song-poetry','','[]','江流嶓冢雨，路入漢家山。',12,'全唐诗/poet.song.0.json','["江流嶓冢雨，路入漢家山。"]'),
('f47ecac3-1a0a-4ead-9ce9-ca68ba5a1b14','句  其一二','楊徽之','宋','宋诗','song-poetry','','[]','山雲收雨半川晴。',8,'全唐诗/poet.song.0.json','["山雲收雨半川晴。"]'),
('68b34a8b-3985-4c90-a167-7a4fa79ba731','句  其一三','楊徽之','宋','宋诗','song-poetry','','[]','少孤心易感。',6,'全唐诗/poet.song.0.json','["少孤心易感。"]'),
('fb8b5ca2-6610-4dae-a29f-f8ecaf9ff588','謝進士張翼投詩兩軸','王溥','宋','宋诗','song-poetry','','[]','清河詩客本賢良，惠我新吟六十章。',64,'全唐诗/poet.song.0.json','["清河詩客本賢良，惠我新吟六十章。", "格調宛同羅給事，功夫深似賈司倉。", "登山始覺天高廣，到海方知浪渺茫。", "好去蟾宮是歸路，明年應折桂枝香。"]'),
('47026628-7f4d-4360-a7c3-4d384e92943a','寄鄧洵美','王溥','宋','宋诗','song-poetry','','[]','衡陽歸雁別重湖，銜到同人一紙書。',64,'全唐诗/poet.song.0.json','["衡陽歸雁別重湖，銜到同人一紙書。", "忽見姓名雙淚落，不知消息十年餘。", "彩衣我已登黄閣，白社君猶葺舊居。", "南望荆門千里外，暮雲重疊滿晴虛。"]'),
('cfcc9bb2-0bbf-416c-8e3b-aedf99728b79','詩一首','王溥','宋','宋诗','song-poetry','','[]','揮毫文戰偶搴旗，待詔金華亦偶爲。',64,'全唐诗/poet.song.0.json','["揮毫文戰偶搴旗，待詔金華亦偶爲。", "白社遽當宗伯選，赤心旋遇聖人知。", "九霄得路榮雖極，三接承恩出每遲。", "職在臺司多少暇，親師不及舞雩時。"]'),
('127de090-3507-48d6-abbf-3747b4e09684','句  其一','王溥','宋','宋诗','song-poetry','','[]','兩制職官三十客，自憐榮耀老萊衣。',16,'全唐诗/poet.song.0.json','["兩制職官三十客，自憐榮耀老萊衣。"]'),
('0995f5c2-e07d-41b8-91f3-85137c1e9845','句  其二','王溥','宋','宋诗','song-poetry','','[]','又向靈臺飲福杯。',8,'全唐诗/poet.song.0.json','["又向靈臺飲福杯。"]'),
('ee6b786e-6291-456a-9475-55ee104c7f06','偈','釋智勤','宋','宋诗','song-poetry','','[]','今年五十五，脚未蹋寸土。',24,'全唐诗/poet.song.0.json','["今年五十五，脚未蹋寸土。", "山河是眼睛，大海是我肚。"]'),
('9cdf1a3c-8858-4fc2-b94c-bb73dc294218','答僧','釋遇安','宋','宋诗','song-poetry','','[]','欲識曹溪旨，雲飛前面山。',24,'全唐诗/poet.song.0.json','["欲識曹溪旨，雲飛前面山。", "分明真實箇，不用別追攀。"]'),
('ce766629-430d-41e2-96f8-f73de098b6d0','偈','釋海印','宋','宋诗','song-poetry','','[]','道本無爲，法非延促。',64,'全唐诗/poet.song.0.json','["道本無爲，法非延促。", "一念萬年，千古在目。", "月白風恬，山青水綠。", "法法現前，頭頭具足。", "祖意教意，非直非曲。", "要識廬陵米價，會取山前麥熟。"]'),
('74d5c894-b2c0-4097-bb35-5386f0c3148a','雪中駕幸敝廬恭紀','趙普','宋','宋诗','song-poetry','','[]','貞元重數莢，滕六劇霏花。',180,'全唐诗/poet.song.0.json','["貞元重數莢，滕六劇霏花。", "漠漠初濡砌，皚皚欲聚沙。", "閭閻銀作界，宮闕玉爲家。", "調鼎慚鹽撒，霑溫覺絮加。", "瑞凝三殿瓦，欣動五雲車。", "冰柱撐茅屋，瓊枝擁翠華。", "微行停蹕警，冷漏靜街譁。", "具野曾無隗，磻溪豈問牙。", "公然門駐輦，那信室盤蝸。", "積素堪麟畫，飛黄想兔罝。", "一庭看曳練，十道趣宣麻。", "戎索籌先後，雄才辨等差。", "神威殷地軸，御指落天花。", "表賀甘朝穩，裴功敢夜誇。", "雪山行獻琯，早晚到星槎。"]'),
('91ec1a26-49e6-4054-b645-8e12105c074f','贈道士吳崇岳','周渭','宋','宋诗','song-poetry','','[]','楮爲冠子布爲裳，吞得丹霞壽最長。',64,'全唐诗/poet.song.0.json','["楮爲冠子布爲裳，吞得丹霞壽最長。", "混俗性靈常樂道，出塵風格早休糧。", "枕中經妙誰傳與，肘後方新自寫將。", "百尺松梢幾飛步，鶴棲枝上禮虛皇。"]'),
('1ff71672-4cbe-46b2-902b-4b6cec1ac9d0','疊秀山','周渭','宋','宋诗','song-poetry','','[]','平生賦性愛觀瀾，今日登臨疊秀山。',64,'全唐诗/poet.song.0.json','["平生賦性愛觀瀾，今日登臨疊秀山。", "天錫卦爻分象外，地將圭笏出人間。", "昭州水遶孤城小，五嶺山高衆垤難。", "極目紫宸何處是，碧雲深處珮珊珊。"]'),
('4dc5c4d7-c4ee-4a95-bede-9bad317fb73a','遊兼山','周渭','宋','宋诗','song-poetry','','[]','插空峭壁白雲迷，獨上高巔萬象低。',64,'全唐诗/poet.song.0.json','["插空峭壁白雲迷，獨上高巔萬象低。", "一路接天連楚界，兩峰拔地鎮南夷。", "泉飛石澗遊魂冷，風捲松濤匹馬嘶。", "踏破層崖心未折，鳳凰山後鷓鴣啼。"]'),
('b6b8780d-c19c-463b-b999-e5beaad279e0','重門曲','周濆','宋','宋诗','song-poetry','','[]','憔悴榮華怯對春，寂寥宮殿鎖閒門。',32,'全唐诗/poet.song.0.json','["憔悴榮華怯對春，寂寥宮殿鎖閒門。", "此身却羨宮中樹，不失芳時雨露恩。"]'),
('629a66ec-b87b-4edd-9ac7-f243ae6e9d2f','山下水','周濆','宋','宋诗','song-poetry','','[]','背雲衝石出深山，淺碧泠泠一带寒。',32,'全唐诗/poet.song.0.json','["背雲衝石出深山，淺碧泠泠一带寒。", "不獨有聲流出此，會歸滄海助波瀾。"]'),
('057248d0-aa49-4aee-916b-a0a5fbb826d6','逢鄰女','周濆','宋','宋诗','song-poetry','','[]','日高鄰女笑相逢，慢束羅裙半露胸。',32,'全唐诗/poet.song.0.json','["日高鄰女笑相逢，慢束羅裙半露胸。", "莫向秋池照綠水，參差羞殺白芙蓉。"]'),
('7c5c27c2-da30-4c45-ad91-c74c5e22eae5','廢宅','周濆','宋','宋诗','song-poetry','','[]','牢落畫堂空鎖塵，荒凉庭樹暗消春。',32,'全唐诗/poet.song.0.json','["牢落畫堂空鎖塵，荒凉庭樹暗消春。", "豪家莫笑此中事，曾見此中人笑人。"]'),
('d6fd8360-a8b0-4ffb-9121-d044d1c0770a','以蜀箋寄弟洎','韓溥','宋','宋诗','song-poetry','','[]','十樣蠻牋出益州，寄來新自浣溪頭。',32,'全唐诗/poet.song.0.json','["十樣蠻牋出益州，寄來新自浣溪頭。", "老兄得此全無用，助爾添修五鳳樓。"]'),
('7d48e850-1b42-464b-86cd-ed5ab8c516c4','奉揚英公大師詩匠','韓溥','宋','宋诗','song-poetry','','[]','悟解真空始壯年，兩朝供奉近爐烟。',64,'全唐诗/poet.song.0.json','["悟解真空始壯年，兩朝供奉近爐烟。", "故鄉夢斷三湘遠，應制詩高四海傳。", "晴望野雲生紫閣，夜吟蘭燭滴花牋。", "應愁內殿徵書至，恐向東林負昔緣。"]'),
('c872b8c2-4e4f-4aeb-bb01-54faf5fb16fc','句','陶彝','宋','宋诗','song-poetry','','[]','生凉好喚雞蘇佛，回味宜稱橄欖仙。',16,'全唐诗/poet.song.0.json','["生凉好喚雞蘇佛，回味宜稱橄欖仙。"]'),
('fd1b7735-40a2-41b7-bae0-9d31e4b1ba2d','南陽酇詩','王祜','宋','宋诗','song-poetry','','[]','置酒向南宮，分明將將雄。',48,'全唐诗/poet.song.0.json','["置酒向南宮，分明將將雄。", "指蹤爲第一，大國賞元戎。", "似續惟人傑，危忘盡狗功。", "賢哉垂儉德，千古仰清風。"]'),
('24f5540d-3515-4a3d-bec4-d20804fef514','贈率子連  其一','王祜','宋','宋诗','song-poetry','','[]','下瞰虛空臨絕澗，上排烟霧倚山顛。',32,'全唐诗/poet.song.0.json','["下瞰虛空臨絕澗，上排烟霧倚山顛。", "四邊險絕無猿鳥，獨卧深雲三十年。"]'),
('618aa479-3b8b-4746-a7ba-02dbd1a6647d','贈率子連  其二','王祜','宋','宋诗','song-poetry','','[]','古星當崖映日間，年年常伴白雲閑。',32,'全唐诗/poet.song.0.json','["古星當崖映日間，年年常伴白雲閑。", "糇糧丹火何從出，四面無人見下山。"]'),
('2276958a-24e4-4fad-a48f-bace26af5bfc','贈率子連  其三','王祜','宋','宋诗','song-poetry','','[]','心意逍遥物莫知，山中山下識人稀。',32,'全唐诗/poet.song.0.json','["心意逍遥物莫知，山中山下識人稀。", "想君絕慮離塵土，不是王喬即令威。"]'),
('6a34f52f-e71b-4b25-ac90-91ddd18e9a9f','句  其一','王祜','宋','宋诗','song-poetry','','[]','花片已隨山下水，雲層虛鎖河中春。',16,'全唐诗/poet.song.0.json','["花片已隨山下水，雲層虛鎖河中春。"]'),
('7a4dae7d-77f9-4af0-a77c-8e09f5c3e2c7','句  其二','王祜','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','詩狂直欲吞雲霧，酒渴何妨吸洞庭。',16,'全唐诗/poet.song.0.json','["詩狂直欲吞雲霧，酒渴何妨吸洞庭。"]'),
('352c0716-1cce-484c-8850-ced129888cef','祜公榮歸','趙存佐','宋','宋诗','song-poetry','','[]','任重功餘屢乞辭，犯顔曾不避天威。',32,'全唐诗/poet.song.0.json','["任重功餘屢乞辭，犯顔曾不避天威。", "朝回一體奎章下，携得天香滿袖歸。"]'),
('72ced332-bb34-4ae3-aff1-d1ffedee6226','內宴奉詔作','曹翰','宋','宋诗','song-poetry','','[]','三十年前學六韜，英名常得預時髦。',64,'全唐诗/poet.song.0.json','["三十年前學六韜，英名常得預時髦。", "曾因國難披金甲，不爲家貧賣寶刀。", "臂健尚嫌弓力軟，眼明猶識陣雲高。", "庭前昨夜秋風起，羞睹盤花舊戰袍。"]'),
('d803c32e-0424-4f08-a004-d4cfd7262f88','贈緣德','曹翰','宋','宋诗','song-poetry','','[]','二十年來訪道人，奔波寒暑備艱辛。',64,'全唐诗/poet.song.0.json','["二十年來訪道人，奔波寒暑備艱辛。", "誰知此日圓通會，便是今生出世因。", "爐里有丹欣得遇，法中無語幸相親。", "如何至訣容傳受，免向迷途强問津。"]'),
('336c2f56-2577-4242-8ad3-2ad3c4c81946','將卒示嗣子藴仁','釋遇安','宋','宋诗','song-poetry','','[]','不是嶺頭携得事，豈從雞足付將來。',32,'全唐诗/poet.song.0.json','["不是嶺頭携得事，豈從雞足付將來。", "自古聖賢皆若此，非吾今日爲君裁。"]'),
('eb2ce99e-2a2b-43bf-8cbc-f531488d228b','呈韶國師偈','釋遇安','宋','宋诗','song-poetry','','[]','推真真無物，窮妄妄無形。',24,'全唐诗/poet.song.0.json','["推真真無物，窮妄妄無形。", "返觀真與妄，真妄亦虛名。"]'),
('6ac1bb5c-7f05-41f8-8890-82d839f51770','鷺鷥','曹衍','宋','宋诗','song-poetry','','[]','波瀾靜處立身孤，氄雪攢霜腹轉虛。',32,'全唐诗/poet.song.0.json','["波瀾靜處立身孤，氄雪攢霜腹轉虛。", "盡日灘頭延頸望，能銷大海幾多魚。"]'),
('8bbddabd-6705-4de2-ad38-b86d3ac03325','貧女','曹衍','宋','宋诗','song-poetry','','[]','自恨無媒出嫁遲，老來方始遇佳期。',32,'全唐诗/poet.song.0.json','["自恨無媒出嫁遲，老來方始遇佳期。", "滿頭白髮爲新婦，笑殺豪家年少兒。"]'),
('643654f3-df88-4df8-9be2-08d092a7e5e3','和李昉','鄧洵美','宋','宋诗','song-poetry','','[]','詞場幾度讓長鞭，又向清朝賀九遷。',64,'全唐诗/poet.song.0.json','["詞場幾度讓長鞭，又向清朝賀九遷。", "品秩雖然殊此日，歲寒終不改當年。", "馳名早已超三院，侍直仍忻步八磚。", "今日相逢番自愧，閑吟對酒倍潸然。"]'),
('7bb0df95-95c6-4db5-8c11-30470a5cd909','句  其一','胡君防','宋','宋诗','song-poetry','','[]','避世一處士，傳家三詔書。',12,'全唐诗/poet.song.0.json','["避世一處士，傳家三詔書。"]'),
('ea682c93-94d9-4a9f-a6bc-71369221b633','句  其二','胡君防','宋','宋诗','song-poetry','','[]','桄榔雨醉江城夜，橄欖風吟野驛秋。',16,'全唐诗/poet.song.0.json','["桄榔雨醉江城夜，橄欖風吟野驛秋。"]'),
('0b4f9d0d-f76a-448a-9507-8285e90fb98c','句  其三','胡君防','宋','宋诗','song-poetry','','[]','樓臺舊地牛羊滿，宮殿遺基禾黍平。',16,'全唐诗/poet.song.0.json','["樓臺舊地牛羊滿，宮殿遺基禾黍平。"]'),
('09c34306-5e86-49fb-a0e2-3aaeb1f3588a','句  其四','胡君防','宋','宋诗','song-poetry','','[]','島日斜明僧寺閣，汀雲低影客船窗。',16,'全唐诗/poet.song.0.json','["島日斜明僧寺閣，汀雲低影客船窗。"]'),
('8692b0e7-e144-4f6a-a915-537f5dcbd1c7','句  其五','胡君防','宋','宋诗','song-poetry','','[]','水邊閑詠處，雲島月斜明。',12,'全唐诗/poet.song.0.json','["水邊閑詠處，雲島月斜明。"]'),
('803d18eb-eb93-489d-b483-b2832c47c2fc','小園獨坐偶賦所懷寄秘閣侍郎','李昉','宋','宋诗','song-poetry','','[]','烟光澹澹思悠悠，朝退還家懶出遊。',64,'全唐诗/poet.song.0.json','["烟光澹澹思悠悠，朝退還家懶出遊。", "靜坐最憐紅日永，新晴更助小園幽。", "砌苔點點青錢小，窗竹森森綠玉稠。", "賓友不來春又晚，眼看辜負一年休。"]'),
('3616d6ba-ebe6-4238-8c17-92378b472634','偶述所懷寄秘閣侍郎','李昉','宋','宋诗','song-poetry','','[]','何事情懷鬰不開，爲思蓬閣謫仙才。',64,'全唐诗/poet.song.0.json','["何事情懷鬰不開，爲思蓬閣謫仙才。", "通宵空有夢魂去，隔月更無篇詠來。", "夜室已聞啼蟋蟀，秋庭惟見長莓苔。", "清晨懶把菱花照，兩鬢如絲堪自咍。"]'),
('d0bf708a-b9f0-4fa0-986a-f9f53edf4fe9','偶書口號寄秘閣侍郎','李昉','宋','宋诗','song-poetry','','[]','朝退歸來只在家，詩書滿架是生涯。',64,'全唐诗/poet.song.0.json','["朝退歸來只在家，詩書滿架是生涯。", "吟成拙句何人和，按得新聲沒處誇。", "夜景最憐蟾影潔，秋空時見雁行斜。", "望君偷暇來相訪，猶有東籬殘菊花。"]'),
('3c1fd382-2126-4236-bce1-4ebf21b24418','獨賞牡丹因而成詠','李昉','宋','宋诗','song-poetry','','[]','遶東叢了遶西叢，爲愛叢叢紫閒紅。',64,'全唐诗/poet.song.0.json','["遶東叢了遶西叢，爲愛叢叢紫閒紅。", "怨望乍疑啼曉霧，妖饒渾欲殢春風。", "香苞半綻丹砂吐，細朵齊開烈焰烘。", "病老情懷慢相對，滿欄應笑白頭翁。"]'),
('adbee426-be40-489a-88c2-da5b0da51992','依韻和殘春有感  其一','李昉','宋','宋诗','song-poetry','','[]','暮春三月思依依，又到年年惜別時。',64,'全唐诗/poet.song.0.json','["暮春三月思依依，又到年年惜別時。", "暖逼流鶑藏密樹，香迷舞蝶戀空枝。", "海棠殘艷紅鋪地，蜀柳長條翠拂池。", "便是林亭微暑至，葛衣重喜趁凉披。"]'),
('46a83a71-4e34-4662-a815-b3de4065a701','依韻和殘春有感  其二','李昉','宋','宋诗','song-poetry','','[]','夜來微雨曉來風，春色都歸悵望中。',64,'全唐诗/poet.song.0.json','["夜來微雨曉來風，春色都歸悵望中。", "楊柳带烟嚬細綠，牡丹和露泣殘紅。", "嬌鶑遶樹聲初老，野草連門路近通。", "韶景欲留留不住，西園悶殺雪髯翁。"]'),
('653da15e-c989-4333-a7fe-b03e2469b15a','和喜雨','李昉','宋','宋诗','song-poetry','','[]','溟濛烟景似江臯，靜賞何須郭外遨。',64,'全唐诗/poet.song.0.json','["溟濛烟景似江臯，靜賞何須郭外遨。", "點點暗滋花氣色，祁祁盡作麥脂膏。", "洗開玳瑁湘妃竹，裛損烟脂阿母桃。", "昨日君王倚欄看，東風吹濕赭黄袍。"]'),
('50f7b038-6218-4250-a1af-3b2b38cf50e7','依韻奉和見貽之什且以答來章而歌盛美也','李昉','宋','宋诗','song-poetry','','[]','逢丘深靜養疏慵，角枕斜欹數過鴻。',64,'全唐诗/poet.song.0.json','["逢丘深靜養疏慵，角枕斜欹數過鴻。", "萬事不關思想內，一心長在詠歌中。", "昂藏鶴貌無凡態，冷淡琴聲有古風。", "共說聖君偏注意，朝昏須作黑頭公。"]'),
('7424a5c7-d172-4f26-8316-e7f9b3cda7b9','攀和嘉篇','李昉','宋','宋诗','song-poetry','','[]','小亭愁坐對殘陽，梧葉翻階片片黄。',64,'全唐诗/poet.song.0.json','["小亭愁坐對殘陽，梧葉翻階片片黄。", "老去只添新悵望，病餘無復舊歡狂。", "四時奔速都如電，兩鬢凋疏總作霜。", "看取衰容今若此，有何情緒聽宮商。"]'),
('446fe37e-9daf-4b60-832f-d5f4b4a28bf8','聞館中宣賜賞雪賦詩之會書五十六字呈秘閣侍郎','李昉','宋','宋诗','song-poetry','','[]','聖主憐才古所稀，轉知吾道有光輝。',64,'全唐诗/poet.song.0.json','["聖主憐才古所稀，轉知吾道有光輝。", "特宣秘府羣仙會，教看遥空六出飛。", "痛飲不容停盞斝，冥搜各要鬭珠璣。", "仍聞中使傳中旨，須盡歡娛酩酊歸。"]'),
('6870475a-44ad-48ea-a788-221897426da0','宿雨初晴春風頓至小園獨步方多索寞之懷嘉句忽來驟引吟哦之興仰攀高韻少達鄙誠','李昉','宋','宋诗','song-poetry','','[]','融融和氣滿亭臺，寂絕無人訪我來。',64,'全唐诗/poet.song.0.json','["融融和氣滿亭臺，寂絕無人訪我來。", "忽喜貳卿篇詠至，如聞三島信音迴。", "偷閑旋要償詩債，減俸惟將買樹栽。", "春旦兩壺宣賜酒，一壺留著待君開。"]'),
('55e68b8e-4966-4109-a468-93d5a8d779b3','老病相攻偶成長句寄秘閣侍郎','李昉','宋','宋诗','song-poetry','','[]','衰病增加我斗諳，頭風目眩一般般。',64,'全唐诗/poet.song.0.json','["衰病增加我斗諳，頭風目眩一般般。", "縱逢盃酒都無味，任聽笙歌亦寡歡。", "朝退便思親枕簟，客來多倦著衣冠。", "行行漸近懸車歲，轉恐君恩報答難。"]'),
('e303f487-c3dd-4850-9ba7-056905a1fd16','寄秘閣侍郎','李昉','宋','宋诗','song-poetry','','[]','楮冠仍用竹爲簪，隨分林亭自稱心。',64,'全唐诗/poet.song.0.json','["楮冠仍用竹爲簪，隨分林亭自稱心。", "病裏亦難全斷酒，老來無柰更躭吟。", "閑行策杖青苔逕，靜坐移床綠樹陰。", "時有新詩寄何處，蓬丘仙客是知音。"]'),
('6d3688fe-c508-4e8a-96bb-72b837dfdceb','輒歌盛美寄秘閣侍郎','李昉','宋','宋诗','song-poetry','','[]','滿朝清望更誰如，才略文章盡有餘。',64,'全唐诗/poet.song.0.json','["滿朝清望更誰如，才略文章盡有餘。", "避寵怕聞調鼎鼐，愛閑專喜掌圖書。", "歌詩唱和心偏樂，勢利奔趨跡自疏。", "恰與宗兄性相近，好來城外卜鄰居。"]'),
('a795e158-db36-403c-b738-dc2ca799f4d9','更依前韻上獻惡詩搜吟雖罄於短才歌詠寧窮於盛美','李昉','宋','宋诗','song-poetry','','[]','茂陵詞客馬相如，貯蓄胸中萬卷餘。',64,'全唐诗/poet.song.0.json','["茂陵詞客馬相如，貯蓄胸中萬卷餘。", "閑坐小齋惟看畫，旋分清俸只抄書。", "檻花灼灼韶光盛，庭竹森森翠影疏。", "晨入蓬山暮歸去，到歸多是閉門居。"]'),
('01145823-eaeb-41b6-a22c-514f97b5ca3c','昉著灸數朝廢吟累日繼披佳什莫匪正聲亦貢七章補爲十首學顰之誚誠所甘心  其一','李昉','宋','宋诗','song-poetry','','[]','心情休問近何如，冉冉浮生六十餘。',64,'全唐诗/poet.song.0.json','["心情休問近何如，冉冉浮生六十餘。", "抱病久無歡笑興，信緣慵答往還書。", "容顔也道隨年改，牙齒誰教斗頓疏。", "何處此身堪養老，萬安山下有村居。"]'),
('e2a10476-da2e-40b3-bfac-4d91b2f0327d','昉著灸數朝廢吟累日繼披佳什莫匪正聲亦貢七章補爲十首學顰之誚誠所甘心  其二','李昉','宋','宋诗','song-poetry','','[]','行年已老擬何如，手植園林十畝餘。',64,'全唐诗/poet.song.0.json','["行年已老擬何如，手植園林十畝餘。", "婢僕盡能修藥餌，兒孫親教讀經書。", "趨時徇俗誠爲拙，守道安身未必疏。", "惟望多情蓬島客，偷閑時訪野人居。"]'),
('6aa08603-f0a8-41bf-9b3f-a7b135648fd1','昉著灸數朝廢吟累日繼披佳什莫匪正聲亦貢七章補爲十首學顰之誚誠所甘心  其三','李昉','宋','宋诗','song-poetry','','[]','交朋相問興何如，不願家財有羨餘。',64,'全唐诗/poet.song.0.json','["交朋相問興何如，不願家財有羨餘。", "一卷佛經心諳誦，七篇真誥手親書。", "榮名厚祿都來足，酒興詩情積漸疏。", "多謝營巢舊時燕，又依時節到貧居。"]'),
('a337ba76-6158-4755-9f32-2326fe3418c7','昉著灸數朝廢吟累日繼披佳什莫匪正聲亦貢七章補爲十首學顰之誚誠所甘心  其四','李昉','宋','宋诗','song-poetry','','[]','歷官從宦復何如，冒寵叨榮最有餘。',64,'全唐诗/poet.song.0.json','["歷官從宦復何如，冒寵叨榮最有餘。", "五載濫批黄紙勑，半生曾典紫泥書。", "安民濟物才無取，報國酬恩志未疏。", "聖主憂邊心正切，若爲端坐自安居。"]'),
('0e6909a8-ad8e-4746-b195-b2591a2c646b','昉著灸數朝廢吟累日繼披佳什莫匪正聲亦貢七章補爲十首學顰之誚誠所甘心  其五','李昉','宋','宋诗','song-poetry','','[]','平生榮遇更誰如，竊位妨賢四紀餘。',64,'全唐诗/poet.song.0.json','["平生榮遇更誰如，竊位妨賢四紀餘。", "昔冠北門諸學士，今先南省六尚書。", "演綸豈有文章稱，調鼎仍慚績效疏。", "弭役銷兵恨無策，退朝長是閉門居。"]'),
('77260c66-ba32-4d66-9dbc-cb24d3e95f69','昉著灸數朝廢吟累日繼披佳什莫匪正聲亦貢七章補爲十首學顰之誚誠所甘心  其六','李昉','宋','宋诗','song-poetry','','[]','息念忘懷心晏如，隨宜生計不求餘。',64,'全唐诗/poet.song.0.json','["息念忘懷心晏如，隨宜生計不求餘。", "汲泉自溉新栽竹，借本重添舊欠書。", "唯仰酒盃相慰暖，敢嗟容鬢漸凋疏。", "澄波橋北多嫌遠，少有交朋到我居。"]'),
('a18d546c-5801-4075-9903-3ee974a2dbdf','昉著灸數朝廢吟累日繼披佳什莫匪正聲亦貢七章補爲十首學顰之誚誠所甘心  其七','李昉','宋','宋诗','song-poetry','','[]','清靜僧家亦未如，綠葵紅稻飽餐餘。',64,'全唐诗/poet.song.0.json','["清靜僧家亦未如，綠葵紅稻飽餐餘。", "逢人不喜談時事，養性惟便讀道書。", "來往自行三逕熟，過從每共四鄰疏。", "洛安郡裏東城下，一簇芳林是我居。"]'),
('8106218c-7d06-4d89-bb18-fc01da6fdf7a','將就十章更獻三首詞雖愈拙誠即可矜或歌執事之風猷或導鄙人之情志願寬捷給稍賜披尋  其一','李昉','宋','宋诗','song-poetry','','[]','曾逢禪客話真如，福逐緣生信有餘。',64,'全唐诗/poet.song.0.json','["曾逢禪客話真如，福逐緣生信有餘。", "謝傅兒孫皆幹蠱，鄭家姬妾盡知書。", "穩辭高位身心泰，中立明庭勢利疏。", "只恐欲閑閑不得，絳騶重引入宸居。"]'),
('99c77476-bfc1-4865-ab8a-cf86ed6c0c16','將就十章更獻三首詞雖愈拙誠即可矜或歌執事之風猷或導鄙人之情志願寬捷給稍賜披尋  其二','李昉','宋','宋诗','song-poetry','','[]','流年流矢亦爭如，不覺春秋四十餘。',64,'全唐诗/poet.song.0.json','["流年流矢亦爭如，不覺春秋四十餘。", "鳳闕有恩殊未報，麟臺無德豈堪書。", "眼前僥倖將何稱，身外貪求本自疏。", "唯擬從今作閑計，白雲深處買山居。"]'),
('e5b825c3-9006-4227-8886-8e1921798582','將就十章更獻三首詞雖愈拙誠即可矜或歌執事之風猷或導鄙人之情志願寬捷給稍賜披尋  其三','李昉','宋','宋诗','song-poetry','','[]','野性從來只澹如，奉身求足不求餘。',64,'全唐诗/poet.song.0.json','["野性從來只澹如，奉身求足不求餘。", "清風明月三間屋，赤軸黄籤一架書。", "午睡愛茶魚眼細，春餐費笋錦皮疏。", "比慚多病仍多告，猶擬分司洛下居。"]'),
('b849e3b7-e257-4136-b667-632356ab70af','對雨閑吟呈吏部侍郎','李昉','宋','宋诗','song-poetry','','[]','羃羃濃雲勢未收，森森凉氣忽如秋。',64,'全唐诗/poet.song.0.json','["羃羃濃雲勢未收，森森凉氣忽如秋。", "密籠芳樹飄何急，高卷疏簾看不休。", "咫尺莫聞人對語，逡巡已見水平流。", "此時遥憶諸君子，堪命棋枰與酒甌。"]'),
('7d16b1b8-124d-4081-abf5-54848ed9a548','自思忝幸因動詠吟','李昉','宋','宋诗','song-poetry','','[]','如蓬短髮不勝簪，筋力衰羸分所甘。',64,'全唐诗/poet.song.0.json','["如蓬短髮不勝簪，筋力衰羸分所甘。", "清職美官皆徧歷，物情時態盡深諳。", "乘軒服冕身可用，嘯月吟風意尚躭。", "安得故人頻會面，一罇相對共醺酣。"]'),
('59167eeb-1f5d-43d5-9533-93fc9093ae2f','暑雨初晴炎風稱解更逢連假甚適閑情竹軒正恣於高眠蓬閣忽貽於佳句一篇一詠雖許於唱酬載笑載言頗疏於陪接不蒙顧我深所慊懷敢次來章用伸微抱','李昉','宋','宋诗','song-poetry','','[]','一朝纔退掩衡門，如此爭能答聖恩。',64,'全唐诗/poet.song.0.json','["一朝纔退掩衡門，如此爭能答聖恩。", "病質尚慚紆組綬，閑心惟擬泥琴樽。", "行雖策杖身無力，卧亦看書眼漸昏。", "蓬閣神仙轉疏我，近來曾不訪西園。"]'),
('d582af59-44a5-4bc2-9808-a484bdf25d30','伏蒙侍郎見示蓬閣多餘暇詩十首調高情逸無以詠歌篇篇實爲絕倫一一尤難次韻强率鄙思別奉五章却以秘閣清虛地爲首句所謂效西子之顰也惟工拙之不同豈天壤之相接莞爾而笑其敢逃乎  其一','李昉','宋','宋诗','song-poetry','','[]','秘閣清虛地，深居好養賢。',48,'全唐诗/poet.song.0.json','["秘閣清虛地，深居好養賢。", "不聞塵外事，如在洞中天。", "日轉遲遲影，爐焚裊裊烟。", "應同白少傅，時復枕書眠。"]'),
('de07c9be-6d2b-42b6-8bad-873e4702f394','伏蒙侍郎見示蓬閣多餘暇詩十首調高情逸無以詠歌篇篇實爲絕倫一一尤難次韻强率鄙思別奉五章却以秘閣清虛地爲首句所謂效西子之顰也惟工拙之不同豈天壤之相接莞爾而笑其敢逃乎  其二','李昉','宋','宋诗','song-poetry','','[]','秘閣清虛地，仙材稱此居。',48,'全唐诗/poet.song.0.json','["秘閣清虛地，仙材稱此居。", "心輕萬鍾錄，性樂百王書。", "枕上漏聲近，窗前竹影疏。", "遲來稀見面，高興復何如。"]'),
('1f8ae43a-6d9a-4506-b5d8-de1dd5acb89a','伏蒙侍郎見示蓬閣多餘暇詩十首調高情逸無以詠歌篇篇實爲絕倫一一尤難次韻强率鄙思別奉五章却以秘閣清虛地爲首句所謂效西子之顰也惟工拙之不同豈天壤之相接莞爾而笑其敢逃乎  其三','李昉','宋','宋诗','song-poetry','','[]','秘閣清虛地，更無閑客過。',48,'全唐诗/poet.song.0.json','["秘閣清虛地，更無閑客過。", "身雖紆組綬，心若住烟蘿。", "架上羣書滿，階前敗葉多。", "知君自得意，其奈萬靈何。"]'),
('e266d885-a238-42b2-9c29-3d03f81d2f0f','伏蒙侍郎見示蓬閣多餘暇詩十首調高情逸無以詠歌篇篇實爲絕倫一一尤難次韻强率鄙思別奉五章却以秘閣清虛地爲首句所謂效西子之顰也惟工拙之不同豈天壤之相接莞爾而笑其敢逃乎  其四','李昉','宋','宋诗','song-poetry','','[]','秘閣清虛地，安然養道心。',48,'全唐诗/poet.song.0.json','["秘閣清虛地，安然養道心。", "無人接高論，遇興恣閑吟。", "筆閣珊瑚架，冠欺玳瑁簪。", "蒼生待康濟，未用憶雲林。"]'),
('c5bb5411-a6eb-4d49-8e43-cc0603831912','伏蒙侍郎見示蓬閣多餘暇詩十首調高情逸無以詠歌篇篇實爲絕倫一一尤難次韻强率鄙思別奉五章却以秘閣清虛地爲首句所謂效西子之顰也惟工拙之不同豈天壤之相接莞爾而笑其敢逃乎  其五','李昉','宋','宋诗','song-poetry','','[]','秘閣清虛地，優賢最得宜。',48,'全唐诗/poet.song.0.json','["秘閣清虛地，優賢最得宜。", "自持儒者行，徧受聖君知。", "道比朱弦直，心無暗室欺。", "宗兄雖暮齒，待看致雍熙。"]'),
('1cd3652e-7335-49f4-ada5-0f576a98fcc9','侍郎吟思愈清逸才無敵唱彌高而和彌寡我已竭而彼轉盈欲罷不能蓋彰其餘刃知難而退甘豎於降旗五章强振於蕪音三鼓那成於勇氣暫希解甲少遂息肩庶重整其懦兵願別當其堅陣此時勝負期一决焉却以地僻塵埃少爲首希垂采覽  其一','李昉','宋','宋诗','song-poetry','','[]','地僻塵埃少，幽居一院清。',48,'全唐诗/poet.song.0.json','["地僻塵埃少，幽居一院清。", "自題花色號，暗記樹根莖。", "竹撼蕭疏影，松摇淅瀝聲。", "也知園圃少，隨分適閑情。"]'),
