('406d4dd2-01f5-48d5-b8a0-27475a0b29eb','侍郎吟思愈清逸才無敵唱彌高而和彌寡我已竭而彼轉盈欲罷不能蓋彰其餘刃知難而退甘豎於降旗五章强振於蕪音三鼓那成於勇氣暫希解甲少遂息肩庶重整其懦兵願別當其堅陣此時勝負期一决焉却以地僻塵埃少爲首希垂采覽  其三','李昉','宋','宋诗','song-poetry','','[]','地僻塵埃少，於身頗自安。',48,'全唐诗/poet.song.0.json','["地僻塵埃少，於身頗自安。", "望山秋閣迥，占月夜庭寬。", "四野霜纔殞，千林葉盡乾。", "凌晨入朝去，拂面曉風寒。"]'),
('775b13f9-7296-4831-b9da-e74eae4f9fa5','侍郎吟思愈清逸才無敵唱彌高而和彌寡我已竭而彼轉盈欲罷不能蓋彰其餘刃知難而退甘豎於降旗五章强振於蕪音三鼓那成於勇氣暫希解甲少遂息肩庶重整其懦兵願別當其堅陣此時勝負期一决焉却以地僻塵埃少爲首希垂采覽  其四','李昉','宋','宋诗','song-poetry','','[]','地僻塵埃少，閑門掩綠苔。',48,'全唐诗/poet.song.0.json','["地僻塵埃少，閑門掩綠苔。", "長因五字至，暫得兩眉開。", "信步尋三逕，祛寒飲一盃。", "何曾問家計，散誕自堪咍。"]'),
('3830d684-1b3a-4756-b80d-e833441f1bf4','侍郎吟思愈清逸才無敵唱彌高而和彌寡我已竭而彼轉盈欲罷不能蓋彰其餘刃知難而退甘豎於降旗五章强振於蕪音三鼓那成於勇氣暫希解甲少遂息肩庶重整其懦兵願別當其堅陣此時勝負期一决焉却以地僻塵埃少爲首希垂采覽  其五','李昉','宋','宋诗','song-poetry','','[]','地僻塵埃少，家貧顯靜南。',48,'全唐诗/poet.song.0.json','["地僻塵埃少，家貧顯靜南。", "門前多野景，牆外是精藍。", "美食身非稼，豐衣婦不蠶。", "因思寒餧者，飽暖自須慚。"]'),
('2d7b9a63-b956-478f-a118-0979a5f471ee','又捧新詩見褒陋止睹五章之綺麗如九奏之凄清其末章末句云誰比天人福皆從積善招天人之比固不敢當積善之徵其來有自味嘉言之若是省薄德以何勝仰謝良知謹次來韻以老去心何用爲首希垂采覽  其一','李昉','宋','宋诗','song-poetry','','[]','老去心何用，題詩滿粉牆。',48,'全唐诗/poet.song.0.json','["老去心何用，題詩滿粉牆。", "空庭夜待月，靜室晝焚香。", "策杖閑尋水，移床卧向陽。", "自憐衰病者，雅稱住閑坊。"]'),
('66b118f6-d69b-4c72-995c-e4ee4ce4cd15','又捧新詩見褒陋止睹五章之綺麗如九奏之凄清其末章末句云誰比天人福皆從積善招天人之比固不敢當積善之徵其來有自味嘉言之若是省薄德以何勝仰謝良知謹次來韻以老去心何用爲首希垂采覽  其二','李昉','宋','宋诗','song-poetry','','[]','老去心何用，幽居似故林。',48,'全唐诗/poet.song.0.json','["老去心何用，幽居似故林。", "移花初得地，種柳已成陰。", "減食餧饑犬，汲泉防渴禽。", "除營閑事外，兀兀任浮沈。"]'),
('7f50e7f6-e901-4aa1-9f4f-e52b08051c72','又捧新詩見褒陋止睹五章之綺麗如九奏之凄清其末章末句云誰比天人福皆從積善招天人之比固不敢當積善之徵其來有自味嘉言之若是省薄德以何勝仰謝良知謹次來韻以老去心何用爲首希垂采覽  其三','李昉','宋','宋诗','song-poetry','','[]','老去心何用，虛窗夏景凉。',48,'全唐诗/poet.song.0.json','["老去心何用，虛窗夏景凉。", "麥光鋪作簟，雪粉煮爲漿。", "竹徑時教掃，蔬畦不使荒。", "子孫何所遺，經史在南堂。"]'),
('536af142-88eb-4555-bcd6-9205f253a1a1','又捧新詩見褒陋止睹五章之綺麗如九奏之凄清其末章末句云誰比天人福皆從積善招天人之比固不敢當積善之徵其來有自味嘉言之若是省薄德以何勝仰謝良知謹次來韻以老去心何用爲首希垂采覽  其四','李昉','宋','宋诗','song-poetry','','[]','老去心何用，閑吟月正中。',48,'全唐诗/poet.song.0.json','["老去心何用，閑吟月正中。", "細香紅菡萏，疏影碧梧桐。", "鶴立莓苔逕，犬眠蘭菊叢。", "吾宗不我顧，幽興與誰同。"]'),
('72708357-aa41-4276-b58d-e22cdcda7dc5','又捧新詩見褒陋止睹五章之綺麗如九奏之凄清其末章末句云誰比天人福皆從積善招天人之比固不敢當積善之徵其來有自味嘉言之若是省薄德以何勝仰謝良知謹次來韻以老去心何用爲首希垂采覽  其五','李昉','宋','宋诗','song-poetry','','[]','老去心何用，恬然守寂寥。',48,'全唐诗/poet.song.0.json','["老去心何用，恬然守寂寥。", "有時思綠蟻，幾度換金貂。", "歲稔人情樂，天寒馬力驕。", "望君頻訪我，不必待書招。"]'),
('1c2d6dd2-4cbc-4390-8a24-9b51aa1b76b9','依韻奉和千葉玫瑰之什','李昉','宋','宋诗','song-poetry','','[]','滿檻妖饒甚，皆因暖律催。',168,'全唐诗/poet.song.0.json','["滿檻妖饒甚，皆因暖律催。", "好憑鶑說意，不假蝶爲媒。", "带露羞容歛，隨風笑臉迴。", "去年觀始種，今日見齊開。", "熠熠燈千炷，熒熒火一堆。", "濃香蓋天與，碎葉是誰裁。", "旋爲除芳草，惟愁落綠苔。", "最宜含細雨，肯使撲輕埃。", "易賦詩盈軸，難辭酒滿盃。", "汲泉頻灌溉，買土更封培。", "銷得邀賓賞，堪教選地栽。", "醉吟翻悵望，行遶重徘徊。", "謾對鮮妍色，慚無綺麗才。", "自憐垂白叟，扶病看花來。"]'),
('4a036b56-d6aa-490b-ae45-21594b94c19f','寶相花送上秘閣侍郎并獻惡詩一首','李昉','宋','宋诗','song-poetry','','[]','寶相爲嘉號，移根自蜀都。',48,'全唐诗/poet.song.0.json','["寶相爲嘉號，移根自蜀都。", "遠來還可重，他處更應無。", "嫩葉細裁綠，芳英勻抹朱。", "風流別花客，知道此花殊。"]'),
('3e524fbf-5315-4082-8403-19e7f25c55ad','自過節辰又逢連假既閉關而不出但欹枕以閑眠交朋頓少見過盃酒又難獨飲若無吟詠何適性情一唱一酬亦足以解端憂而散滯思也吾弟則調高思逸誠爲百勝之師劣兄則年老氣羸甘取數奔之誚恭依來韻更次五章以自喜身無事爲首  其一','李昉','宋','宋诗','song-poetry','','[]','自喜身無事，閑吟適性情。',48,'全唐诗/poet.song.0.json','["自喜身無事，閑吟適性情。", "欲依芳樹歇，更傍小欄行。", "地僻疏還往，年高倦送迎。", "臨軒瞑目坐，神思當時清。"]'),
('2ab8a00c-4578-48d7-bfb1-3afb78c2d853','自過節辰又逢連假既閉關而不出但欹枕以閑眠交朋頓少見過盃酒又難獨飲若無吟詠何適性情一唱一酬亦足以解端憂而散滯思也吾弟則調高思逸誠爲百勝之師劣兄則年老氣羸甘取數奔之誚恭依來韻更次五章以自喜身無事爲首  其二','李昉','宋','宋诗','song-poetry','','[]','自喜身無事，因行過寺牆。',48,'全唐诗/poet.song.0.json','["自喜身無事，因行過寺牆。", "閑題僧舍壁，靜爇佛家香。", "竹戶蜘蛛掛，莎階蟋蟀藏。", "唱酬聊取樂，不覺又盈箱。"]'),
('5eb7390f-fbc9-4885-bd0b-2348b1e75142','自過節辰又逢連假既閉關而不出但欹枕以閑眠交朋頓少見過盃酒又難獨飲若無吟詠何適性情一唱一酬亦足以解端憂而散滯思也吾弟則調高思逸誠爲百勝之師劣兄則年老氣羸甘取數奔之誚恭依來韻更次五章以自喜身無事爲首  其三','李昉','宋','宋诗','song-poetry','','[]','自喜身無事，論才拙復疏。',48,'全唐诗/poet.song.0.json','["自喜身無事，論才拙復疏。", "五年陪稷禼，二紀接嚴徐。", "本是漁樵客，終慚鄒魯儒。", "溫衣飽食外，何必待盈餘。"]'),
('adf8f377-8a5b-47a9-98a3-59f38d869d3f','自過節辰又逢連假既閉關而不出但欹枕以閑眠交朋頓少見過盃酒又難獨飲若無吟詠何適性情一唱一酬亦足以解端憂而散滯思也吾弟則調高思逸誠爲百勝之師劣兄則年老氣羸甘取數奔之誚恭依來韻更次五章以自喜身無事爲首  其四','李昉','宋','宋诗','song-poetry','','[]','自喜身無事，門庭草色連。',48,'全唐诗/poet.song.0.json','["自喜身無事，門庭草色連。", "前軒滿床月，後院一林烟。", "策杖困還歇，枕書慵更眠。", "稱家隨分過，何用苦忙然。"]'),
('73bfdfdb-d483-4e7a-8eea-93f29da28472','自過節辰又逢連假既閉關而不出但欹枕以閑眠交朋頓少見過盃酒又難獨飲若無吟詠何適性情一唱一酬亦足以解端憂而散滯思也吾弟則調高思逸誠爲百勝之師劣兄則年老氣羸甘取數奔之誚恭依來韻更次五章以自喜身無事爲首  其五','李昉','宋','宋诗','song-poetry','','[]','自喜身無事，乘春但種花。',48,'全唐诗/poet.song.0.json','["自喜身無事，乘春但種花。", "時時遊野墅，往往宿僧家。", "入竹新尋笋，燃鐺旋煮茶。", "趨朝十里路，來往不嫌賒。"]'),
('a050e7ed-5596-4ece-aa02-38f8fb5fc962','對海紅花懷吏部侍郎','李昉','宋','宋诗','song-poetry','','[]','爛熳海紅花，花中信殊異。',72,'全唐诗/poet.song.0.json','["爛熳海紅花，花中信殊異。", "萬朵壓欄干，一堆紅錦被。", "顔色燒人眼，馨香撲人鼻。", "宜哉富豪家，長近歌鍾地。", "對花花不語，憶君君不至。", "盡日惜穠芳，情懷有如醉。"]'),
('28a085de-ef77-4105-bda7-b43d69213e3f','修竹百竿纔欣種植佳篇五首旋辱詠歌若無還答之言是闕唱酬之禮恭依來韻以導鄙懷調下才卑豈逃嗤誚  其一','李昉','宋','宋诗','song-poetry','','[]','謾栽花卉滿朱欄，爭似疏篁種百竿。',64,'全唐诗/poet.song.0.json','["謾栽花卉滿朱欄，爭似疏篁種百竿。", "長愛枕前聞淅瀝，乍欣窗外見檀欒。", "春來莫重和烟翠，歲晚應須带雪看。", "我得此君添一友，時時相對列盃盤。"]'),
('1411560d-6641-4af0-b79f-5d2b1ab476fe','修竹百竿纔欣種植佳篇五首旋辱詠歌若無還答之言是闕唱酬之禮恭依來韻以導鄙懷調下才卑豈逃嗤誚  其二','李昉','宋','宋诗','song-poetry','','[]','北軒留得無多地，不種閑花種此君。',64,'全唐诗/poet.song.0.json','["北軒留得無多地，不種閑花種此君。", "寒檜老松堪接影，綠楊紅杏莫同羣。", "要添迂叟窗前景，特就山僧院裏分。", "更侍明年新笋出，亭亭必見勢凌雲。"]'),
('487ec3e9-5430-460c-aa04-01e1f95c07c4','修竹百竿纔欣種植佳篇五首旋辱詠歌若無還答之言是闕唱酬之禮恭依來韻以導鄙懷調下才卑豈逃嗤誚  其三','李昉','宋','宋诗','song-poetry','','[]','久聞山僧寄書覓，今來□下白雲邊。',64,'全唐诗/poet.song.0.json','["久聞山僧寄書覓，今來□下白雲邊。", "不教凡草生叢畔，長喜清陰在眼前。", "忍把翠筠裁作簟，爭將迸笋截爲鞭。", "行吟坐對情無盡，只欠潺潺一道泉。"]'),
('e05dc266-8df5-408c-8a15-f1a6615a03ed','修竹百竿纔欣種植佳篇五首旋辱詠歌若無還答之言是闕唱酬之禮恭依來韻以導鄙懷調下才卑豈逃嗤誚  其四','李昉','宋','宋诗','song-poetry','','[]','青青鬰鬰影疏疏，碧嶂移根到我居。',64,'全唐诗/poet.song.0.json','["青青鬰鬰影疏疏，碧嶂移根到我居。", "爲愛綠陰時遣掃，恐傷新笋不教鋤。", "勾牽好鳥啼幽檻，摇擺清風上碧虛。", "栽得此君知有幸，入他仙客詠吟餘。"]'),
('e715a4b8-6ebe-407d-ae11-24e86ab1899e','修竹百竿纔欣種植佳篇五首旋辱詠歌若無還答之言是闕唱酬之禮恭依來韻以導鄙懷調下才卑豈逃嗤誚  其五','李昉','宋','宋诗','song-poetry','','[]','移得修篁带嫩苔，欲教相夾小桃開。',64,'全唐诗/poet.song.0.json','["移得修篁带嫩苔，欲教相夾小桃開。", "何須一一依行種，但要疏疏滿檻栽。", "枝上掛衣閑就枕，影中鋪簟好持盃。", "蓬丘仙客偏憐爾，應爲幽叢數數來。"]'),
('e02325d5-3aa4-47d1-a5f5-cf2a27117c33','齒疾未平灸瘡正作新詩又至奇韻難當暗忍呻吟强思酬和別披小簡蓋念短才更竭病懷甘輸降款  其一','李昉','宋','宋诗','song-poetry','','[]','蒼翠一叢湘岸色，問僧求得不嫌多。',64,'全唐诗/poet.song.0.json','["蒼翠一叢湘岸色，問僧求得不嫌多。", "重移砌畔新栽石，旋斸庭中舊種莎。", "誘引吟情終不盡，裝添野景更無過。", "明年新笋成林後，裊裊長竿拂樹柯。"]'),
('92fcaa7f-5bd9-4f03-a74b-3e0bb40ffb41','齒疾未平灸瘡正作新詩又至奇韻難當暗忍呻吟强思酬和別披小簡蓋念短才更竭病懷甘輸降款  其二','李昉','宋','宋诗','song-poetry','','[]','春早移來漸漸芳，童兒盜笋最須防。',64,'全唐诗/poet.song.0.json','["春早移來漸漸芳，童兒盜笋最須防。", "清陰羃羃低籠檻，翠影森森半出牆。", "今對小窗殊不厭，長侵幽逕亦何妨。", "十篇嘉句形褒詠，多謝高才秘閣郎。"]'),
('c3b16f18-4415-4009-a256-2f3456417e44','齒疾未平灸瘡正作新詩又至奇韻難當暗忍呻吟强思酬和別披小簡蓋念短才更竭病懷甘輸降款  其三','李昉','宋','宋诗','song-poetry','','[]','北就牆陰創小欄，小欄非窄亦非寬。',64,'全唐诗/poet.song.0.json','["北就牆陰創小欄，小欄非窄亦非寬。", "何須渭水誇千畝，且對蕭齋種百竿。", "春笋屈盤穿砌出，夜枝交戛入窗寒。", "誰能携妓東山去，垂老區區學謝安。"]'),
('b1267f80-51d0-4a26-bca5-579361829d95','齒疾未平灸瘡正作新詩又至奇韻難當暗忍呻吟强思酬和別披小簡蓋念短才更竭病懷甘輸降款  其四','李昉','宋','宋诗','song-poetry','','[]','等閑無客訪閑門，時訪閑門只有君。',64,'全唐诗/poet.song.0.json','["等閑無客訪閑門，時訪閑門只有君。", "最喜舉觴吟綠篠，誰能騎馬詠紅裙。", "遮窗密影朝朝見，聒枕幽聲夜夜聞。", "更待明年漸滋盛，投林宿鳥定成羣。"]'),
('0963b1c3-9346-4f7c-afd8-efefbd3cb75a','齒疾未平灸瘡正作新詩又至奇韻難當暗忍呻吟强思酬和別披小簡蓋念短才更竭病懷甘輸降款  其五','李昉','宋','宋诗','song-poetry','','[]','一簇檀欒愛者多，朝昏賞翫意如何。',64,'全唐诗/poet.song.0.json','["一簇檀欒愛者多，朝昏賞翫意如何。", "北軒小檻方栽植，東觀新詩已詠歌。", "啼鳥戀枝長懶去，鄰僧爲爾數來過。", "叢邊若有東流水，堪看清陰照綠波。"]'),
('7fb86f9a-30e3-4bd3-af1c-f27c0f882fd3','數日來頓疏酬唱若無牽率寧度鬰蒸輒貢狂吟用驚晝寢','李昉','宋','宋诗','song-poetry','','[]','日照清空火欲燃，須將酬唱强相牽。',64,'全唐诗/poet.song.0.json','["日照清空火欲燃，須將酬唱强相牽。", "若無嘯月吟風侶，爭度流金鑠石天。", "簾卷小亭終少到，簟鋪深室亦難眠。", "如何偷得清凉樂，除却冥心學坐禪。"]'),
('c55929de-fbdb-4465-a8f9-60e51d6be5d0','更述荒蕪自詠閑適','李昉','宋','宋诗','song-poetry','','[]','滿架詩書滿炷香，琴碁爲樂是尋常。',64,'全唐诗/poet.song.0.json','["滿架詩書滿炷香，琴碁爲樂是尋常。", "誠知老去唯宜靜，自笑閑中亦有忙。", "腰下轉嫌金印重，眉間漸長白毫長。", "手栽園樹皆成實，引著兒孫旋摘嘗。"]'),
('6167b5f4-6276-4cd1-86cd-bfad37fa78ee','和夏日直秘閣之什','李昉','宋','宋诗','song-poetry','','[]','靜卧蓬山養道情，百司繁冗盡堪輕。',64,'全唐诗/poet.song.0.json','["靜卧蓬山養道情，百司繁冗盡堪輕。", "窗前竹撼森疏影，樹杪蟬吟斷續聲。", "閑蹋綠莎芒作履，旋烹芳茗石爲鐺。", "料君難戀神仙境，重築沙堤走馬行。"]'),
('bcf948f9-02de-41c9-a220-c68e1e2aa51e','和暑夜偶作之什','李昉','宋','宋诗','song-poetry','','[]','新搆華居近禁城，旋栽松檜滿中庭。',64,'全唐诗/poet.song.0.json','["新搆華居近禁城，旋栽松檜滿中庭。", "順風子細聞清漏，隔竹依稀見落星。", "萬乘異恩無路報，千年昌運此時丁。", "一軒明月誰爲伴，應共金昆醉復醒。"]'),
('fdde303f-349e-4346-8de3-3046f7f39cdf','謝侍郎三弟朝蓋相過','李昉','宋','宋诗','song-poetry','','[]','喜得君來慰我心，清歡何假酒頻斟。',64,'全唐诗/poet.song.0.json','["喜得君來慰我心，清歡何假酒頻斟。", "共窺鶴跡行苔逕，同聽鶑聲坐柳陰。", "蝴蝶遶欄飛又歇，薔薇壓架淺兼深。", "相留不用忙忙去，直待林梢夕照沈。"]'),
('c448fae4-27d7-4054-8ac3-91e97c6e2c7d','侍郎見貽佳什愈見高懷因次來章輒歌盛美  其一','李昉','宋','宋诗','song-poetry','','[]','望高官重兩難儔，遇興裁詩許唱酬。',64,'全唐诗/poet.song.0.json','["望高官重兩難儔，遇興裁詩許唱酬。", "鸞鳳羽翰歸碧落，神仙行止在丹丘。", "空庭引鶴閑臨水，遠樹驚蟬又報秋。", "唯說近來都不飲，夢魂無復醉鄉遊。"]'),
('965985ad-c4f4-49e6-94df-b97b600ab546','侍郎見貽佳什愈見高懷因次來章輒歌盛美  其二','李昉','宋','宋诗','song-poetry','','[]','一簇林亭景象幽，葛巾芒屨恣優游。',64,'全唐诗/poet.song.0.json','["一簇林亭景象幽，葛巾芒屨恣優游。", "未饒榮啟歌三樂，不學張衡詠四愁。", "二品位高猶是忝，九天恩重若爲酬。", "儒生所得誰如我，豈復咨嗟雪滿頭。"]'),
('b3231b44-d330-482d-8222-1594f72e1271','輒歌盛美獻秘閣侍郎','李昉','宋','宋诗','song-poetry','','[]','濟時才略本縱橫，翻向文章振大名。',64,'全唐诗/poet.song.0.json','["濟時才略本縱橫，翻向文章振大名。", "政事堂中辭重位，圖書閣下養閑情。", "高高節行將誰比，的的襟懷向我傾。", "吟得新詩只相寄，心看軒冕一銖輕。"]'),
('0e2384bd-7645-4e66-9d95-3cea21ed22e6','牡丹盛開對之感歎寄秘閣侍郎','李昉','宋','宋诗','song-poetry','','[]','白公曾詠牡丹芳，一種鮮妍獨異常。',64,'全唐诗/poet.song.0.json','["白公曾詠牡丹芳，一種鮮妍獨異常。", "眼底見伊真國色，鼻頭聞者是天香。", "朝含宿雨低垂淚，晚背殘陽暗斷腸。", "多病老翁爭奈向，寄詩遥問少年郎。"]'),
('69bfa3ec-b8da-4003-9a6e-19eaf59f50de','冬至後作呈秘閣侍郎','李昉','宋','宋诗','song-poetry','','[]','節辰纔過一陽生，草樹依依已有情。',64,'全唐诗/poet.song.0.json','["節辰纔過一陽生，草樹依依已有情。", "楊柳莫嫌凋舊葉，牡丹還喜動新萌。", "潜驚綠竹微添翠，暗覺幽禽漸變聲。", "從此日長天又暖，時時獨入小園行。"]'),
('cb8950ef-baa3-4847-97fe-060f93066cca','昉啟昉世雖積善身匪懷才川嶽粹靈固非稟受朝廷華顯靡不踐揚爰及孟冬適逢生日兒孫在列爭持獻壽之盃珠玉忽來又捧祝延之什老夫內省爲幸斯多輒述荒詞用繼高韻','李昉','宋','宋诗','song-poetry','','[]','九重天子搆明堂，凡木那堪作棟梁。',64,'全唐诗/poet.song.0.json','["九重天子搆明堂，凡木那堪作棟梁。", "生世固非賢者出，佐時空遇帝圖昌。", "略無聲望朝廷重，寧有功名史冊芳。", "羅列兒孫共爲壽，老年難訴滿金觴。"]'),
('515701c4-5c46-4f2d-a034-66be772a061c','贈鄧洵美','李昉','宋','宋诗','song-poetry','','[]','憶昔詞場共著鞭，當時鶑谷喜同遷。',64,'全唐诗/poet.song.0.json','["憶昔詞場共著鞭，當時鶑谷喜同遷。", "關河契闊三千里，音信稀疏二十年。", "君遇已知依玉帳，我無才藻步花磚。", "時情人事堪惆悵，天外相逢一泫然。"]'),
('0988984c-0d67-4bee-9f80-35c6cf7f147c','吊鄧洵美','李昉','宋','宋诗','song-poetry','','[]','十年衣染帝鄉塵，蹤迹仍傳活計貧。',64,'全唐诗/poet.song.0.json','["十年衣染帝鄉塵，蹤迹仍傳活計貧。", "高掇桂枝曾遂志，假拖藍綬至終身。", "侯門寂寞非知己，澤國悽惶似旅人。", "今已嚮公墳畔過，不勝懷抱暗酸辛。"]'),
('6f8c3538-030c-4de3-acd1-27de33f765fb','贈賈黄中','李昉','宋','宋诗','song-poetry','','[]','七歲神童古所難，賈家門戶有衣冠。',64,'全唐诗/poet.song.0.json','["七歲神童古所難，賈家門戶有衣冠。", "十人科第排頭上，五部經書誦舌端。", "見榜不知名字貴，登筵未識管弦歡。", "從今穩上青雲去，萬里誰能測羽翰。"]'),
('2e7e99cb-9192-4b84-8d6f-b9e509108693','寄孟賓于','李昉','宋','宋诗','song-poetry','','[]','幼携書劍別湘潭，金榜標名第十三。',64,'全唐诗/poet.song.0.json','["幼携書劍別湘潭，金榜標名第十三。", "昔日聲塵喧洛下，近年詩價滿江南。", "長爲邑令情終屈，縱處曹郎志未甘。", "莫學馮唐便休去，明君晚事未爲慚。"]'),
('77bece9e-09b5-4fbf-8391-87c5f4051f02','御書飛白玉堂之署四字頒賜禁苑今懸挂已畢輒述惡詩一章用歌盛事','李昉','宋','宋诗','song-poetry','','[]','玉堂四字重千金，宸翰親揮賜禁林。',96,'全唐诗/poet.song.0.json','["玉堂四字重千金，宸翰親揮賜禁林。", "地望轉從今日貴，君恩無似此時深。", "宴回上苑花初發，麻就中宵月未沈。", "衣惹御香拖瑞錦，筆宣皇澤灑春霖。", "院門不許閑人入，仙境寧教外事侵。", "我直承明踰二紀，臨川實動羨魚心。"]'),
('29861c05-7c39-4741-8c29-714aee9a5bd6','新桐廬知縣員外端修節行富有才名九霄未展於奮飛百里暫勞於綏撫言之美任即動征橈敢賦惡詩用伸攀送','李昉','宋','宋诗','song-poetry','','[]','詞筆淩雲正後生，安貧守道住神京。',64,'全唐诗/poet.song.0.json','["詞筆淩雲正後生，安貧守道住神京。", "昔年南國無虛譽，今日終朝有令名。", "楊柳岸邊揮袂去，木蘭舟裏載書行。", "琴堂莫作多時計，碧落方開萬里程。"]'),
('62dc8fba-a281-440a-9857-cf17ed0eb0b2','贈襄陽妓','李昉','宋','宋诗','song-poetry','','[]','峴山亭畔紅妝女，小筆香牋善賦詩。',64,'全唐诗/poet.song.0.json','["峴山亭畔紅妝女，小筆香牋善賦詩。", "顔貌共推傾國色，篇章皆是斷腸辭。", "便牽魂夢從今日，得見嬋娟在幾時。", "千里關河萬重意，夜深無睡暗尋思。"]'),
('230ffda4-8a59-4f4c-8332-032def25e5ef','禁林春直','李昉','宋','宋诗','song-poetry','','[]','疏簾摇曳日輝輝，直閣深嚴半掩扉。',64,'全唐诗/poet.song.0.json','["疏簾摇曳日輝輝，直閣深嚴半掩扉。", "一院有花春晝永，八方無事詔書稀。", "樹頭百囀鶑鶑語，梁上新來燕燕飛。", "豈合此身居此地，妨賢尸祿自知非。"]'),
('a9f98eae-4e9b-446f-9666-e644e9646c9f','仙客','李昉','宋','宋诗','song-poetry','','[]','胎化仙禽性本殊，何人携爾到京都。',64,'全唐诗/poet.song.0.json','["胎化仙禽性本殊，何人携爾到京都。", "因加美號爲仙客，稱向閑庭伴野夫。", "警露秋聲雲外影，翹沙晴影月中孤。", "青田萬里終歸去，暫處鷄羣莫歎吁。"]'),
('cdd369f7-65a0-470f-b14c-dab1cf752ff3','題岱宗無字碑','李昉','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','巨石來從十八盤，離宮複道滿千山。',32,'全唐诗/poet.song.0.json','["巨石來從十八盤，離宮複道滿千山。", "不因封禪窮民力，漢祖何緣便入關。"]'),
('afc5a4fc-9938-4ca4-bab7-704bfacec171','桐柏觀','李昉','宋','宋诗','song-poetry','','[]','子晉棲霞境，高高出世埃。',48,'全唐诗/poet.song.0.json','["子晉棲霞境，高高出世埃。", "直疑天上去，歸認下雲來。", "銀漢星辰近，金庭洞府開。", "遲明欲回首，更上降真臺。"]'),
('88fd0501-c796-470e-9101-f1654c62ffce','退官詩','李昉','宋','宋诗','song-poetry','','[]','布裘藜杖鹿胎冠，散率身如不在官。',32,'全唐诗/poet.song.0.json','["布裘藜杖鹿胎冠，散率身如不在官。", "晝枕靜欹無遠夢，秋窗閑坐有微寒。"]'),
('b6c22deb-5406-4019-8471-db011f3553f5','泰陵忌辰','李昉','宋','宋诗','song-poetry','','[]','秘殿深嚴聖語溫，十年前是一乾坤。',64,'全唐诗/poet.song.0.json','["秘殿深嚴聖語溫，十年前是一乾坤。", "孤臣林壑殺生在，帝里金湯舊業存。", "舜殿南風難解慍，漢陵西望欲銷魂。", "年年此日無窮恨，風雨瀟瀟獨閉門。"]'),
('54f97ea1-b53d-4f8f-bdde-a8e344d2e097','永昌陵挽詞','李昉','宋','宋诗','song-poetry','','[]','丹青史筆敢虛張，功德巍然軼漢唐。',32,'全唐诗/poet.song.0.json','["丹青史筆敢虛張，功德巍然軼漢唐。", "奠玉五回朝上帝，御樓三度納降王。"]'),
('dbb9b61b-624f-408d-a5df-2e486feafaf9','題義門胡氏華林書院','李昉','宋','宋诗','song-poetry','','[]','孝義冠鄉閭，門多長者車。',48,'全唐诗/poet.song.0.json','["孝義冠鄉閭，門多長者車。", "歲收千頃稻，家貯一樓書。", "待客開新酒，留僧煮嫩蔬。", "三公老且病，無暇訪山居。"]'),
('a2d9dc45-f722-4cbf-a6d6-58f75d8e2d6f','祜公榮歸','李昉','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','南望鄉閭隔楚雲，歸心迢遞更紛紜。',32,'全唐诗/poet.song.0.json','["南望鄉閭隔楚雲，歸心迢遞更紛紜。", "何因得共飛帆上，細看長江濯錦文。"]'),
