('6895f366-9970-4d1b-9134-0a785749f962','送新知永州陳秘丞瞻赴任','朱昂','宋','宋诗','song-poetry','','[]','赴郡逢秋節，晨征思爽然。',48,'全唐诗/poet.song.0.json','["赴郡逢秋節，晨征思爽然。", "過橋猶見月，臨水忽聞蟬。", "野色藏溪樹，香風撼渚蓮。", "此行君得意，千里獨摇鞭。"]'),
('d1d4669b-cc40-4f5a-ab4e-f0fbb0438ef9','涪州江心有巨石隠於深淵石傍刻二魚古記云魚出歲必大豐端拱元年十二月十有四日昂自瞿塘迴遵途於此知郡瑯琊王公□云石魚再出來歲復稔昂往而觀之果如所說因歌聖德輒成一章','朱昂','宋','宋诗','song-poetry','','[]','欲識豐年兆，揚鬐勢漸浮。',48,'全唐诗/poet.song.0.json','["欲識豐年兆，揚鬐勢漸浮。", "只應同在藻，無復畏吞鉤。", "去水非居轍，爲祥勝躍舟。", "須知明聖代，涵泳杳難儔。"]'),
('96002979-8904-4c24-9228-37fc75fd4ed9','題義門胡氏華林書院','朱昂','宋','宋诗','song-poetry','','[]','數峰嵐翠朝昏見，一徑莓苔出入疏。',64,'全唐诗/poet.song.0.json','["數峰嵐翠朝昏見，一徑莓苔出入疏。", "宗炳不離廬嶽社，戴逵原在剡州居。", "籬邊舊種千竿竹，架上新添百帙書。", "弟侄一科雙折桂，不勞人問道何如。"]'),
('5fc310ca-6b19-4656-a897-f70fdfc02939','詩三首  其一','釋遇賢','宋','宋诗','song-poetry','','[]','門前綠樹無啼鳥，庭下蒼苔有落花。',32,'全唐诗/poet.song.0.json','["門前綠樹無啼鳥，庭下蒼苔有落花。", "聊與東君論箇事，十分春色屬誰家。"]'),
('cebea315-5618-405d-86ee-5a294fb18f81','詩三首  其二','釋遇賢','宋','宋诗','song-poetry','','[]','心閒增道氣，忍事敵災屯。',24,'全唐诗/poet.song.0.json','["心閒增道氣，忍事敵災屯。", "謹言終少禍，節儉勝求人。"]'),
('13f39dd8-46b5-4479-bfd9-00cea690a1e6','詩三首  其三','釋遇賢','宋','宋诗','song-poetry','','[]','金斝又聞泛，玉山還報頹。',24,'全唐诗/poet.song.0.json','["金斝又聞泛，玉山還報頹。", "莫教更漏促，趁取月明迴。"]'),
('d23b4d1c-ada5-40da-9fd7-4ed06bd9f060','詩一首','釋遇賢','宋','宋诗','song-poetry','','[]','揚子江頭浪最深，行人到此盡沉吟。',32,'全唐诗/poet.song.0.json','["揚子江頭浪最深，行人到此盡沉吟。", "他時若向無波處，還似有波時用心。"]'),
('14fcbc5d-52c6-485c-9bf0-423dc719eea2','寄張學士洎','伍喬','宋','宋诗','song-poetry','','[]','不知何處好消憂，公退携壺即上樓。',64,'全唐诗/poet.song.0.json','["不知何處好消憂，公退携壺即上樓。", "職事久參侯伯幕，夢魂長遶帝王州。", "黄山嚮晚盈軒翠，黟水含春繞郡流。", "遥想玉堂多暇日，花時誰伴出城遊。"]'),
('dee006eb-e2ce-450a-86a8-247490fa67a4','僻居酬友人','伍喬','宋','宋诗','song-poetry','','[]','僻居惟愛近林泉，幽徑閒園任蘚連。',64,'全唐诗/poet.song.0.json','["僻居惟愛近林泉，幽徑閒園任蘚連。", "向竹掩扉隨鶴息，就溪安石學僧禪。", "古琴带月音聲正，山果經霜氣味全。", "多謝故交憐樸野，隔雲時復寄佳篇。"]'),
('51924438-acec-4f73-86ee-ffa962f3527d','遊西禪','伍喬','宋','宋诗','song-poetry','','[]','遠岫當軒列翠光，高僧一衲萬緣忘。',64,'全唐诗/poet.song.0.json','["遠岫當軒列翠光，高僧一衲萬緣忘。", "碧松影裏地長潤，白藉花中水亦香。", "雲自雨前生凈石，鶴于鐘後宿長廊。", "遊人戀此吟終日，盛暑樓臺早有凉。"]'),
('ec31892a-035b-4656-88ec-39bd6ccdff81','僻居謝何明府見訪','伍喬','宋','宋诗','song-poetry','','[]','公退琴堂動逸懷，閒披烟靄訪微才。',64,'全唐诗/poet.song.0.json','["公退琴堂動逸懷，閒披烟靄訪微才。", "馬嘶窮巷蛙聲息，轍到衡門草色開。", "風引柳花當坐起，日將林影入庭來。", "滿齋塵土一床蘚，多謝從容水飯回。"]'),
('c43cc10c-cb67-45c1-87b6-d972b41ff19c','冬日道中','伍喬','宋','宋诗','song-poetry','','[]','去去天涯無定期，瘦童羸馬共依依。',64,'全唐诗/poet.song.0.json','["去去天涯無定期，瘦童羸馬共依依。", "暮烟江口客來絕，寒葉嶺頭人住稀。", "带雪野風吹旅思，入雲山火照行衣。", "釣臺吟閣滄洲在，應爲初心未得歸。"]'),
('1bacd935-f352-496f-9f20-6d7f8f3025f4','遊西山龍泉禪寺','伍喬','宋','宋诗','song-poetry','','[]','疊巘層峰坐可觀，枕門流水更潺湲。',64,'全唐诗/poet.song.0.json','["疊巘層峰坐可觀，枕門流水更潺湲。", "曉鐘聲徹洞溪遠，夏木影籠軒檻寒。", "幽徑乍尋衣屨潤，古堂頻宿夢魂安。", "因嗟城郭營營事，不得長遊空鬢殘。"]'),
('84ab3d86-55f8-44f9-bdc3-0b65888d425b','宿灊山','伍喬','宋','宋诗','song-poetry','','[]','一入仙山萬慮寬，夜深寧厭倚虛欄。',64,'全唐诗/poet.song.0.json','["一入仙山萬慮寬，夜深寧厭倚虛欄。", "鶴和雲影宿高木，人带月光登古壇。", "芝朮露濃溪塢白，薜蘿風起殿廊寒。", "更陪羽客論真理，不覺初鐘叩曉殘。"]'),
('9f9896b2-4b62-4557-8982-dc81da5fc8b7','寄史處士','伍喬','宋','宋诗','song-poetry','','[]','長羨閒居一水湄，吟情高古有誰知。',64,'全唐诗/poet.song.0.json','["長羨閒居一水湄，吟情高古有誰知。", "石樓待月橫琴久，漁浦經風下釣遲。", "僻塢落花多掩徑，舊山殘燒幾侵籬。", "松門別後無消息，早晚重應躡屐隨。"]'),
('f2bd645b-940c-41d1-a5a0-de0c495c6d7c','僻居秋思寄友人','伍喬','宋','宋诗','song-poetry','','[]','門巷秋歸更寂寥，雨餘閒砌委蘭苗。',64,'全唐诗/poet.song.0.json','["門巷秋歸更寂寥，雨餘閒砌委蘭苗。", "夢迴月夜蟲吟壁，病起茅齋藥滿瓢。", "澤國舊遊關遠思，竹林前會負佳招。", "身名未立猶辛苦，何許流年晚鬢凋。"]'),
('0f456742-a639-4263-852a-11a78a420df0','寄落星史虛白處士','伍喬','宋','宋诗','song-poetry','','[]','白雲峰下古溪頭，曾與提壺爛熳遊。',64,'全唐诗/poet.song.0.json','["白雲峰下古溪頭，曾與提壺爛熳遊。", "登閣共看彭蠡水，圍爐相憶杜陵秋。", "棋玄不壓通高品，句妙多容隔歲酬。", "別後相思時一望，暮山空碧水空流。"]'),
('7fdb096b-ceb4-4dfa-a0c5-b6a32e3efcca','九江旅夜寄山中故人','伍喬','宋','宋诗','song-poetry','','[]','弱柳風高遠漏沈，坐來難便息愁吟。',64,'全唐诗/poet.song.0.json','["弱柳風高遠漏沈，坐來難便息愁吟。", "江城雪盡寒猶在，客舍燈孤夜正深。", "塵土積年粘旅服，關山無處寄歸心。", "此時遥羨閒眠侶，靜掩雲扉卧一林。"]'),
('08d3337f-92af-4eb3-821b-a963de44b079','聞杜牧赴闕','伍喬','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','舊隠匡廬一草堂，今聞携策謁吾皇。',64,'全唐诗/poet.song.0.json','["舊隠匡廬一草堂，今聞携策謁吾皇。", "峽雲難卷從龍勢，古劍終騰出土光。", "開翅定期歸碧落，濯纓寧肯問滄浪。", "他時得意交知仰，莫忘裁詩寄釣鄉。"]'),
('5384bb70-748b-4ae4-872c-a635685c3758','題西林寺水閣','伍喬','宋','宋诗','song-poetry','','[]','竹翠苔花遶檻濃，此亭幽致詎曾逢。',64,'全唐诗/poet.song.0.json','["竹翠苔花遶檻濃，此亭幽致詎曾逢。", "水分林下清泠派，山峙雲間峭峻峰。", "怪石夜光寒射燭，老杉秋韻冷和鐘。", "不知來往留題客，誰約重尋蓮社蹤。"]'),
('d5eb62bc-3125-4a2d-8b37-43b24e238c50','林居喜崔三博遠至','伍喬','宋','宋诗','song-poetry','','[]','幾日區區在遠程，晚烟林徑喜相迎。',64,'全唐诗/poet.song.0.json','["幾日區區在遠程，晚烟林徑喜相迎。", "姿容雖有塵中色，巾屨猶多嶽上清。", "野石靜排爲坐榻，溪茶深煮當飛觥。", "留連話與方經宿，又欲携書別我行。"]'),
('7b9db878-2950-467f-83b6-036ea0cea39b','觀華夷圖','伍喬','宋','宋诗','song-poetry','','[]','別手應難及此精，須知攢簇自心靈。',64,'全唐诗/poet.song.0.json','["別手應難及此精，須知攢簇自心靈。", "始於毫末分諸國，漸見圖中列四溟。", "關路欲伸通楚勢，蜀山俄聳入秦青。", "筆端盡現寰區事，堪把長懸在戶庭。"]'),
('f84e3bf6-28fe-49e5-b554-1365a0b90098','廬山書堂送祝秀才還鄉','伍喬','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','束書辭我下重巔，相送同臨楚岸邊。',64,'全唐诗/poet.song.0.json','["束書辭我下重巔，相送同臨楚岸邊。", "歸思幾隨千里水，離情空寄一枝蟬。", "園林到日酒初熟，庭戶開時月正圓。", "莫使蹉跎戀疏野，男兒酬志在當年。"]'),
('cb75c726-e8ec-44b0-8209-215e228716e3','暮冬送何秀才毘陵','伍喬','宋','宋诗','song-poetry','','[]','匹馬嘶風去思長，素琴孤劍稱戎裝。',64,'全唐诗/poet.song.0.json','["匹馬嘶風去思長，素琴孤劍稱戎裝。", "路塗多是過殘歲，杯酒無辭到醉鄉。", "雲傍水村凝冷片，雪連山驛積寒光。", "毘陵城下饒嘉景，回日新詩應滿堂。"]'),
('1bc2633f-7adf-4795-8ec1-4950f1cbb6fa','龍潭張道者','伍喬','宋','宋诗','song-poetry','','[]','碧洞幽巖獨息心，時人何路得相尋。',64,'全唐诗/poet.song.0.json','["碧洞幽巖獨息心，時人何路得相尋。", "養生不說憑諸藥，適意惟聞在一琴。", "石徑掃稀山蘚合，竹軒開晚野雲深。", "他年功就期飛去，應笑吾徒多苦吟。"]'),
('5401c571-56b3-4c6b-a710-41d82aeff1a7','晚秋同何秀才溪上','伍喬','宋','宋诗','song-poetry','','[]','閒步秋光思杳然，荷藜因共過林烟。',64,'全唐诗/poet.song.0.json','["閒步秋光思杳然，荷藜因共過林烟。", "期收野藥尋幽路，欲採溪菱上小船。", "雲吐晚陰藏霽岫，柳含餘靄咽殘蟬。", "倒尊盡日忘歸處，山磬數聲敲暝天。"]'),
('cc22926b-96c0-49c2-add0-0c8dadb8c869','送江少府授延陵後寄','伍喬','宋','宋诗','song-poetry','','[]','五老雲中勤學者，遇時能不困風塵。',64,'全唐诗/poet.song.0.json','["五老雲中勤學者，遇時能不困風塵。", "束書西上謁明主，捧檄南歸慰老親。", "別館友朋留醉久，去程烟月入吟新。", "莫因官小慵之任，自古鸞棲有異人。"]'),
('eadf400c-75c9-4736-8b37-4ad04fd92fdc','觀山水障子','伍喬','宋','宋诗','song-poetry','','[]','功績精妍世少倫，圖時應倍用心神。',64,'全唐诗/poet.song.0.json','["功績精妍世少倫，圖時應倍用心神。", "不知草木承何異，但見江山長带春。", "雲勢似離巖底石，浪花如動岸邊蘋。", "更疑獨泛漁舟者，便是其中舊隠人。"]'),
('b040252b-980a-4375-b940-dfdc58198c48','句','伍喬','宋','宋诗','song-poetry','','[]','積靄沈諸壑，微陽在半峰。',12,'全唐诗/poet.song.0.json','["積靄沈諸壑，微陽在半峰。"]'),
('80d09c20-f024-481d-8130-9738886f4c12','送崇教大師回天台','阮思道','宋','宋诗','song-poetry','','[]','碧雲高價徹天涯，珪璧清無一點瑕。',64,'全唐诗/poet.song.0.json','["碧雲高價徹天涯，珪璧清無一點瑕。", "雙闕再承新雨露，三吳重賞舊烟霞。", "水軒散味朝賢句，松院分嘗御府茶。", "聞說赤城終未見，畫圖何日寄京華。"]'),
('1a002017-1c21-445f-a3e6-1b01a3fa7c8e','題義門胡氏華林書院','阮思道','宋','宋诗','song-poetry','','[]','北闕重旌表，西齋盛討論。',96,'全唐诗/poet.song.0.json','["北闕重旌表，西齋盛討論。", "高陽旬爽里，通德鄭玄門。", "選勝開松院，憑幽敞竹軒。", "靈泉飛洞壑，花樹蔽郊原。", "露滴棲松鶴，風傳隔嶺猿。", "庭蘭香醉步，山月冷吟魂。", "客愛清塵慮，僧憐避俗喧。", "幾時清賞玩，嘯詠與琴樽。"]'),
('4a25b021-a2cb-45dc-a018-2e51b6ff1114','次韻贈丁謂之','龔穎','宋','宋诗','song-poetry','','[]','膽怯何由戴鐵冠，祗緣昭代奬孤寒。',64,'全唐诗/poet.song.0.json','["膽怯何由戴鐵冠，祗緣昭代奬孤寒。", "曲肱未遂違前志，直指無聞是曠官。", "三署每傳朝客說，五溪閑憑郡樓看。", "祝君早得文場雋，况值天階正舞干。"]'),
('a475850b-b959-4324-a1b9-0e9686399be1','惜花','張佖','宋','宋诗','song-poetry','','[]','蝶散鶑啼尚數枝，日斜風定更離披。',32,'全唐诗/poet.song.0.json','["蝶散鶑啼尚數枝，日斜風定更離披。", "看多記得傷心事，金谷樓前委地時。"]'),
('4ddb6dda-68be-4bb2-8874-8508c6c6e3ad','寄人二首  其一','張佖','宋','宋诗','song-poetry','','["\u601d\u5ff5", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u7edd\u53e5", "\u6708\u4eae", "\u7231\u60c5"]','別夢依依到謝家，小廊迴合曲闌斜。',32,'全唐诗/poet.song.0.json','["別夢依依到謝家，小廊迴合曲闌斜。", "多情只有春庭月，猶爲離人照落花。"]'),
('116d6a6b-5f6b-42b2-a3f0-a62e54d1636d','寄人二首  其二','張佖','宋','宋诗','song-poetry','','[]','酷憐風月爲多情，還到春時別恨生。',32,'全唐诗/poet.song.0.json','["酷憐風月爲多情，還到春時別恨生。", "倚柱尋思倍惆悵，一場春夢不分明。"]'),
('76aebb2b-7679-4072-bdd4-6cd40121ade6','邊上','張佖','宋','宋诗','song-poetry','','[]','戍樓吹角起征鴻，獵獵寒旌背晚風。',64,'全唐诗/poet.song.0.json','["戍樓吹角起征鴻，獵獵寒旌背晚風。", "千里暮烟愁不盡，一川秋草恨無窮。", "山河慘澹關城閉，人物蕭條市井空。", "只此旅魂招未得，更堪回首夕陽中。"]'),
('ac1bed91-33cd-4efe-a02e-9cd2524e3e50','長安道中早行','張佖','宋','宋诗','song-poetry','','[]','客離孤館一燈殘，牢落星河欲曙天。',64,'全唐诗/poet.song.0.json','["客離孤館一燈殘，牢落星河欲曙天。", "雞唱未沈函谷月，雁聲新度灞陵烟。", "浮生已悟莊周蝶，壯志仍輸祖逖鞭。", "何事悠悠策羸馬，此中辛苦過流年。"]'),
('36e16072-6b79-4185-be66-0053830a8bfa','洞庭阻風','張佖','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u6292\u60c5", "\u4f24\u6625", "\u5199\u666f", "\u5730\u65b9", "\u5b64\u5bc2"]','空江浩蕩景蕭然，盡日菰蒲泊釣船。',64,'全唐诗/poet.song.0.json','["空江浩蕩景蕭然，盡日菰蒲泊釣船。", "青草浪高三月渡，綠楊花撲一溪烟。", "情多莫舉傷春目，愁極兼無買酒錢。", "猶有漁人數家住，不成村落夕陽邊。"]'),
('d19c7efb-2d4c-4eca-bbff-e25012fbaf93','春日旅泊桂州','張佖','宋','宋诗','song-poetry','','[]','暖風芳草竟芊綿，多病多愁負少年。',64,'全唐诗/poet.song.0.json','["暖風芳草竟芊綿，多病多愁負少年。", "弱柳未勝寒食雨，好花爭奈夕陽天。", "溪邊物色堪圖畫，林畔鶑聲似管弦。", "獨有離人開淚眼，强憑杯酒亦潸然。"]'),
('946533fe-7858-4f17-819f-69075e63fd63','晚次湘源縣','張佖','宋','宋诗','song-poetry','','[]','烟郭遥聞向晚雞，水平舟靜浪聲齊。',64,'全唐诗/poet.song.0.json','["烟郭遥聞向晚雞，水平舟靜浪聲齊。", "高林带雨楊梅熟，曲岸籠雲謝豹啼。", "二女廟荒汀樹老，九疑山碧楚天低。", "湘南自古多離怨，莫動哀吟易慘悽。"]'),
('3bd9a9f1-c900-4138-9aae-e19171eaf1f9','惆悵吟','張佖','宋','宋诗','song-poetry','','[]','秋風丹葉動荒城，慘澹雲遮日半明。',64,'全唐诗/poet.song.0.json','["秋風丹葉動荒城，慘澹雲遮日半明。", "晝夢却因惆悵得，晚愁多爲別離生。", "江淹彩筆空留恨，莊叟玄譚未及情。", "千古怨魂銷不得，一江寒浪若爲平。"]'),
('d067fe05-9112-4ec8-98c0-bd8e15fc4218','秋晚過洞庭','張佖','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','征帆初挂酒初酣，暮景離情兩不堪。',64,'全唐诗/poet.song.0.json','["征帆初挂酒初酣，暮景離情兩不堪。", "千里晚霞雲夢北，一洲霜橘洞庭南。", "溪風送雨過秋寺，磵石驚龍落夜潭。", "莫把羈魂弔湘魄，九疑愁絕鎖烟嵐。"]'),
('08513c26-cabb-4a69-850e-a6bf0ad5c2d3','題華嚴寺木塔','張佖','宋','宋诗','song-poetry','','[]','六街晴色動秋光，雨霽憑高只易傷。',64,'全唐诗/poet.song.0.json','["六街晴色動秋光，雨霽憑高只易傷。", "一曲晚烟浮渭水，半橋斜日照咸陽。", "休將世路悲塵事，莫指雲山認故鄉。", "回首漢宮樓閣暮，數聲鐘鼓自微茫。"]'),
('9d6f9c36-0578-4c8c-be9b-83d610734309','經舊遊','張佖','宋','宋诗','song-poetry','','[]','暫到高唐曉又還，丁香結夢水潺潺。',32,'全唐诗/poet.song.0.json','["暫到高唐曉又還，丁香結夢水潺潺。", "不知雲雨歸何處，歷歷空留十二山。"]'),
('11d2a7da-53b5-420a-8a07-86cabe4147c8','碧戶','張佖','宋','宋诗','song-poetry','','[]','碧戶扃魚鎖，蘭窗掩鏡臺。',120,'全唐诗/poet.song.0.json','["碧戶扃魚鎖，蘭窗掩鏡臺。", "落花疑悵望，歸燕自裴回。", "詠絮知難敵，傷春不易裁。", "恨從芳草起，愁爲晚風來。", "衣惹湘雲薄，眉分楚岫開。", "香濃眠舊枕，夢好醉春杯。", "小障明金鳳，幽屏點翠苔。", "寶箏橫塞雁，怨笛落江梅。", "卓氏仍多酒，相如正富才。", "莫教琴上意，翻作鶴聲哀。"]'),
('cbe33360-15ce-4095-a062-bc7062022bc2','芍藥','張佖','宋','宋诗','song-poetry','','[]','香清粉澹怨殘春，蝶翅蜂鬚戀蕊塵。',64,'全唐诗/poet.song.0.json','["香清粉澹怨殘春，蝶翅蜂鬚戀蕊塵。", "閒倚晚風生悵望，靜留遲日學因循。", "休將薜荔爲青瑣，好與玫瑰作近鄰。", "零落若教隨暮雨，又應愁殺別離人。"]'),
('5eb450df-67a9-49c8-828f-415b3fb611f5','春晚謠','張佖','宋','宋诗','song-poetry','','[]','雨微微，烟霏霏，小庭半坼紅薔薇。',64,'全唐诗/poet.song.0.json','["雨微微，烟霏霏，小庭半坼紅薔薇。", "鈿箏斜倚畫屏曲，零落幾行金雁飛。", "蕭關夢斷無尋處，萬疊春波起南浦。", "凌亂楊花撲繡簾，晚窗時有流鶑語。"]'),
('5d03e279-0853-4f9c-8b42-a03324f6ea87','所思','張佖','宋','宋诗','song-poetry','','[]','空塘水碧春雨微，東風散漫楊柳飛。',96,'全唐诗/poet.song.0.json','["空塘水碧春雨微，東風散漫楊柳飛。", "依依南浦夢猶在，脈脈高唐雲不歸。", "江頭日暮多芳草，極目傷心烟悄悄。", "隔江紅杏一枝明，似玉佳人俯清沼。", "休向春臺更迴望，銷魂自古因惆悵。", "銀河碧海共無情，兩處悠悠起風浪。"]'),
('f99f30fa-f83a-449a-b7f4-1cd64156d668','春夕言懷','張佖','宋','宋诗','song-poetry','','[]','風透疏簾月滿庭，倚欄無事倍傷情。',64,'全唐诗/poet.song.0.json','["風透疏簾月滿庭，倚欄無事倍傷情。", "烟垂柳带纖腰軟，露滴花房怨臉明。", "愁逐野雲銷不盡，情隨春浪去難平。", "幽窗謾結相思夢，欲化西園蝶未成。"]'),
('0fb6beb5-9df9-434f-9b00-8a00414d07be','春江雨','張佖','宋','宋诗','song-poetry','','[]','雨溟溟，風泠泠，老松瘦竹臨烟汀。',64,'全唐诗/poet.song.0.json','["雨溟溟，風泠泠，老松瘦竹臨烟汀。", "空江冷落野雲重，村中鬼火微如星。", "夜驚溪上漁人起，滴瀝篷聲滿愁耳。", "子規叫斷獨未眠，罨岸春濤打船尾。"]'),
('d7a06ef4-41da-46ea-a048-9dec66f93a7e','送容州中丞赴鎮','張佖','宋','宋诗','song-poetry','','[]','交趾同星坐，龍泉佩斗文。',48,'全唐诗/poet.song.0.json','["交趾同星坐，龍泉佩斗文。", "燒香翠羽帳，看舞鬰金裙。", "鷁首衝瀧浪，犀渠拂嶺雲。", "莫教銅柱北，祗說馬將軍。"]'),
('ae8f827c-08fb-4b88-bf00-6b8aa1f408b5','贈韓道士','張佖','宋','宋诗','song-poetry','','[]','日暮秋風吹野花，上清歸客意無涯。',64,'全唐诗/poet.song.0.json','["日暮秋風吹野花，上清歸客意無涯。", "桃源寂寂烟霞閉，天路悠悠星漢斜。", "還似世人生白髮，定知仙骨變黄芽。", "東城南陌頻相見，應是壺中別有家。"]'),
('f5bd2b9e-bb89-4320-9c2c-d0e7e3729f5d','句','張佖','宋','宋诗','song-poetry','','[]','檻外有天皆在照，望中無物敢潛行。',16,'全唐诗/poet.song.0.json','["檻外有天皆在照，望中無物敢潛行。"]'),
('f3caa618-a8f3-45cd-8b63-d69b0b3ffcfc','查公山','查元方','宋','宋诗','song-poetry','','[]','大道貴知止，昔賢稱二疏。',264,'全唐诗/poet.song.0.json','["大道貴知止，昔賢稱二疏。", "今來我季方，退身茲有餘。", "瀟灑去桎梏，放蕩狎樵漁。", "疏泉離遠竇，鑿石構層廬。", "溪禽拂窗牖，山花滿庭除。", "寒藤繫舴艋，碧潭澄素舒。", "睹茲塵𡏖外，始見仁智居。", "痛哉方散適，溘然歸丘墟。", "恨不同老彭，其樂永只且。", "自古千祿輩，知進不知退。", "立事名雖揚，全身理何昧。", "茂先賦鷦鷯，體物知顯晦。", "一旦禍自速，臨刑無以對。", "李斯戀富貴，下包周身智。", "及憶東門犬，已棄咸陽市。", "平子著歸田，淵明捨彭澤。", "後來區區人，誰復挂書冊。", "我喜從今云，吾宗有逋客。", "山號查公山，嵽嵲雲漢間。", "山下查公塚，溪聲長潺潺。", "高臺好悵望，絕磴堪躋攀。", "他年謝簪紱，永此繼閑閑。"]'),
('17bcf25c-5b5b-4e05-a7a4-88b297111cd6','黄鶴樓','盧郢','宋','宋诗','song-poetry','','[]','黄鶴何年去杳冥，高樓千載倚江城。',64,'全唐诗/poet.song.0.json','["黄鶴何年去杳冥，高樓千載倚江城。", "碧雲朝卷四山景，流水夜傳三峽聲。", "柳暗西州供騁望，草芳南浦徧離情。", "登臨一晌須回首，看却鄉心萬感生。"]'),
('0f1302af-b7c7-4c62-a566-7e8c7a23dcde','殘絲曲','盧郢','宋','宋诗','song-poetry','','[]','春風駘蕩吹人衣，殘絲罥花曳空飛。',64,'全唐诗/poet.song.0.json','["春風駘蕩吹人衣，殘絲罥花曳空飛。", "閒愁十丈斷不得，雄蜂雌蝶相因依。", "高樓夾路凌雲起，瑣窗鸞柱彈流水。", "鶑聲啼老楊柳烟，香夢濛濛隔千里。"]'),
('7cbce94f-2ba2-43a8-bb97-890abde42ae7','詠刺蝟','朱貞白','宋','宋诗','song-poetry','','[]','行似針氈動，卧似栗裘圓。',24,'全唐诗/poet.song.0.json','["行似針氈動，卧似栗裘圓。", "莫欺如此大，誰敢便行拳。"]'),
('d5ec792d-7f59-429d-ad16-a10ed45b1812','謁貴公子不禮書格子屏風','朱貞白','宋','宋诗','song-poetry','','[]','道格何曾格，言糊又不糊。',24,'全唐诗/poet.song.0.json','["道格何曾格，言糊又不糊。", "渾身總是眼，還解識人無。"]'),
('eb357a23-0b44-4059-9f4a-848564f5bbc0','題棺木','朱貞白','宋','宋诗','song-poetry','','[]','久久終須要，而今未要君。',24,'全唐诗/poet.song.0.json','["久久終須要，而今未要君。", "有時閑憶著，大是要知聞。"]'),
('a8e9d36a-6f27-476d-8e2a-293c9c6d72f9','題狗蚤','朱貞白','宋','宋诗','song-poetry','','[]','與虱都來不較多，㩧挑筋鬭大婁羅。',32,'全唐诗/poet.song.0.json','["與虱都來不較多，㩧挑筋鬭大婁羅。", "忽然管著一藍子，有甚心情那你何。"]'),
('f0890360-c046-4c63-8121-76d8fe8d6195','詠月','朱貞白','宋','宋诗','song-poetry','','[]','當塗當塗見，蕪湖蕪湖見。',24,'全唐诗/poet.song.1000.json','["當塗當塗見，蕪湖蕪湖見。", "八月十五夜，一似沒柄扇。"]'),
('cb8d923e-6592-41ab-8948-013063676207','詠螃蟹','朱貞白','宋','宋诗','song-poetry','','[]','蟬眼龜形脚似蛛，未嘗正面向人趨。',32,'全唐诗/poet.song.1000.json','["蟬眼龜形脚似蛛，未嘗正面向人趨。", "如今飣在盤筵上，得似江湖亂走無。"]'),
('97587a08-1a0d-490c-a77a-5f18edb76651','句  其一','朱貞白','宋','宋诗','song-poetry','','[]','倒排雙陸子，稀插碧牙籌。',36,'全唐诗/poet.song.1000.json','["倒排雙陸子，稀插碧牙籌。", "既似柿牛妳，又如鈴馬兜。", "鼓搥并㩧箭，直是有來由。"]'),
('db15d4b8-0c6b-4de4-8b41-61e9a09a771c','句  其二','朱貞白','宋','宋诗','song-poetry','','[]','一夜小園開似雪。',8,'全唐诗/poet.song.1000.json','["一夜小園開似雪。"]'),
('db94b6a3-b9f1-4999-b492-56d3d7a91d4d','句','邵拙','宋','宋诗','song-poetry','','[]','萬國未得雨，孤雲猶在山。',12,'全唐诗/poet.song.1000.json','["萬國未得雨，孤雲猶在山。"]'),
('f41fbe99-a906-43e0-ba4e-404a273ca6bf','句','羅穎','宋','宋诗','song-poetry','','[]','嫚侮羣豪誇大度，可憐容得辟陽侯。',16,'全唐诗/poet.song.1000.json','["嫚侮羣豪誇大度，可憐容得辟陽侯。"]'),
('6ad0677d-1bcf-4564-9334-870b483c06ca','魰','劉吉','宋','宋诗','song-poetry','','[]','八珍一箸千金價，往往精庖賤惠文。',32,'全唐诗/poet.song.1000.json','["八珍一箸千金價，往往精庖賤惠文。", "莫道形模大剛拙，剖珠也解獻殷勤。"]'),
('3ee5e66e-b9fb-4087-ab3a-e82e662ae88b','句','劉吉','宋','宋诗','song-poetry','','[]','一箭不中鵠，五湖歸釣魚。',12,'全唐诗/poet.song.1000.json','["一箭不中鵠，五湖歸釣魚。"]'),
('63454de7-b551-421c-ab9a-3a8d3996e9d1','送季大夫牧舒州','湯悅','宋','宋诗','song-poetry','','[]','却下烏臺建隼旟，侯封歸去襲龍舒。',32,'全唐诗/poet.song.1000.json','["却下烏臺建隼旟，侯封歸去襲龍舒。", "嚴霜尚滿辭天闕，甘雨看隨入境車。"]'),
('50f5516c-2681-47f4-ad28-ee928d5a10c2','奉和聖制送鄧王牧宣城','湯悅','宋','宋诗','song-poetry','','[]','千里陵陽同陝服，鑿門胙土寄親賢。',64,'全唐诗/poet.song.1000.json','["千里陵陽同陝服，鑿門胙土寄親賢。", "曙烟已別黄金殿，晚照重登白玉筵。", "江上浮光宜雨後，郡中遠岫列窗前。", "天心待報期年政，留與工師播管弦。"]'),
('b8a98cdd-d7d8-427c-b770-9a38e6bfa14d','早春寄華下同志','湯悅','宋','宋诗','song-poetry','','[]','正是花時節，思君寢復興。',48,'全唐诗/poet.song.1000.json','["正是花時節，思君寢復興。", "市沽終不醉，春夢亦無憑。", "嶽面懸清雨，河心走濁冰。", "東門一條路，離恨正相仍。"]'),
('3f6e946e-dfc2-4d0f-81c8-37d87387f350','鼎臣學士侍郎以東館庭梅昔翰苑之毫末今復半枯向時同僚零落都盡素髮垂領茲唯二人感舊傷懷發於吟詠惠然好我不能無言輒次來韻攀和','湯悅','宋','宋诗','song-poetry','','[]','憶見萌芽日，還憐合抱時。',48,'全唐诗/poet.song.1000.json','["憶見萌芽日，還憐合抱時。", "舊歡如夢想，物態暗還移。", "素豔今無幾，朱顔亦自衰。", "樹將人共老，何暇更悲絲。"]'),
('66a5b385-8447-455c-a0e0-ee6dcc12def4','再次前韻代梅答','湯悅','宋','宋诗','song-poetry','','[]','託植經多稔，頃筐向盛時。',48,'全唐诗/poet.song.1000.json','["託植經多稔，頃筐向盛時。", "枝條雖已故，情分不曾移。", "莫向階前老，還同鏡裏衰。", "更應憐墮葉，殘吹挂蟲絲。"]'),
('6c21edc7-0ce7-442c-a563-b45567dd8d2b','鼎臣學士侍郎楚金舍人學士以再傷庭梅詩同垂寵和清絕感歎情致俱深因成四十字陳謝','湯悅','宋','宋诗','song-poetry','','[]','人物同遷謝，重成念舊悲。',48,'全唐诗/poet.song.1000.json','["人物同遷謝，重成念舊悲。", "連華得瓊玖，合奏發塤篪。", "餘枿雖無取，殘芳尚獲知。", "問君何所似，珍重杜秋詩。"]'),
('edcc5aef-2025-4428-8230-c0325810496a','謁聖林','楊文郁','宋','宋诗','song-poetry','','[]','悠悠往古繼來今，天地無窮照孔林。',32,'全唐诗/poet.song.1000.json','["悠悠往古繼來今，天地無窮照孔林。", "兩到金絲堂下拜，門生無負百年心。"]'),
('36899218-aef8-44c8-856b-2f0252d2b50e','句','駱仲舒','宋','宋诗','song-poetry','','[]','張鴻詩在楞伽峽，韓愈碑留燕喜亭。',16,'全唐诗/poet.song.1000.json','["張鴻詩在楞伽峽，韓愈碑留燕喜亭。"]'),
('ea9e5948-df19-4767-8c43-d6740ea76451','偈','釋省念','宋','宋诗','song-poetry','','[]','今年六十七，老病隨緣且遣日。',30,'全唐诗/poet.song.1000.json','["今年六十七，老病隨緣且遣日。", "今年記却來年事，來年記著今朝日。"]'),
('782fd752-2c29-4bc9-94cf-79dc3b23fe2a','偈','釋省念','宋','宋诗','song-poetry','','[]','白銀世界金色身，情與非情共一真。',32,'全唐诗/poet.song.1000.json','["白銀世界金色身，情與非情共一真。", "明暗盡時俱不照，日輪午後示全身。"]'),
('f00257f5-a3dc-46db-9da0-97feae00a060','句  其一','釋省念','宋','宋诗','song-poetry','','[]','一言截斷千江口，萬仞峰前始得玄。',16,'全唐诗/poet.song.1000.json','["一言截斷千江口，萬仞峰前始得玄。"]'),
('7e14926b-4698-435b-aaf4-fddc5baeda48','句  其二','釋省念','宋','宋诗','song-poetry','','[]','萬里神光都一照，誰人敢並日輪齊。',16,'全唐诗/poet.song.1000.json','["萬里神光都一照，誰人敢並日輪齊。"]'),
('5785a3ba-c68f-4136-ae68-5f1e26245006','贈成務崇','孟嘏','宋','宋诗','song-poetry','','[]','同呼碧嶂前，已是十餘年。',48,'全唐诗/poet.song.1000.json','["同呼碧嶂前，已是十餘年。", "話別非容易，相逢不偶然。", "多爲詩酒役，早免利名牽。", "幸有歸真路，何妨學上玄。"]'),
('2b33ebc4-b9d7-4192-9408-a9f76a54dff6','句','孟嘏','宋','宋诗','song-poetry','','[]','詩酒獨游寺，琴書多寄僧。',12,'全唐诗/poet.song.1000.json','["詩酒獨游寺，琴書多寄僧。"]'),
('56bf93c3-49cd-4f4c-a372-c5edbd703c26','贈天台逸人','廖融','宋','宋诗','song-poetry','','[]','移檜托禪子，携家上赤城。',48,'全唐诗/poet.song.1000.json','["移檜托禪子，携家上赤城。", "拂琴天籟寂，欹枕海濤生。", "雪白寒峰晚，鳥歌春谷晴。", "又聞求桂楫，載月十洲行。"]'),
('f961ffa1-b7da-4647-a94a-874341f596b3','題寺古檜','廖融','宋','宋诗','song-poetry','','[]','何人見植初，老對梵王居。',48,'全唐诗/poet.song.1000.json','["何人見植初，老對梵王居。", "山鬼暗栖托，樵夫難破除。", "聲高秋漢迥，影倒月潭虛。", "盡日無僧繞，清風長有餘。"]'),
('6b79995f-1975-4762-88dc-c34088f0c392','夢仙謠','廖融','宋','宋诗','song-poetry','','[]','琪木扶疏繫辟邪，麻姑夜宴紫皇家。',64,'全唐诗/poet.song.1000.json','["琪木扶疏繫辟邪，麻姑夜宴紫皇家。", "銀河旌節摇波影，珠閣笙簫吸月華。", "翠鳳引游三島路，赤龍齊別五雲車。", "星稀猶倚虹橋立，擬就張騫搭漢槎。"]'),
('4b7030f8-52c7-4fe3-b8a9-516161b1938d','退宮妓','廖融','宋','宋诗','song-poetry','','[]','神仙風格本難儔，曾從前皇翠輦游。',64,'全唐诗/poet.song.1000.json','["神仙風格本難儔，曾從前皇翠輦游。", "紅躑躅繁金殿暖，碧芙蓉笑水宮秋。", "寶車鈿剝陰塵覆，錦帳香消畫燭幽。", "一旦色衰歸故里，月明猶夢按梁州。"]'),
('f5a958e3-ca48-4a1c-b71c-23ce5ad4bc92','謝翁宏以詩百篇見示','廖融','宋','宋诗','song-poetry','','[]','高奇一百篇，見造化工全。',48,'全唐诗/poet.song.1000.json','["高奇一百篇，見造化工全。", "積思游滄海，冥搜入洞天。", "神珠迷罔象，瑞玉匪雕鑴。", "休嘆不得力，離騷千古傳。"]'),
('fb77bc0e-e130-4921-980e-4f4d835bd3d3','書伍彬屋壁','廖融','宋','宋诗','song-poetry','','[]','圓塘綠水平，魚躍紫蒓生。',48,'全唐诗/poet.song.1000.json','["圓塘綠水平，魚躍紫蒓生。", "要路貧無力，深村老退耕。", "犢隨原草遠，蛙傍塹籬鳴。", "撥棹茶川去，初逢穀雨晴。"]'),
('3abbe6ef-d470-42f6-96b9-04be221f5c01','贈王正己','廖融','宋','宋诗','song-poetry','','[]','吟高鄙俗流，傲逸訪巢由。',48,'全唐诗/poet.song.1000.json','["吟高鄙俗流，傲逸訪巢由。", "古寺尋僧飯，寒巖衣鹿裘。", "園桃山鼠嚙，崖蜜獵人偷。", "遂這箇清性，浮生不苟求。"]'),
('8052552d-8dc5-455f-8539-d8627f41c827','贈狄渙','廖融','宋','宋诗','song-poetry','','[]','高卧白雲鄉，崖泉對閣凉。',48,'全唐诗/poet.song.1000.json','["高卧白雲鄉，崖泉對閣凉。", "守貧無屬道，多病數求方。", "耕犢驚雷斃，寒蕪入圃荒。", "如何帝未夢，吟苦頂鋪霜。"]'),
('f1df05b0-b50b-4b8d-905e-5a8a49008e2f','句  其一','廖融','宋','宋诗','song-poetry','','[]','雲穿搗藥屋，雪壓釣魚船。',12,'全唐诗/poet.song.1000.json','["雲穿搗藥屋，雪壓釣魚船。"]'),
('4d0d6686-a420-4735-9c8b-f744575fbb27','句  其二','廖融','宋','宋诗','song-poetry','','[]','松風吹髮亂，巖溜濺碁寒。',12,'全唐诗/poet.song.1000.json','["松風吹髮亂，巖溜濺碁寒。"]'),
('a64c65d7-aef5-4900-a177-59155ed99005','句  其三','廖融','宋','宋诗','song-poetry','','[]','圭竇先知曉，盆池別見天。',12,'全唐诗/poet.song.1000.json','["圭竇先知曉，盆池別見天。"]'),
('007f8de5-82cf-4552-8091-3d2a914b73ee','存目','廖融','宋','宋诗','song-poetry','','[]','詩題：酬皇甫冉西陵見寄詩：西陵潮已漏，島嶼沒中流。',61,'全唐诗/poet.song.1000.json','["詩題：酬皇甫冉西陵見寄詩：西陵潮已漏，島嶼沒中流。", "越客依風水，相看南渡頭。", "寒光生極浦，暮雪映滄州。", "何事揚帆去，空驚海上鷗。"]'),
('bcf31be6-087f-4e14-b169-25dfacab60a8','宮詞','翁宏','宋','宋诗','song-poetry','','[]','又是春殘也，如何出翠帷。',48,'全唐诗/poet.song.1000.json','["又是春殘也，如何出翠帷。", "落花人獨立，微雨燕雙飛。", "寓目魂將斷，經年夢亦非。", "那堪嚮秋夕，蕭颯暮蟾輝。"]'),
('430ac82a-dff3-4f3e-a80b-f112a8eb42e9','秋風曲','翁宏','宋','宋诗','song-poetry','','[]','又是秋殘也，無聊意若何。',48,'全唐诗/poet.song.1000.json','["又是秋殘也，無聊意若何。", "客程江外遠，歸思夜深多。", "峴首飛黄葉，湘湄走白波。", "仍聞漢都護，今歲合休戈。"]'),
('ed351b9d-4f54-461d-baf9-d16b12d907c7','贈衡山廖融南遊','翁宏','宋','宋诗','song-poetry','','["\u8861\u5c71", "\u6d1e\u5ead\u6e56"]','病卧瘴雲間，莓苔漬竹關。',48,'全唐诗/poet.song.1000.json','["病卧瘴雲間，莓苔漬竹關。", "孤吟牛渚月，老憶洞庭山。", "壯志潛消盡，淳風竟未還。", "今朝忽相遇，執手一開顔。"]'),
('02d6e06c-6949-4ff8-953d-3329c889142b','句  其一','翁宏','宋','宋诗','song-poetry','','[]','風高弓力大，霜重角聲干。',12,'全唐诗/poet.song.1000.json','["風高弓力大，霜重角聲干。"]'),
('8a7ee677-b934-438d-b97c-b34b828ca7ce','句  其二','翁宏','宋','宋诗','song-poetry','','[]','客帆來異域，別島落蟠桃。',12,'全唐诗/poet.song.1000.json','["客帆來異域，別島落蟠桃。"]'),
('709c55ad-1d49-407b-be16-f562daf7a6dd','句  其三','翁宏','宋','宋诗','song-poetry','','[]','寒清萬國土，冷鬭四維根。',12,'全唐诗/poet.song.1000.json','["寒清萬國土，冷鬭四維根。"]'),
('6fda12ce-e270-4847-8911-704044cc20ab','句  其四','翁宏','宋','宋诗','song-poetry','','[]','漏光殘井甃，缺影背山椒。',12,'全唐诗/poet.song.1000.json','["漏光殘井甃，缺影背山椒。"]'),
('643dd213-8dab-4c3f-b9be-17b225732848','句  其五','翁宏','宋','宋诗','song-poetry','','[]','萬木殘秋裏，孤舟半夜猿。',12,'全唐诗/poet.song.1000.json','["萬木殘秋裏，孤舟半夜猿。"]'),
('84550d30-057e-4ef4-a97c-80d7b1645d88','句  其六','翁宏','宋','宋诗','song-poetry','','[]','因尋買珠客，誤入射猿家。',12,'全唐诗/poet.song.1000.json','["因尋買珠客，誤入射猿家。"]'),
('347cab9c-13fd-416f-ada5-9d864c3990f3','句  其七','翁宏','宋','宋诗','song-poetry','','[]','何處殘春夜，和花落古宮。',12,'全唐诗/poet.song.1000.json','["何處殘春夜，和花落古宮。"]'),
('f86756a7-96b4-4e3b-8ebe-3bae895af163','句  其八','翁宏','宋','宋诗','song-poetry','','[]','孤舟半夜雨，上國十年心。',12,'全唐诗/poet.song.1000.json','["孤舟半夜雨，上國十年心。"]'),
('084aa964-06b6-4c08-96a5-a31aab236a2f','懷翁宏','王元','宋','宋诗','song-poetry','','[]','獨夜思君切，無人知此情。',48,'全唐诗/poet.song.1000.json','["獨夜思君切，無人知此情。", "滄洲歸未得，華髮別來生。", "孤館木初落，高空月正明。", "遠書多隔歲，猶念沒前程。"]'),
('799c3821-ced0-43aa-b6ff-c5865b75578b','登祝融峰','王元','宋','宋诗','song-poetry','','[]','草疊到孤頂，身齊高鳥翔。',48,'全唐诗/poet.song.1000.json','["草疊到孤頂，身齊高鳥翔。", "勢疑撞翼軫，翠欲滴瀟湘。", "雲濕幽崖滑，風梳古木香。", "晴空聊縱目，杳杳極窮荒。"]'),
('2795c4c4-e865-436b-959f-188ef8d101cd','聽琴','王元','宋','宋诗','song-poetry','','[]','拂塵開素匣，有客獨傷時。',48,'全唐诗/poet.song.1000.json','["拂塵開素匣，有客獨傷時。", "古調俗不樂，正聲君自知。", "寒泉出澗澀，老檜倚風悲。", "縱有來聽者，誰堪繼子期。"]'),
('cbaa337c-1525-4ca4-b529-c79ebcfcd7c1','題鄧真人遺址','王元','宋','宋诗','song-poetry','','[]','三千功滿輕升去，留得山前舊隠基。',64,'全唐诗/poet.song.1000.json','["三千功滿輕升去，留得山前舊隠基。", "但見白雲長掩映，不知浮世幾興衰。", "松梢風觸霓旌動，棕葉霜沾鶴翅垂。", "近代無人尋異事，野泉噴月瀉秋池。"]'),
('23574d66-84e4-4329-9a70-1ca20e51f88e','悼李韶','王元','宋','宋诗','song-poetry','','[]','韶也命何奇，生前與世違。',48,'全唐诗/poet.song.1000.json','["韶也命何奇，生前與世違。", "貧棲古梵剎，終著舊麻衣。", "雅句僧抄遍，孤墳客吊稀。", "故園今孰在，應見夢中歸。"]'),
('addfd61d-a95d-4497-81d4-914d1d4a52ab','句  其一','王元','宋','宋诗','song-poetry','','[]','伴行唯瘦鶴，尋寺入深雲。',12,'全唐诗/poet.song.1000.json','["伴行唯瘦鶴，尋寺入深雲。"]'),
('430ad405-58db-430f-94ec-c879f8f6ca54','句  其二','王元','宋','宋诗','song-poetry','','[]','江城賣藥常將鶴，古寺看碑不下馿。',16,'全唐诗/poet.song.1000.json','["江城賣藥常將鶴，古寺看碑不下馿。"]'),
('6782a5ba-a643-4539-9b48-69187b86f349','題全義分水嶺','伍彬','宋','宋诗','song-poetry','','[]','前賢功及物，禹後杳難儔。',48,'全唐诗/poet.song.1000.json','["前賢功及物，禹後杳難儔。", "不及古今色，平分南北流。", "寒衝山影岸，清繞荻花洲。", "盡是朝宗去，潺湲早晚休。"]'),
('b00b9871-6a6f-49a2-964e-2a91481dd2d8','句  其一','伍彬','宋','宋诗','song-poetry','','[]','稚子出看莎徑沒，漁翁來報竹橋流。',16,'全唐诗/poet.song.1000.json','["稚子出看莎徑沒，漁翁來報竹橋流。"]'),
('bb8181f3-c780-417f-9008-4b27dbc17de5','句  其二','伍彬','宋','宋诗','song-poetry','','[]','踪跡未辭鴛鷺客，夢魂先到鷓鴣村。',16,'全唐诗/poet.song.1000.json','["踪跡未辭鴛鷺客，夢魂先到鷓鴣村。"]'),
('19589d70-c086-4970-92bb-61eb0acbd6a3','贈藴上人','王正己','宋','宋诗','song-poetry','','[]','佛法詩名誰更繼，未聞隨分謁侯王。',64,'全唐诗/poet.song.1000.json','["佛法詩名誰更繼，未聞隨分謁侯王。", "洗盂秋澗日華動，搗藥夜堂雲氣香。", "苔蘚亂青封疊石，杉松濃影過空牆。", "若非火嶽□□地，那得吾師住久長。"]'),
('57f9961b-99ae-437f-ab44-116e6458a306','贈廖融','王正己','宋','宋诗','song-poetry','','[]','湖南雖不就卑官，高卧深雲道自安。',64,'全唐诗/poet.song.1000.json','["湖南雖不就卑官，高卧深雲道自安。", "病起坐當秋閣迥，酒醒吟對夜濤寒。", "爐中藥熟分僧服，榻上琴閑借我彈。", "幸遇清朝有良鑒，退身爭忍似方干。"]'),
('752149e4-2705-43c1-b3cb-b98dce253fe0','偈','豐禪師','宋','宋诗','song-poetry','','[]','駿馬機前異，遊人肘後懸。',24,'全唐诗/poet.song.1000.json','["駿馬機前異，遊人肘後懸。", "既參雲外客，試爲老僧看。"]'),
('ceac2c44-4b7d-4e34-800a-9c57411d413b','句','豐禪師','宋','宋诗','song-poetry','','[]','雪嶺梅花綻，雲洞老僧驚。',12,'全唐诗/poet.song.1000.json','["雪嶺梅花綻，雲洞老僧驚。"]'),
('b12a54ca-b242-4113-abf6-1e40d849b3b0','壽陽山','石仲元','宋','宋诗','song-poetry','','[]','平原翠削萬瓊瑰，頓轡塵沙眼暫開。',32,'全唐诗/poet.song.1000.json','["平原翠削萬瓊瑰，頓轡塵沙眼暫開。", "文網牽人寧底急，未妨特特看山來。"]'),
('5746b8f2-f9f2-471e-b80e-098c46a4fbc8','句  其一','石仲元','宋','宋诗','song-poetry','','[]','地連錦野東西去，水接朱川次第來。',16,'全唐诗/poet.song.1000.json','["地連錦野東西去，水接朱川次第來。"]'),
('8bb9377d-ab62-482d-99d3-8a6917ebdbee','句  其二','石仲元','宋','宋诗','song-poetry','','[]','石壓木斜出，岸懸花倒生。',12,'全唐诗/poet.song.1000.json','["石壓木斜出，岸懸花倒生。"]'),
('cefb90ef-1f34-4636-a97b-806c6547998d','吟贈夢英大師','王著','宋','宋诗','song-poetry','','[]','到處聞人乞篆蹤，學來年久有深功。',64,'全唐诗/poet.song.1000.json','["到處聞人乞篆蹤，學來年久有深功。", "墨池闊類湘江水，筆塚高齊太華峰。", "金錫罷飛新解虎，鐵盂收掌舊降龍。", "知師吟戀烟村景，不肯迴頭望九重。"]'),
('d2c51a22-1e7c-4cb1-bc12-94e528041e2c','禁林讌會之什','梁周翰','宋','宋诗','song-poetry','','[]','寶書驚絕耀天章，飛白親題賜玉堂。',96,'全唐诗/poet.song.1000.json','["寶書驚絕耀天章，飛白親題賜玉堂。", "瑞彩上騰流素月，朗河下注映丹牆。", "鶴盤吳嶼雙翎健，鵲顧雕陵巨翼長。", "遊霧半收懸組練，輕雲斜拂駐鸞皇。", "墨池併獲三奇寶，翠琰俱生五色光。", "陪讌禁林知有幸，叩頭遥祝萬年觴。"]'),
('4c263501-dcd0-40f4-93b0-8a6c17d11ab3','題義門胡氏華林書院','梁周翰','宋','宋诗','song-poetry','','[]','知有英儒伯始孫，聚書講學賁邱園。',64,'全唐诗/poet.song.1000.json','["知有英儒伯始孫，聚書講學賁邱園。", "征搜合副來賢詔，旌表宜題遍德門。", "舉族爲人俱孝弟，深幽何草不蘭蓀。", "小冠子夏來相示，詩版因憑寄竹軒。"]'),
('d0969259-bc60-4dc2-ad62-d0bee767f05c','句  其一','梁周翰','宋','宋诗','song-poetry','','[]','誰似金華楊學士，十聯詩在御屏間。',16,'全唐诗/poet.song.1000.json','["誰似金華楊學士，十聯詩在御屏間。"]'),
('1f100b7d-3690-483f-87d8-2b50da3454e8','句  其二','梁周翰','宋','宋诗','song-poetry','','[]','百花將盡牡丹坼，十雨初晴太液春。',16,'全唐诗/poet.song.1000.json','["百花將盡牡丹坼，十雨初晴太液春。"]'),
('b474231f-80dc-4782-bc09-979b23e9b8dc','句  其三','梁周翰','宋','宋诗','song-poetry','','[]','宿雨一番蔬甲拆，春山幾處茗旗香。',19,'全唐诗/poet.song.1000.json','["宿雨一番蔬甲拆，春山幾處茗旗香。", "ff。"]'),
('15355d9e-c64c-40a0-9fe2-0338d57f2c4f','寄懷英公大師清交','馬去非','宋','宋诗','song-poetry','','[]','雲隠秋鴻水隠魚，相思難得惠休書。',64,'全唐诗/poet.song.1000.json','["雲隠秋鴻水隠魚，相思難得惠休書。", "遥聞養性棲蓮岳，不肯携筇入帝都。", "金殿聖緣應未斷，玉堂知己漸凋疏。", "何人曾得陪高論，頭戴神羊馬大夫。"]'),
('bedd3a3c-7c6c-41a0-aece-3ee0903f46af','宿山寺','孟貫','宋','宋诗','song-poetry','','[]','溪山盡日行，方聽遠鐘聲。',48,'全唐诗/poet.song.1000.json','["溪山盡日行，方聽遠鐘聲。", "入院逢僧定，登樓見月生。", "露垂羣木潤，泉落一巖清。", "此景關吾事，通宵寐不成。"]'),
('63844b5f-670a-4363-9439-4bc5a9dabbea','贈棲隠洞譚先生','孟貫','宋','宋诗','song-poetry','','[]','先生雙鬢華，深谷卧雲霞。',48,'全唐诗/poet.song.1000.json','["先生雙鬢華，深谷卧雲霞。", "不伐有巢樹，多移無主花。", "石泉春釀酒，松火夜煎茶。", "因問山中事，如君有幾家。"]'),
('a23f2ece-2cb8-4d01-a8d6-b9d5aa708f6b','歸雁','孟貫','宋','宋诗','song-poetry','','[]','春至衡陽雁，思歸塞路長。',48,'全唐诗/poet.song.1000.json','["春至衡陽雁，思歸塞路長。", "汀洲齊奮翼，霄漢共成行。", "雪盡翻風暖，寒收度月凉。", "直應到秋日，依舊返瀟湘。"]'),
('c1da456d-4b2f-4bba-a07a-21b278bcc492','春江送人','孟貫','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','春江多去情，相去枕長汀。',48,'全唐诗/poet.song.1000.json','["春江多去情，相去枕長汀。", "數雁別湓浦，片帆離洞庭。", "雨餘沙草綠，雲散岸峰青。", "誰共觀明月，漁歌夜好聽。"]'),
('fd049d90-1cd1-4439-84c5-a8dd3877699e','過秦嶺','孟貫','宋','宋诗','song-poetry','','[]','古今傳此嶺，高下勢崢嶸。',48,'全唐诗/poet.song.1000.json','["古今傳此嶺，高下勢崢嶸。", "安得青山路，化爲平地行。", "蒼苔留虎跡，碧樹障溪聲。", "欲過一回首，踟躕無限情。"]'),
('140087b4-62f3-4051-bcf8-502eeb791fcd','送吳夢誾歸閩','孟貫','宋','宋诗','song-poetry','','[]','甌閩在天末，此去整行衣。',48,'全唐诗/poet.song.1000.json','["甌閩在天末，此去整行衣。", "久客逢春盡，思家冒暑歸。", "海雲添晚景，山瘴滅晴暉。", "相憶吟偏苦，不堪書信稀。"]'),
('5db97497-a360-4711-8df5-6eae47cd8d53','山中夏日','孟貫','宋','宋诗','song-poetry','','[]','深山宜避暑，門戶映嵐光。',48,'全唐诗/poet.song.1000.json','["深山宜避暑，門戶映嵐光。", "夏木蔭溪路，晝雲埋石床。", "心源澄道靜，衣葛蘸泉凉。", "算得紅塵裏，誰知此興長。"]'),
('1ce8228a-bf0c-4c7c-bac2-434cce590b45','宿故人江居','孟貫','宋','宋诗','song-poetry','','[]','渡口樹冥冥，南山漸隠青。',48,'全唐诗/poet.song.1000.json','["渡口樹冥冥，南山漸隠青。", "漁舟歸舊浦，鷗鳥宿前汀。", "靜榻懸燈坐，閒門對浪扃。", "相思頻到此，幾番醉還醒。"]'),
('996e9d98-b074-47aa-9f63-37d8b04f7659','寄伍喬','孟貫','宋','宋诗','song-poetry','','[]','蹉跎春又晚，天末信來遲。',48,'全唐诗/poet.song.1000.json','["蹉跎春又晚，天末信來遲。", "長憶分携日，正當摇落時。", "獨遊饒旅恨，多事失歸期。", "君看前溪樹，山禽巢幾枝。"]'),
('56748e8a-9d84-4612-9ea3-4a73fcf32475','山中訪人不遇','孟貫','宋','宋诗','song-poetry','','[]','負琴兼杖藜，特地過巖西。',48,'全唐诗/poet.song.1000.json','["負琴兼杖藜，特地過巖西。", "已見竹軒閉，又聞山鳥啼。", "長松寒倚谷，細草暗連溪。", "久立無人事，烟霞歸路迷。"]'),
('d5229736-8dc7-47d4-a45d-be6694468963','贈隠者','孟貫','宋','宋诗','song-poetry','','[]','世路爭名利，深山獨結茅。',48,'全唐诗/poet.song.1000.json','["世路爭名利，深山獨結茅。", "安情自得所，非道豈相交。", "百尺松當戶，千年鶴在巢。", "知君於此景，未欲等閒拋。"]'),
('31a0cc79-ed6f-4305-aa53-bc47b084cd84','寄暹上人','孟貫','宋','宋诗','song-poetry','','[]','聞罷城中講，來安頂上禪。',48,'全唐诗/poet.song.1000.json','["聞罷城中講，來安頂上禪。", "夜燈明石室，清磬出巖泉。", "欲訪慚多事，相思恨隔年。", "終期息塵慮，接話虎溪邊。"]'),
('9b2327cc-e9d3-4e8a-badd-1f8984e1c1d7','江邊閒步','孟貫','宋','宋诗','song-poetry','','[]','閒來南渡口，迤邐看江楓。',48,'全唐诗/poet.song.1000.json','["閒來南渡口，迤邐看江楓。", "一路波濤畔，數家蘆葦中。", "遠汀排晚樹，深浦漾寒鴻。", "吟罷慵回首，此情誰與同。"]'),
('f0daf4d7-388e-44b4-88bb-8ea87bd29be5','過王逸人園林','孟貫','宋','宋诗','song-poetry','','[]','谷口何時住，烟霞一徑深。',48,'全唐诗/poet.song.1000.json','["谷口何時住，烟霞一徑深。", "水聲離遠洞，山色出疏林。", "雪彩從沾鬢，年光不計心。", "自言人少到，猶喜我來尋。"]'),
('16edfa8c-6218-4158-9ad0-289d628036be','寄李處士','孟貫','宋','宋诗','song-poetry','','[]','僧話磻溪叟，平生重赤松。',48,'全唐诗/poet.song.1000.json','["僧話磻溪叟，平生重赤松。", "夜堂悲蟋蟀，秋水老芙蓉。", "吟坐倦垂釣，閒行多倚筇。", "聞名來已久，未得一相逢。"]'),
('d66b388b-ed19-48b1-b70f-ba5e93d34918','夏日寄史處士','孟貫','宋','宋诗','song-poetry','','[]','掩關苔滿地，終日坐騰騰。',48,'全唐诗/poet.song.1000.json','["掩關苔滿地，終日坐騰騰。", "暑氣冷衣葛，暮雲催燭燈。", "寂寥知得趣，疏懶似無能。", "還憶舊遊否，何年別杜陵。"]'),
('bd67e649-fa6a-4f7b-a65a-04011b5848c6','夏日登瀑頂寺因寄諸知己','孟貫','宋','宋诗','song-poetry','','[]','曾於塵埃望，此景在烟霄。',48,'全唐诗/poet.song.1000.json','["曾於塵埃望，此景在烟霄。", "巖靜水聲近，山深暑氣遥。", "杖藜青石路，煮茗白雲樵。", "寄語爲郎者，誰能訪寂寥。"]'),
('b7601bfd-d87d-4d11-ad9f-10f646757ee2','懷果上人','孟貫','宋','宋诗','song-poetry','','[]','擁錫南遊去，名香幾處焚。',48,'全唐诗/poet.song.1000.json','["擁錫南遊去，名香幾處焚。", "別來無遠信，多恐在深雲。", "好月曾同步，幽香省共聞。", "相思不相見，林下葉紛紛。"]'),
('26dec266-e02d-4b28-ae4c-78695cd9f9d6','寄故園兄弟','孟貫','宋','宋诗','song-poetry','','[]','久與鄉關阻，風塵損舊衣。',48,'全唐诗/poet.song.1000.json','["久與鄉關阻，風塵損舊衣。", "水思和月泛，山憶共僧歸。", "林想添鄰舍，溪應改釣磯。", "弟兄無苦事，不用別庭闈。"]'),
('a76396f7-a4eb-48ac-b6ea-8cf512ed2e70','早秋吟眺','孟貫','宋','宋诗','song-poetry','','[]','新秋初雨後，獨立對遥山。',48,'全唐诗/poet.song.1000.json','["新秋初雨後，獨立對遥山。", "去鳥望中沒，好雲吟裏還。", "長年慚道薄，明代取身閒。", "從有西征思，園林懶閉關。"]'),
('fac3ae01-1d9c-4ccf-8501-9649274d6340','送江爲歸嶺南','孟貫','宋','宋诗','song-poetry','','[]','舊山臨海色，歸路到天涯。',48,'全唐诗/poet.song.1000.json','["舊山臨海色，歸路到天涯。", "此別各多事，重逢是幾時。", "江行晴望遠，嶺宿夜吟遲。", "珍重南方客，清風失所思。"]'),
('a3e8aa5f-4d94-4dce-b51f-5ef570fd34a0','山中答友人','孟貫','宋','宋诗','song-poetry','','[]','偶愛春山在，因循值暑時。',48,'全唐诗/poet.song.1000.json','["偶愛春山在，因循值暑時。", "風塵非所願，泉石本相宜。", "坐久松陰轉，吟餘蟬韻移。", "自慚疏野甚，多失故人期。"]'),
('2df271ce-7afc-44dc-830c-52b5805e7005','山齋早秋雨中','孟貫','宋','宋诗','song-poetry','','[]','深居少往還，卷箔早秋間。',48,'全唐诗/poet.song.1000.json','["深居少往還，卷箔早秋間。", "雨灑吟蟬樹，雲藏嘯狖山。", "炎蒸如便退，衣葛亦堪閒。", "靜坐得無事，酒卮聊暢顔。"]'),
('096709b4-daaa-43c1-b2f6-ce57c4654c51','送人遊南越','孟貫','宋','宋诗','song-poetry','','[]','孑然南越去，替爾畏前程。',48,'全唐诗/poet.song.1000.json','["孑然南越去，替爾畏前程。", "見說路歧嶮，不通車馬行。", "瘴烟迷海色，嶺樹带猿聲。", "獨向山家宿，多應鄉思生。"]'),
('3e292128-5867-4c3d-ab83-1a2c5a022c3c','酬東溪史處士','孟貫','宋','宋诗','song-poetry','','[]','咫尺東溪路，年來偶訪遲。',48,'全唐诗/poet.song.1000.json','["咫尺東溪路，年來偶訪遲。", "泉聲迷雨夜，花片落空枝。", "石徑逢僧出，山床見鶴移。", "貧齋有琴酒，曾許月圓期。"]'),
('9ebfd6b8-fe71-4b00-ad2c-9bb0b31c604a','秋江送客','孟貫','宋','宋诗','song-poetry','','[]','秋風楚江上，送子話遊遨。',48,'全唐诗/poet.song.1000.json','["秋風楚江上，送子話遊遨。", "遠水宿何處，孤舟春夜濤。", "浦雲沈雁影，山月照猿嗥。", "莫爲饑寒苦，便成名利勞。"]'),
('ae60ce0b-1623-4df7-9e9e-7625a83d3341','寄山中高逸人','孟貫','宋','宋诗','song-poetry','','[]','烟霞多放曠，吟嘯是尋常。',48,'全唐诗/poet.song.1000.json','["烟霞多放曠，吟嘯是尋常。", "猿共摘山果，僧鄰住石房。", "躡雲雙屐冷，採藥一身香。", "我憶相逢夜，松潭月色凉。"]'),
('962bc939-ab92-4394-852f-4ce1708e0b75','懷友人','孟貫','宋','宋诗','song-poetry','','[]','浮世況多事，飄流每嘆君。',48,'全唐诗/poet.song.1000.json','["浮世況多事，飄流每嘆君。", "路岐何處去，消息幾時聞。", "吟裏落秋葉，望中生暮雲。", "孤懷誰慰我，夕鳥自成羣。"]'),
('64312d5a-d37b-4a1f-9ca5-361bd5cba8ae','送人歸別業','孟貫','宋','宋诗','song-poetry','','[]','別業五湖上，春殘去路賒。',48,'全唐诗/poet.song.1000.json','["別業五湖上，春殘去路賒。", "還尋舊山水，重到故人家。", "門徑掩芳草，園林落異花。", "君知釣磯在，猶喜有生涯。"]'),
('aab93a2a-01ba-4eaa-ae2e-58db77e3c9fe','冬日登江樓','孟貫','宋','宋诗','song-poetry','','[]','高樓臨古岸，野步晚來登。',48,'全唐诗/poet.song.1000.json','["高樓臨古岸，野步晚來登。", "江水因寒落，山雲爲雪凝。", "遠村雖入望，危檻不堪憑。", "親老未歸去，鄉愁徒自興。"]'),
('f955aa5d-2e3b-4928-ab13-4fdc3fcaa1de','寄張山人','孟貫','宋','宋诗','song-poetry','','[]','草堂南澗邊，有客嘯雲烟。',48,'全唐诗/poet.song.1000.json','["草堂南澗邊，有客嘯雲烟。", "掃葉林風後，拾薪山雨前。", "野橋通竹徑，流水入芝田。", "琴月相親夜，更深戀不眠。"]'),
('504bf5a2-e51a-436c-9b76-4f78ee7d7a54','清洛喜英公大師相訪','許仲宣','宋','宋诗','song-poetry','','[]','方袍紫染出彤庭，久在林泉養性靈。',64,'全唐诗/poet.song.1000.json','["方袍紫染出彤庭，久在林泉養性靈。", "無事撓心長見醉，有名傳世不曾醒。", "多年別我頭先白，此日逢師眼倍青。", "記得上都相會否，夜飛杯篆老君經。"]'),
('8482721e-5f38-4c76-b852-d0b662a1dea5','鍾山寺','樂史','宋','宋诗','song-poetry','','[]','千峰夾一徑，一徑花枕泉。',48,'全唐诗/poet.song.1000.json','["千峰夾一徑，一徑花枕泉。", "聽泉復看花，行到鍾山前。", "古寺雲生屋，高僧月伴禪。", "自慚留一宿，匹馬又朝天。"]'),
('cbfde33c-4840-4240-804e-46ddbedbf246','訪白陂陳處士  其一','樂史','宋','宋诗','song-poetry','','[]','沿溪復踐雲，雲邊訪道人。',48,'全唐诗/poet.song.1000.json','["沿溪復踐雲，雲邊訪道人。", "水聲齊入耳，山色來遶身。", "聞君話經濟，使我開精神。", "少微星在此，飛詔何因循。"]'),
('8f3c5dbc-ed42-476b-876f-57bd4f2ae1bf','訪白陂陳處士  其二','樂史','宋','宋诗','song-poetry','','[]','清風不見面，白汗如波流。',48,'全唐诗/poet.song.1000.json','["清風不見面，白汗如波流。", "走來君洞裏，雲樹冷颼颼。", "更瀉葡萄綠，千杯沃倒愁。", "魂疑更回首，殘熱又爲讎。"]'),
('6227730f-950d-4cb1-9dff-c6824e91ca7e','慈竹','樂史','宋','宋诗','song-poetry','','[]','蜀中何物靈，有竹慈爲名。',291,'全唐诗/poet.song.1000.json','["蜀中何物靈，有竹慈爲名。", "一叢闊數步，森森數十莖。", "長莖復短莖，枝葉不崢嶸。", "去年筍已長，今年筍又生。", "高低相倚頼，渾如長幼情。", "孝子侍父立，順孫隨祖行。", "慈愛必孝順，根枝信天成。", "吾聞唐之人，孝行常忻忻。", "鄆州張公藝，九世同一門。", "大帝聞其名，衡茅降至尊。", "馮宿丱歲時，隨父廬祖墳。", "父子相隨孝，靈芝特地春。", "北海呂元簡，四世爲家主。", "以至牛馬羊，異母皆相乳。", "虞鄉董恭直，鞠養諸孤遺。", "鴝鵒與鴉鵲，同巢而共枝。", "孝行動天地，鳥獸皆隨時。", "又聞猓然獸，死不相棄離。", "{蜳攵}𧍪與鮫魚，子母長相隨。", "獸面而人心，此獸信有之。", "獸心而人面，其人誠可悲。", "李鈞爲侍御，棄母在溫州。", "母因殍餓死，甘旨何悠悠。", "光祿李玕者，亦是斯人流。"]'),
('449f1ec9-a49a-40c8-9d54-65705fa6fbc6','詠華林書院','樂史','宋','宋诗','song-poetry','','[]','能爲孝義復爲文，惟有君家事漸新。',64,'全唐诗/poet.song.1000.json','["能爲孝義復爲文，惟有君家事漸新。", "旌表已迎金殿敕，子孫常宴杏園春。", "親情廣闊追隨大，鼓笛喧勝嫁娶頻。", "更置書堂書萬卷，不辭延待四方人。"]'),
('3271409b-9daa-4e89-8fcc-afe2827153fe','句','魏元吉','宋','宋诗','song-poetry','','[]','去來無蹤跡，大塊一飛塵。',12,'全唐诗/poet.song.1000.json','["去來無蹤跡，大塊一飛塵。"]'),
('41494d05-d604-4de2-881a-cd7ca3eb9e9f','題鎮戎軍廳壁','張繼常','宋','宋诗','song-poetry','','[]','夜聞磧外鈴聲苦，曉聽城頭畫角哀。',32,'全唐诗/poet.song.1000.json','["夜聞磧外鈴聲苦，曉聽城頭畫角哀。", "不是感恩心似鐵，誰人肯向此間來。"]'),
('b4b909c7-be08-44a6-ad77-f7597884a152','贈英公大師','李鑄','宋','宋诗','song-poetry','','[]','僧門奇士有英公，篆隸高能世莫窮。',64,'全唐诗/poet.song.1000.json','["僧門奇士有英公，篆隸高能世莫窮。", "五色彩毫傳夢寐，三乘真諦達虛空。", "賜衣深染函關上，寵號光呼柰苑中。", "幸對風情添逸趣，好陪清話在蓮宮。"]'),
('ce2d22b0-4a25-4ae4-ad9a-5b3cbf37adf7','題歙州問政山聶道士所居','黄台','宋','宋诗','song-poetry','','[]','千尋練带新安水，萬仞花屏問政山。',323,'全唐诗/poet.song.1000.json','["千尋練带新安水，萬仞花屏問政山。", "自少雲霞居物外，不多塵土到人間。", "壺懸仙島吞舟罷，椀浸星宮沈水閑。", "寶籙篋垂金縷带，絳囊絳鎖玉連環。", "靜張棋勢鋪還打，默考仙經補又刪。", "床並葛鞋寒兔伏，窗橫檉几老龍跧。", "溪童乞火朝敲竹，山鬼聽琴夜撼{枦睘}。", "草暗碧潭思句曲，松昏紫氣度深關。", "龜成淺甲毛猶綠，鶴化幽翎頂更殷。", "阮洞神仙分藥去，蔡家兄弟寄書還。", "黄精苗倒眠青鹿，紅杏枝低挂白鷳。", "容易煮茶供客用，辛勤栽果與猿攀。", "常尋靈穴通三島，擬過流沙化百蠻。", "新隠漸開侵月窟，舊林猶悅枕沙灣。", "手疏俗禮慵非傲，肘護靈方臂不慳。", "海上使頻青鳥黠，篋中藏久白馿頑。", "筇枝健拄菖蒲節，筍櫛高簪玳瑁斑。", "花氣熏心香馥馥，澗聲聆耳冷潺潺。", "高墳自掩浮生骨，短晷難窮不死顔。", "早晚重逢蕭塢客，願隨芝蓋出塵寰。"]'),
('cf77a1ab-b5c0-4f71-8764-0fca821e633b','題青紗連二枕','秦南運','宋','宋诗','song-poetry','','[]','陰香裝豔入青紗，還與敧眠好事家。',32,'全唐诗/poet.song.1000.json','["陰香裝豔入青紗，還與敧眠好事家。", "夢裏却成三色雨，枕山不敢鬭清華。"]'),
('67bf7878-5863-41ad-bdc7-3d15269ecc00','送從弟舍人入蜀','劉兼','宋','宋诗','song-poetry','','[]','嘉陵江畔餞行車，離袂難分十里餘。',64,'全唐诗/poet.song.1000.json','["嘉陵江畔餞行車，離袂難分十里餘。", "慷慨莫誇心似鐵，留連不覺淚成珠。", "風光川谷梅將發，音信雲天雁未疏。", "立馬舉鞭無限意，會稀別遠擬何如。"]'),
('f1ecd765-251e-4833-a3f3-d1eba0f0e2d2','再見從弟舍人','劉兼','宋','宋诗','song-poetry','','[]','屈指依稀十五年，鸞臺秘閣位相懸。',64,'全唐诗/poet.song.1000.json','["屈指依稀十五年，鸞臺秘閣位相懸。", "分飛淮甸雁行斷，重見江樓蟾影圓。", "滯跡未偕朝北闕，高才方命入西川。", "願君通理須還早，拜慶慈親几杖前。"]'),
('9d990a9c-15f7-4c07-b48d-1cd0517005c1','春晚寓懷','劉兼','宋','宋诗','song-poetry','','[]','一承兌澤蒞方州，八度春光照郡樓。',64,'全唐诗/poet.song.1000.json','["一承兌澤蒞方州，八度春光照郡樓。", "好景幾時官吏醉，名山時領管弦遊。", "空花任爾頻侵眼，老雪從他漸滿頭。", "歸去杜陵池閣在，只能歡笑不能愁。"]'),
('64a7c287-6b8f-4b67-8eff-512e1144cf8f','送文英大師','劉兼','宋','宋诗','song-poetry','','[]','屈指平陽別社蓮，蟾光一百度曾圓。',64,'全唐诗/poet.song.1000.json','["屈指平陽別社蓮，蟾光一百度曾圓。", "孤雲自在知何處，薄宦參差亦信緣。", "山郡披風方穆若，花時分袂更凄然。", "摇鞭相送嘉陵岸，迴首羣峰隔囊邊。"]'),
('9d60daac-f38d-4def-aa85-4bc3213afc9e','早秋遊湖上亭','劉兼','宋','宋诗','song-poetry','','[]','摇落江天萬木空，雁行斜戛塞垣風。',64,'全唐诗/poet.song.1000.json','["摇落江天萬木空，雁行斜戛塞垣風。", "征閨搗月離愁遠，舊館眠雲旅夢通。", "郢客豈能陪下里，臯禽爭肯戀樊籠。", "此心曠蕩誰相會，盡在南華十卷中。"]'),
('94d76e8b-5caf-479a-b6c1-f72915c1c674','征婦怨','劉兼','宋','宋诗','song-poetry','','[]','金閨寂寞罷粧臺，玉筯欄干界粉腮。',64,'全唐诗/poet.song.1000.json','["金閨寂寞罷粧臺，玉筯欄干界粉腮。", "花落掩關春欲暮，月圓欹枕夢初迴。", "鸞膠豈續愁腸斷，龍劍難揮別緒開。", "曾寄錦書無限意，塞鴻何事不歸來。"]'),
('228fdb7d-32a1-410d-9663-a103c05cb890','寄高書記','劉兼','宋','宋诗','song-poetry','','[]','齊朝慶裔祖敖曹，麟角無雙鳳九毛。',64,'全唐诗/poet.song.1000.json','["齊朝慶裔祖敖曹，麟角無雙鳳九毛。", "聲價五侯爭辟命，文章一代振風騷。", "醉琴自寄陶家意，夢枕誰聽益郡刀。", "補衮應星曾奏舉，北山南海孰爲高。"]'),
('6372d0cf-3dee-4dd6-a9ac-5d93e7784610','晚樓寓懷','劉兼','宋','宋诗','song-poetry','','[]','薄暮疏林宿鳥還，倚樓垂袂復憑欄。',64,'全唐诗/poet.song.1000.json','["薄暮疏林宿鳥還，倚樓垂袂復憑欄。", "月沉江底珠輪凈，雲鎖峰頭玉葉寒。", "劉毅暫貧雖壯志，馮唐將老自低顔。", "無言獨對秋風立，擬把朝簪換釣竿。"]'),
('f22a4a7f-86d3-438b-8159-e46ef31d0869','偶有下殤因而自遣','劉兼','宋','宋诗','song-poetry','','[]','彭壽殤齡共兩空，幻泡緣影夢魂中。',64,'全唐诗/poet.song.1000.json','["彭壽殤齡共兩空，幻泡緣影夢魂中。", "缺圓宿會長如月，飄忽浮生疾似風。", "脩短百年先後定，賢愚千古是非同。", "南柯太守知人意，休問陶陶塞上翁。"]'),
('5d079aff-d161-4928-b980-47c556e000a2','旭川祁宰思家而卒因述意呈秦川知己','劉兼','宋','宋诗','song-poetry','','[]','歲稔民康絕訟論，政成公暇自由身。',64,'全唐诗/poet.song.1000.json','["歲稔民康絕訟論，政成公暇自由身。", "朝看五馬閑如社，夜擁雙姬暖似春。", "家記不憂憑冢子，官資無愧是朝臣。", "豈同齷齪祁員外，至死悲凉一婦人。"]'),
('28a25697-9e8b-4aaa-84d1-3b3cd0bff923','偶聞官吏舉請輒有一篇寄呈成都府從弟舍人','劉兼','宋','宋诗','song-poetry','','[]','官吏潜陳借寇詞，宦情鄉夢兩相違。',64,'全唐诗/poet.song.1000.json','["官吏潜陳借寇詞，宦情鄉夢兩相違。", "青城錦水無心住，紫閣蓮峰有意歸。", "張翰鱸魚因醉憶，孟光書信近春稀。", "黄茅瘴色看看起，貪者猶疑別是機。"]'),
('04efac2d-19f4-4d14-97cf-2dfb230c3f7e','春遊','劉兼','宋','宋诗','song-poetry','','[]','柳成金穗草如茵，載酒尋花共賞春。',32,'全唐诗/poet.song.1000.json','["柳成金穗草如茵，載酒尋花共賞春。", "先入醉鄉君莫問，十年風景在三秦。"]'),
('49ca6f33-73a3-4a12-afec-aafd8a818000','再看光福寺牡丹','劉兼','宋','宋诗','song-poetry','','[]','去年曾看牡丹花，蛺蝶迎人傍綵霞。',64,'全唐诗/poet.song.1000.json','["去年曾看牡丹花，蛺蝶迎人傍綵霞。", "今日再遊光福寺，春風吹我入仙家。", "當筵芬馥歌脣動，倚檻嬌羞醉眼斜。", "來歲未朝京闕去，依前和露載歸衙。"]'),
('ab483eb2-1bab-40d1-a53f-c19194220b32','從弟舍人惠茶','劉兼','宋','宋诗','song-poetry','','[]','曾求芳茗貢蕪詞，果沐頒霑味甚奇。',64,'全唐诗/poet.song.1000.json','["曾求芳茗貢蕪詞，果沐頒霑味甚奇。", "龜背起紋輕炙處，雲頭翻液乍烹時。", "老丞倦悶偏宜矣，舊客過從別有之。", "珍重宗親相寄惠，水亭山閣自携持。"]'),
('809988bc-f597-4141-aef1-5e813ddca284','登郡樓書懷三首  其一','劉兼','宋','宋诗','song-poetry','','[]','烟雨樓臺漸晦冥，錦江澄碧浪花平。',64,'全唐诗/poet.song.1000.json','["烟雨樓臺漸晦冥，錦江澄碧浪花平。", "卞和未雪荆山耻，莊舄空傷越國情。", "天際寂寥無雁下，雲端依約有僧行。", "登高欲繼離騷詠，魂斷愁深寫不成。"]'),
('0f505dcf-f699-4914-9d3c-a006055e703d','登郡樓書懷三首  其二','劉兼','宋','宋诗','song-poetry','','[]','邊郡荒凉悲且歌，故園迢遞隔烟波。',64,'全唐诗/poet.song.1000.json','["邊郡荒凉悲且歌，故園迢遞隔烟波。", "琴聲背俗終如是，劍氣衝星又若何。", "朝客漸通書信少，釣舟頻引夢魂多。", "北山更有移文者，白首無塵歸去麽。"]'),
('025738c0-729a-47d6-a8b8-9644060afd8b','登郡樓書懷三首  其三','劉兼','宋','宋诗','song-poetry','','[]','莫嗔阮氏哭途窮，萬代深沉恨亦同。',64,'全唐诗/poet.song.1000.json','["莫嗔阮氏哭途窮，萬代深沉恨亦同。", "瑞玉豈知將抵鵲，鉛刀何事却屠龍。", "九夷欲適嗟吾道，五柳終歸效古風。", "獨倚郡樓無限意，滿江烟雨正冥濛。"]'),
('b650b9b9-86a7-4fcf-9549-46ffc5059fc5','春夕遣懷','劉兼','宋','宋诗','song-poetry','','[]','窮通分定莫凄凉，且放歡情入醉鄉。',64,'全唐诗/poet.song.1000.json','["窮通分定莫凄凉，且放歡情入醉鄉。", "范蠡扁舟終去相，馮唐半世只爲郎。", "風飄玉笛梅初落，酒泛金樽月未央。", "休把虛名撓懷抱，九原丘壠盡侯王。"]'),
('99a31179-bb93-4cf1-872a-4f67d11bd8f6','貴遊','劉兼','宋','宋诗','song-poetry','','[]','綉衣公子宴池塘，淑景融融萬卉芳。',64,'全唐诗/poet.song.1000.json','["綉衣公子宴池塘，淑景融融萬卉芳。", "珠翠照天春未老，管弦臨水日初長。", "風飄柳線金成穗，雨洗梨花玉有香。", "醉後不能離綺席，擬憑青帝繫斜陽。"]'),
('b74e43e7-1ee0-40f5-9c80-0e0efa014d56','中春登樓二首  其一','劉兼','宋','宋诗','song-poetry','','[]','金盃不以滌愁腸，江郡芳時憶故鄉。',64,'全唐诗/poet.song.1000.json','["金盃不以滌愁腸，江郡芳時憶故鄉。", "兩岸烟花春富貴，一樓風月夜凄凉。", "王章莫耻牛衣淚，潘岳休驚鶴鬢霜。", "歸去蓮花歸未得，白雲深處有茅堂。"]'),
('7f9bda8f-b349-4d70-88c2-cd410d55feea','中春登樓二首  其二','劉兼','宋','宋诗','song-poetry','','[]','古今通塞莫咨嗟，謾把霜髯敵歲華。',64,'全唐诗/poet.song.1000.json','["古今通塞莫咨嗟，謾把霜髯敵歲華。", "失手已慚蛇有足，用心休爲鼠無牙。", "九天雲凈方憐月，一夜風高便厭花。", "獨倚郡樓人不會，釣舟春浪接平沙。"]'),
('31b0c161-2c3f-48a0-87ee-68fd62291de0','中春宴遊','劉兼','宋','宋诗','song-poetry','','[]','二月風光似洞天，紅英翠萼蔟芳筵。',64,'全唐诗/poet.song.1000.json','["二月風光似洞天，紅英翠萼蔟芳筵。", "楚王雲雨迷巫峽，江令文章媚蜀箋。", "歌黛久顰春岫歛，舞衣新綉曉霞鮮。", "酒闌香袂初分散，笑指漁翁釣暮烟。"]'),
('277211a1-8b1e-4957-b5c2-e387fc6c9cd5','江岸獨步','劉兼','宋','宋诗','song-poetry','','[]','醉卓寒筇傍水行，漁翁不會獨吟情。',64,'全唐诗/poet.song.1000.json','["醉卓寒筇傍水行，漁翁不會獨吟情。", "龜能顧印誰相重，鶴偶乘軒自可輕。", "簪組百年終長物，文章千古亦虛名。", "是非得喪皆閑事，休向南柯與夢爭。"]'),
('16b6337a-9bc3-4dd6-b1b5-43d97edc9ccb','咸陽懷古','劉兼','宋','宋诗','song-poetry','','[]','高秋咸鎬起霜風，秦漢荒陵樹葉紅。',64,'全唐诗/poet.song.1000.json','["高秋咸鎬起霜風，秦漢荒陵樹葉紅。", "七國鬭鷄方賈勇，中原逐鹿更爭雄。", "南山漠漠雲常在，渭水悠悠事旋空。", "立馬舉鞭遥望處，阿房遺址夕陽東。"]'),
('a7c7aeab-338a-4ae8-92d3-8e21aa88aa12','倦學','劉兼','宋','宋诗','song-poetry','','[]','樂廣亡來水鏡稀，宓妃嫫母混妍媸。',64,'全唐诗/poet.song.1000.json','["樂廣亡來水鏡稀，宓妃嫫母混妍媸。", "且於霧裏藏玄豹，休向窗中問碧鷄。", "百氏典墳空自苦，一堆螢雪竟誰知。", "門前春色芳如晝，好掩書齋任所之。"]'),
('dc2dc455-41d9-46c2-908b-ffeec8656f03','晝寢','劉兼','宋','宋诗','song-poetry','','[]','花落青苔錦數重，書淫不覺避春慵。',64,'全唐诗/poet.song.1000.json','["花落青苔錦數重，書淫不覺避春慵。", "恣情枕上飛莊蝶，任爾雲間騁陸龍。", "玉液未能消氣魄，牙籤方可滌昏蒙。", "起來已被詩魔引，窗外寒敲翠竹風。"]'),
('9c17859a-da49-4033-9ca4-66584022f561','簡豎儒','劉兼','宋','宋诗','song-poetry','','[]','蹄涔豈信有滄浪，螢火何堪並太陽。',64,'全唐诗/poet.song.1000.json','["蹄涔豈信有滄浪，螢火何堪並太陽。", "淵奧未曾探禹穴，矜誇便擬越丘牆。", "小巫神氣終須怯，下俚音聲必不長。", "近日冰壺多晦昧，虎皮羊質也觀光。"]'),
('ce5fdb63-0cf3-45cb-afeb-6a78d477928d','春夕寓興','劉兼','宋','宋诗','song-poetry','','[]','忘憂何必在庭萱，是事悠悠竟可寬。',64,'全唐诗/poet.song.1000.json','["忘憂何必在庭萱，是事悠悠竟可寬。", "酒病未能辭錦里，春狂又擬入桃源。", "風吹楊柳絲千縷，月照梨花雪萬團。", "閑泥金徽度芳夕，幽泉石上自潺湲。"]'),
('a3e2bff9-e5a5-4f79-ad94-663be75d15f5','江樓望鄉寄內子','劉兼','宋','宋诗','song-poetry','','[]','獨上江樓望故鄉，淚襟霜笛共凄凉。',64,'全唐诗/poet.song.1000.json','["獨上江樓望故鄉，淚襟霜笛共凄凉。", "雲生隴首秋雖早，月在天心夜已長。", "魂夢只能隨蛺蝶，烟波無計學鴛鴦。", "蜀箋都有三千幅，總寫離情寄孟光。"]'),
('3011e336-9cc1-4bc5-896d-021d504415cc','春晝醉眠','劉兼','宋','宋诗','song-poetry','','[]','朱欄芳草綠纖纖，欹枕高堂卷晝簾。',64,'全唐诗/poet.song.1000.json','["朱欄芳草綠纖纖，欹枕高堂卷晝簾。", "處處落花春寂寂，時時中酒病厭厭。", "塞鴻信斷雖堪訝，梁燕詞多且莫嫌。", "自有卷書銷永日，霜華未用鬢邊添。"]'),
('01e096f2-c298-4eb0-94b0-d6d977db058f','命妓不至','劉兼','宋','宋诗','song-poetry','','[]','琴中難挑孰憐才，獨對良宵酒數盃。',64,'全唐诗/poet.song.1000.json','["琴中難挑孰憐才，獨對良宵酒數盃。", "蘇子黑貂將已敝，宋弘青鳥又空迴。", "月空凈牖霜成隙，風卷殘花錦作堆。", "欹枕夢魂何處去，醉和春色入天台。"]'),
('36196837-aeb6-44c2-a614-1507fcb614e0','誡是非','劉兼','宋','宋诗','song-poetry','','[]','巧舌如簧總莫聽，是非多自愛憎生。',64,'全唐诗/poet.song.1000.json','["巧舌如簧總莫聽，是非多自愛憎生。", "三人告母雖投杼，百犬聞風只吠聲。", "辨玉且寬和氏罪，誣金須認不疑情。", "因思疇昔遊談者，六國交馳亦受烹。"]'),
('9b3729e7-3386-4b12-9c92-3855598bc8a9','自遣','劉兼','宋','宋诗','song-poetry','','[]','未上亨衢獨醉吟，賦成無處博黄金。',64,'全唐诗/poet.song.1000.json','["未上亨衢獨醉吟，賦成無處博黄金。", "家人莫問張儀舌，國士須知豫讓心。", "照乘始堪沽善價，陽春爭忍混凡音。", "鵾鵬鱗翼途程在，九萬風雲海浪深。"]'),
('9c25f0a5-d7c6-4fcb-a26c-ed76463acb06','蓮塘霽望','劉兼','宋','宋诗','song-poetry','','[]','新秋菡萏發紅英，向晚風飄滿郡馨。',64,'全唐诗/poet.song.1000.json','["新秋菡萏發紅英，向晚風飄滿郡馨。", "萬疊水紋羅乍展，一雙鸂鶒綉初成。", "採蓮奴散吳歌闋，拾翠人歸楚雨晴。", "遠岸牧童吹短笛，蓼花深處信牛行。"]'),
('2a9d6806-5aa5-464b-8e53-89f11e1dd6f0','秋夕書懷二首  其一','劉兼','宋','宋诗','song-poetry','','[]','荒僻淹留歲已深，解龜無計恨難任。',64,'全唐诗/poet.song.1000.json','["荒僻淹留歲已深，解龜無計恨難任。", "守方半會蠻夷語，賀厦全忘燕雀心。", "夜靜倚樓悲月笛，秋寒欹枕泣霜砧。", "宦情總逐愁腸斷，一筯鱸魚直萬金。"]'),
('05b879fb-5589-4cff-9ffc-c7281f3b4ceb','秋夕書懷二首  其二','劉兼','宋','宋诗','song-poetry','','[]','直氣從來不入時，掩關慵更釣磻溪。',64,'全唐诗/poet.song.1000.json','["直氣從來不入時，掩關慵更釣磻溪。", "斯文未喪宣尼歎，吾道將窮阮籍悲。", "輕粉覆牆凝夜砌，亂金鋪菊織秋籬。", "南陽卧久無人問，薄命非才有可疑。"]'),
('a3bb8537-5c51-4368-901c-5dc86ba1cb57','長春節','劉兼','宋','宋诗','song-poetry','','[]','聖朝佳節遇長春，跪捧金爐祝又焚。',64,'全唐诗/poet.song.1000.json','["聖朝佳節遇長春，跪捧金爐祝又焚。", "寶藏發來天地秀，兵戈銷後帝皇尊。", "太平基址千年永，混一車書萬古存。", "更有馨香滿芳檻，和風遲日在蘭蓀。"]'),
('5b6fe132-5625-4268-a765-bee72ad9d319','對雨','劉兼','宋','宋诗','song-poetry','','[]','幽庭凝碧亦漣漪，簷霤聲繁聒夢歸。',64,'全唐诗/poet.song.1000.json','["幽庭凝碧亦漣漪，簷霤聲繁聒夢歸。", "半岫金烏纔委照，一川石燕又交飛。", "濯枝霢霂梅花吐，吹渚飄颻暑氣微。", "因憶故園閑釣處，蒼苔斑駁滿漁磯。"]'),
('82a93557-25ee-49ea-b47e-f209d43b42e9','登樓寓望','劉兼','宋','宋诗','song-poetry','','[]','憑高多是偶汍瀾，紅葉何堪照病顔。',64,'全唐诗/poet.song.1000.json','["憑高多是偶汍瀾，紅葉何堪照病顔。", "萬疊雲山供遠恨，一軒風物送秋寒。", "背琴鶴客歸松徑，橫笛牛童卧蓼灘。", "獨倚郡樓無限意，夕陽西邁水東邊。"]'),
('acf82992-b795-4907-83fb-02e3c235efe4','訪飲妓不遇招酒徒不至','劉兼','宋','宋诗','song-poetry','','[]','小橋流水接平沙，何處行雲不在家。',64,'全唐诗/poet.song.1000.json','["小橋流水接平沙，何處行雲不在家。", "畢卓未來輕竹葉，劉晨重到殢桃花。", "琴樽冷落春將盡，幃幌蕭條日又斜。", "回首却尋芳草路，金鞭拂柳思無涯。"]'),
('c4855cca-23da-4c81-9622-7e9871cb0bb9','春宴河亭','劉兼','宋','宋诗','song-poetry','','[]','柳擺輕絲拂嫩黄，檻前流水滿池塘。',64,'全唐诗/poet.song.1000.json','["柳擺輕絲拂嫩黄，檻前流水滿池塘。", "一筵金翠臨芳岸，四面烟花出粉牆。", "舞袖逐風翻綉浪，歌塵隨燕下雕梁。", "蠻箋象管休凝思，且放春心入醉鄉。"]'),
('b3da4103-a1fa-4b1e-a47c-0f06281ee3ee','夢歸故園二首  其一','劉兼','宋','宋诗','song-poetry','','[]','桐葉飛霜落井欄，菱花藏雪助衰顔。',64,'全唐诗/poet.song.1000.json','["桐葉飛霜落井欄，菱花藏雪助衰顔。", "夜窗颯颯摇寒竹，秋枕迢迢夢故山。", "臨水釣舟橫葦岸，隔溪禪侶啟柴關。", "覺來依舊三更月，離緒鄉心起萬端。"]'),
('a407336a-58c3-4243-b1ce-65cb62960dcc','夢歸故園二首  其二','劉兼','宋','宋诗','song-poetry','','[]','舊館秋寒一夢長，水簾疏影入迴塘。',64,'全唐诗/poet.song.1000.json','["舊館秋寒一夢長，水簾疏影入迴塘。", "宦情率爾拖漁艇，客恨依然在燕梁。", "白鷺獨飄山面雪，紅蕖全謝鏡心香。", "起來不語無人會，醉倚東軒半夕陽。"]'),
('59d45dff-71b2-45c3-a815-cde1ef18fdad','新竹','劉兼','宋','宋诗','song-poetry','','[]','近窗卧砌兩三叢，佐靜添幽別有功。',64,'全唐诗/poet.song.1000.json','["近窗卧砌兩三叢，佐靜添幽別有功。", "影鏤碎金初透月，聲敲寒玉乍摇風。", "無憑費叟烟波碧，莫信湘妃淚點紅。", "自是子猷偏愛爾，虛心高節雪霜中。"]'),
('dd0195ed-ca31-4568-bd2c-0d1046a3348b','木芙蓉','劉兼','宋','宋诗','song-poetry','','[]','素靈失律詐風流，强把芳菲半載偷。',64,'全唐诗/poet.song.1000.json','["素靈失律詐風流，强把芳菲半載偷。", "是葉葳蕤霜照夜，此花爛熳火燒秋。", "謝蓮色淡爭堪種，陶菊香穠亦合羞。", "誰道金風能肅物，因何厚薄不相侔。"]'),
('5e773f40-4918-4be7-a07b-416d99641bce','玉燭花','劉兼','宋','宋诗','song-poetry','','[]','裊裊香英三四枝，亭亭紅艷照階墀。',64,'全唐诗/poet.song.1000.json','["裊裊香英三四枝，亭亭紅艷照階墀。", "正當晚檻初開處，恰似春闈就試時。", "少女不吹方熠爚，東君偏惜未離披。", "夜深斜倚朱欄外，擬把隣光借與誰。"]'),
('ff338acb-c11d-4457-9577-5efdddcd3a54','新蟬','劉兼','宋','宋诗','song-poetry','','[]','齊女幈幃失舊容，侍中冠冕有芳蹤。',64,'全唐诗/poet.song.1000.json','["齊女幈幃失舊容，侍中冠冕有芳蹤。", "翅翻晚鬢尋香露，聲引秋絲逐遠風。", "旅館聽時髭欲白，戍樓聞處葉多紅。", "只知送恨添愁事，誰見凌霄羽蛻功。"]'),
('bd7133ce-b309-4f79-b21a-09cd0f794ce0','晨鷄','劉兼','宋','宋诗','song-poetry','','[]','朱冠金距綵毛身，昧爽高聲已報晨。',64,'全唐诗/poet.song.1000.json','["朱冠金距綵毛身，昧爽高聲已報晨。", "作瑞莫慚先貢楚，擅場須信獨推秦。", "淮南也伴升仙犬，函谷曾容借曉人。", "此日卑棲隨飲啄，宰君驅我亦相馴。"]'),
('f9988cfd-e11d-4295-b65b-c1da3ebe55d7','春燕','劉兼','宋','宋诗','song-poetry','','[]','多時窗外語呢喃，只要佳人卷綉簾。',64,'全唐诗/poet.song.1000.json','["多時窗外語呢喃，只要佳人卷綉簾。", "大厦已成須慶賀，高門頻入莫憎嫌。", "花間舞蝶和香趁，江畔春泥带雨啣。", "栖息數年情已厚，營巢爭肯傍他簷。"]'),
('db8b7e52-6ec1-4551-8739-ca380baef615','萬葛樹','劉兼','宋','宋诗','song-poetry','','[]','葉如羽蓋豈堪論，百步清陰鎖綠雲。',64,'全唐诗/poet.song.1000.json','["葉如羽蓋豈堪論，百步清陰鎖綠雲。", "善政已聞思召伯，英風偏稱號將軍。", "靜鋪講席麟經潤，高拂□枝兔影分。", "更有歲寒霜雪操，莫將樗櫟擬相羣。"]'),
('bf4888a7-241e-441a-82ff-499fb9ccdc05','秋夕書懷呈戎州郎中  其一','劉兼','宋','宋诗','song-poetry','','[]','素律初迴枕簟凉，松風飄泊入華堂。',64,'全唐诗/poet.song.1000.json','["素律初迴枕簟凉，松風飄泊入華堂。", "談鷄寂默紗窗靜，夢蝶蕭條玉漏長。", "歸去水雲多阻隔，別來情緒足悲傷。", "霜砧月笛休相引，只有離襟泪兩行。"]'),
('5c6c67ec-78cf-4e0b-bf77-e9fef11ddfe2','秋夕書懷呈戎州郎中  其二','劉兼','宋','宋诗','song-poetry','','[]','風送秋荷滿鼻香，竹聲敲玉近虛廊。',64,'全唐诗/poet.song.1000.json','["風送秋荷滿鼻香，竹聲敲玉近虛廊。", "夢迴故國情方黯，月過疏簾夜正凉。", "菱鏡也知移艷態，錦書其柰隔年光。", "鸞膠處處難尋覓，斷盡相思寸寸腸。"]'),
('8e97f776-563f-4ff1-9222-75ea1b0a7e44','重陽感懷二首  其一','劉兼','宋','宋诗','song-poetry','','[]','重陽不忍上高樓，寒菊年年照暮秋。',64,'全唐诗/poet.song.1000.json','["重陽不忍上高樓，寒菊年年照暮秋。", "萬疊故山雲總隔，兩行香淚血和流。", "黄茅莽莽連邊郡，紅葉紛紛落釣舟。", "歸計未成年漸老，茱萸羞戴雪霜頭。"]'),
('6b9ff41a-5a55-420f-a7ee-4cc99904346b','重陽感懷二首  其二','劉兼','宋','宋诗','song-poetry','','[]','載花乘酒上高山，四望秋空八極寬。',64,'全唐诗/poet.song.1000.json','["載花乘酒上高山，四望秋空八極寬。", "蜀國江山存不得，劉家豚犬取何難。", "張儀舊壁蒼苔厚，葛亮荒祠古木寒。", "獨對斜陽更惆悵，錦江東注似波瀾。"]'),
('d9aa982b-1796-4357-af3b-b19064dced97','蜀都道中作','劉兼','宋','宋诗','song-poetry','','[]','劍關雲棧亂崢嶸，得喪何由險與平。',64,'全唐诗/poet.song.1000.json','["劍關雲棧亂崢嶸，得喪何由險與平。", "千載龜城終失守，一堆鬼錄謾留名。", "季年必不延昏主，薄賞那堪激懦兵。", "李特後來多二世，納降歸擬盡公卿。"]'),
('aec77471-51f2-4676-a5e0-c11c184b74be','蜀都春晚感懷','劉兼','宋','宋诗','song-poetry','','[]','蜀都春色漸離披，夢斷雲空事莫追。',64,'全唐诗/poet.song.1000.json','["蜀都春色漸離披，夢斷雲空事莫追。", "宮闕一城荒作草，王孫猶自醉如泥。", "誰家玉笛吹殘照，柳市金絲拂舊堤。", "可惜錦江無錦濯，海棠花下杜鵑啼。"]'),
('b44b5850-878a-4e92-a376-853b393385da','新迴車院筵上作','劉兼','宋','宋诗','song-poetry','','[]','迴車院了未迴車，三載疲民詠袴襦。',64,'全唐诗/poet.song.1000.json','["迴車院了未迴車，三載疲民詠袴襦。", "借寇已承英主詔，乞骸須上老臣書。", "黄金蜀柳籠朱戶，碧玉湘筠映綺疏。", "因問滿筵詩酒客，錦江何處有鱸魚。"]'),
('d81e02c2-7622-4493-8f74-62bb679ca5b3','宣賜錦袍設上贈諸郡客','劉兼','宋','宋诗','song-poetry','','[]','十月芙蓉花滿枝，天庭驛騎賜寒衣。',64,'全唐诗/poet.song.1000.json','["十月芙蓉花滿枝，天庭驛騎賜寒衣。", "將同玉蝶侵肌冷，也遣金鵬遍體飛。", "夜卧始知多忝竊，晝行方覺轉光輝。", "深冬若得朝丹闕，太華峰前衣錦歸。"]'),
('396ef20d-7656-4700-bb33-85d571ed16a2','海棠花','劉兼','宋','宋诗','song-poetry','','[]','淡淡微紅色不深，依依偏得似春心。',64,'全唐诗/poet.song.1000.json','["淡淡微紅色不深，依依偏得似春心。", "烟輕虢國顰歌黛，露重長門歛淚衿。", "低傍綉簾人易折，密藏香蕊蝶難尋。", "良宵更有多情處，月下芬芳伴醉吟。"]'),
('f5496ac6-0e26-4997-8da5-f30fe602ed19','春晚閑望','劉兼','宋','宋诗','song-poetry','','[]','東風滿地是梨花，只把琴心殢酒家。',64,'全唐诗/poet.song.1000.json','["東風滿地是梨花，只把琴心殢酒家。", "立處晚樓橫短笛，望中春草接平沙。", "雁行斷續晴天遠，燕翼參差翠幕斜。", "歸計未成頭欲白，釣舟烟浪思無涯。"]'),
('ed342a9c-38c2-4533-8578-cf7d13ab6bb4','寄酬滑州文秀大師','劉兼','宋','宋诗','song-poetry','','[]','分飛屈指十三年，菡萏峰前別社蓮。',64,'全唐诗/poet.song.1000.json','["分飛屈指十三年，菡萏峰前別社蓮。", "薄宦偶然來左蜀，孤雲何事在南燕。", "一封瑶檢音初達，兩處金沙色共圓。", "珍重湯休惠佳句，郡齋吟久不成眠。"]'),
('c995f327-4202-47cd-b66d-878909cc943d','寄長安鄭員外','劉兼','宋','宋诗','song-poetry','','[]','屈指良交十四人，隙駒風燭漸爲塵。',64,'全唐诗/poet.song.1000.json','["屈指良交十四人，隙駒風燭漸爲塵。", "當初花下三秦客，只有天涯二老身。", "乘醉幾同遊北內，尋芳多共謁東鄰。", "此時阻隔關山遠，月滿江樓淚滿巾。"]'),
('e939abbb-21b3-4abb-bc58-321141c92c12','貽諸學童','劉兼','宋','宋诗','song-poetry','','[]','橫經叉手步還趨，積善方知慶有餘。',64,'全唐诗/poet.song.1000.json','["橫經叉手步還趨，積善方知慶有餘。", "五箇小雛離學院，一行新雁入貧居。", "攘羊告罪言何直，舐犢牽情理豈虛。", "勸汝立身須苦志，月中丹桂自扶疏。"]'),
('892c56c1-436b-452b-97f0-f4afdebbfa3c','對鏡','劉兼','宋','宋诗','song-poetry','','[]','青鏡重磨照白鬚，白鬚閑撚意何如。',64,'全唐诗/poet.song.1000.json','["青鏡重磨照白鬚，白鬚閑撚意何如。", "故園迢遞千山外，荒郡淹留四載餘。", "風送竹聲侵枕簟，月移花影過庭除。", "秋霜滿領難消釋，莫讀離騷失意書。"]'),
('10662eb0-2d5c-418a-950d-3020f49e6547','中夏晝卧','劉兼','宋','宋诗','song-poetry','','[]','寂寂無憀九夏中，傍簷依壁待清風。',32,'全唐诗/poet.song.1000.json','["寂寂無憀九夏中，傍簷依壁待清風。", "壯圖奇策無人問，不及南陽一卧龍。"]'),
('6533e400-636f-49ab-a97d-858ae61a11ff','到郡後寄西川從弟舍人右司閻郎中齊殿院','劉兼','宋','宋诗','song-poetry','','[]','蜀路新修盡坦平，交親深幸再逢迎。',64,'全唐诗/poet.song.1000.json','["蜀路新修盡坦平，交親深幸再逢迎。", "正當返袂思鄉國，却似歸家見弟兄。", "霑澤只慚堯綍重，泝流還喜范舟輕。", "欲將感戀裁書旨，多少魚箋寫得成。"]'),
('ae47597f-2f4f-454d-8d65-571f9ec45bbc','初至郡界','劉兼','宋','宋诗','song-poetry','','[]','嘉陵江畔接榮川，兩畔旌旗下瀨船。',64,'全唐诗/poet.song.1000.json','["嘉陵江畔接榮川，兩畔旌旗下瀨船。", "郡印已分炎瘴地，朝衣猶惹御爐烟。", "蓮塘小飲香隨艇，月榭高吟水壓天。", "錦字莫嫌歸路遠，華夷一統太平年。"]'),
('86862fe7-874c-4bfd-a905-e951975aca4c','送二郎君歸長安','劉兼','宋','宋诗','song-poetry','','[]','我兒辭去淚雙流，蜀郡秦川兩處愁。',64,'全唐诗/poet.song.1000.json','["我兒辭去淚雙流，蜀郡秦川兩處愁。", "紅葉滿山歸故國，黄茅徧地住他州。", "荷衣曉掛慚官吏，菱鏡秋窺訝鬢髹。", "好向雲泉營舊隠，莫教莊叟畏犧牛。"]'),
('c4c331c0-dc06-4dde-b7ef-39cdc2b3059c','登郡樓書事','劉兼','宋','宋诗','song-poetry','','[]','偶奉綸書蒞旭川，郡樓嘉致盡依然。',64,'全唐诗/poet.song.1000.json','["偶奉綸書蒞旭川，郡樓嘉致盡依然。", "松欹鳥道雲藏寺，月滿漁舟水浸天。", "望帝古祠花簇簇，錦城歸路草芊芊。", "有時倚檻垂雙袂，故國風光似眼前。"]'),
('63fa228a-f911-4f7a-8f05-1a24c0039bf3','酬勾評事','劉兼','宋','宋诗','song-poetry','','[]','閑庭欹枕正悲秋，忽覺新編涴遠愁。',64,'全唐诗/poet.song.1000.json','["閑庭欹枕正悲秋，忽覺新編涴遠愁。", "才薄只愁安雁戶，年高空憶復漁舟。", "鷺翹皓雪臨汀岸，蓮裊紅香匝郡樓。", "對景却慚無藻思，南金荆玉卒難酬。"]'),
('abe2b428-94b6-4fdb-b265-78a3e3480ed2','郡樓閑望書懷','劉兼','宋','宋诗','song-poetry','','[]','郡城樓閣遶江濱，風物清秋入望頻。',64,'全唐诗/poet.song.1000.json','["郡城樓閣遶江濱，風物清秋入望頻。", "銅鼓祭龍雲塞廟，蘆花飄市雪粘人。", "蓮披凈沼羣香散，鷺點寒烟玉片新。", "歸去杜陵池館在，且將朝服拂埃塵。"]'),
('fcebb327-220e-4948-9e40-886c2e19ac59','郡齋寓興','劉兼','宋','宋诗','song-poetry','','[]','依約樊川似旭川，郡齋風物盡蕭然。',64,'全唐诗/poet.song.1000.json','["依約樊川似旭川，郡齋風物盡蕭然。", "秋庭碧蘚鋪雲錦，晚閣紅蕖簇水仙。", "醉筆語狂揮粉壁，歌梁塵亂拂花鈿。", "情懷放蕩無羈束，地角天涯亦信緣。"]'),
('f1a9a024-d0b7-4ca2-8d63-d42965ea83ce','春游','劉兼','宋','宋诗','song-poetry','','[]','摇摇離緒不能持，滿郡花開酒熟時。',64,'全唐诗/poet.song.1000.json','["摇摇離緒不能持，滿郡花開酒熟時。", "羞聽黄鶑求善友，强隨綠柳展愁眉。", "隔雲故國山千疊，傍水芳林錦萬枝。", "聖主未容歸北闕，且將勤儉撫南夷。"]'),
('777d6d93-ba76-47af-b3d9-1b298ad6af5a','春宵','劉兼','宋','宋诗','song-poetry','','[]','春雲春日共朦朧，滿院梨花半夜風。',64,'全唐诗/poet.song.1000.json','["春雲春日共朦朧，滿院梨花半夜風。", "宿酒未醒珠箔卷，艷歌初闋玉樓空。", "五湖范蠡才堪重，六印蘇秦道不同。", "再取素琴聊假寐，南柯靈夢莫相通。"]'),
('34dc6161-3d88-4403-a6d1-9eb4e63bb647','芳春','劉兼','宋','宋诗','song-poetry','','[]','微雨微風隔晝簾，金爐檀炷冷慵添。',64,'全唐诗/poet.song.1000.json','["微雨微風隔晝簾，金爐檀炷冷慵添。", "桃花滿地春牢落，柳絮成堆雪棄嫌。", "寶瑟不能邀卓氏，綵毫何必夢江淹。", "宦情歸興休相撓，隼旆漁舟總未厭。"]'),
('d9c028f3-15ed-4c23-b7c8-98353c8b83e7','春霽','劉兼','宋','宋诗','song-poetry','','[]','春霽江山似畫圖，醉垂鞭袂出康衢。',64,'全唐诗/poet.song.1000.json','["春霽江山似畫圖，醉垂鞭袂出康衢。", "猖狂亂打貔貅鼓，稽懶慵修鴛鷺書。", "老色漸來欺鬢髮，閑情將欲傲簪裾。", "苔錢遍地知多少，買得花枝不落無。"]'),
('1e6dc150-eb93-439a-a01a-e6e3fc274d20','春夜','劉兼','宋','宋诗','song-poetry','','[]','薄薄春雲籠皓月，杏花滿地堆香雪。',32,'全唐诗/poet.song.1000.json','["薄薄春雲籠皓月，杏花滿地堆香雪。", "醉垂羅袂倚朱欄，小數玉仙歌未闋。"]'),
('06cc5f9f-2dec-49cf-9a6d-3a38065b424d','西齋','劉兼','宋','宋诗','song-poetry','','[]','西齋新竹兩三莖，也有風敲碎玉聲。',32,'全唐诗/poet.song.1000.json','["西齋新竹兩三莖，也有風敲碎玉聲。", "莫恨移來欄檻遠，譬如元本此間生。"]'),
('14767739-b331-4a49-a7c9-ea42eaa218c5','春怨','劉兼','宋','宋诗','song-poetry','','[]','繡林紅岸落花鈿，故去新來感自然。',64,'全唐诗/poet.song.1000.json','["繡林紅岸落花鈿，故去新來感自然。", "絕塞杪春悲漢月，長林深夜泣緗弦。", "錦書雁斷應難寄，菱鏡鸞孤貌可憐。", "獨倚畫屏人不會，夢魂纔別戍樓邊。"]'),
('e80e7460-a96b-40ef-815c-433b9ad69985','宴遊池館','劉兼','宋','宋诗','song-poetry','','[]','綺筵金碧照芳菲，酒滿瑶卮水滿池。',64,'全唐诗/poet.song.1000.json','["綺筵金碧照芳菲，酒滿瑶卮水滿池。", "去歲南岐離郡日，今春東蜀看花時。", "儉蓮發臉當籌著，緒柳生腰按柘枝。", "座客半酣言笑狎，孔融懷抱正怡怡。"]'),
('a1caaa1b-bd9f-41f5-9e46-efb6aa2d3941','去年今日','劉兼','宋','宋诗','song-poetry','','[]','去年今日到榮州，五騎紅塵入郡樓。',64,'全唐诗/poet.song.1000.json','["去年今日到榮州，五騎紅塵入郡樓。", "貔虎只知迎太守，蠻夷不信是儒流。", "姦豪已息時將泰，疲瘵全蘇歲又周。", "聖主若容辭重祿，便歸烟水狎羣鷗。"]'),
('1d1d4b35-cbe8-4100-87dd-95c83904ad98','題義門胡氏華林書院','王綸','宋','宋诗','song-poetry','','[]','華林幽勝地，胡氏舊門閭。',48,'全唐诗/poet.song.1000.json','["華林幽勝地，胡氏舊門閭。", "四遠來名士，一家常義居。", "素風殊不墜，儒業未曾虛。", "何日諧尋訪，琴棋萬卷書。"]'),
('6ea3f3db-9db7-409e-bc15-bbbd97d9644d','題義門胡氏華林書院','趙赴','宋','宋诗','song-poetry','','[]','家隠西山下，華林地絕塵。',48,'全唐诗/poet.song.1000.json','["家隠西山下，華林地絕塵。", "門旌千古義，學聚四方人。", "道致清雲富，名隨白日新。", "他年應許我，猿鶴一相親。"]'),
('795cf5e6-e065-4ccf-9451-0de0842d37ef','題義門胡氏華林書院','姚秘','宋','宋诗','song-poetry','','[]','南紀仙鄉景最佳，林泉幽致有儒家。',64,'全唐诗/poet.song.1000.json','["南紀仙鄉景最佳，林泉幽致有儒家。", "門旌孝義爲人範，殿試賢能是國華。", "物象四時供野興，圖書萬卷益生涯。", "遥思竹閣憑虛檻，下瞰章江浸曉霞。"]'),
('cfcb9dbd-b57b-4eaf-b57a-02e0621c2fdb','題義門胡氏華林書院','賈宜','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','滕王閣畔斗星傍，此處幽人構草堂。',64,'全唐诗/poet.song.1000.json','["滕王閣畔斗星傍，此處幽人構草堂。", "鶴散窗含松島露，客來衣带橘洲香。", "詔旌門第殊恩沛，教被鄉閭益訟藏。", "小圃花時三徑雪，朝昏誰共對琴觴。"]'),
('9439f132-c7ca-4718-90e3-a386abc56e61','題義門胡氏華林書院','張孝隆','宋','宋诗','song-poetry','','[]','烟霞縹緲鎖仙鄉，萬卷詩書一草堂。',64,'全唐诗/poet.song.1000.json','["烟霞縹緲鎖仙鄉，萬卷詩書一草堂。", "孝義聲華輝北闕，門閭顯赫耀南方。", "千尋瀑布侵肌冷，四季閑花撲鼻香。", "勝事人間無敵處，王公詩版砌虹梁。"]'),
('75e1758a-d4fd-461b-92c5-bde14f2e7c1f','題義門胡氏華林書院','王浻','宋','宋诗','song-poetry','','[]','桃李清明舊著行，門旌高映郤詵堂。',64,'全唐诗/poet.song.1000.json','["桃李清明舊著行，門旌高映郤詵堂。", "烏衣里巷欽風化，曲水盃盤樂羽觴。", "客館早鄰徐孺宅，仙居今似武夷鄉。", "家聲傳得緗縑事，後裔揚名道更光。"]'),
('3964b256-b3dd-48cd-a679-c6a15120aab3','題義門胡氏華林書院','師禎','宋','宋诗','song-poetry','','[]','滿架高峰隠史書，英儒冠蓋會仙居。',64,'全唐诗/poet.song.1000.json','["滿架高峰隠史書，英儒冠蓋會仙居。", "雲霞滿屋光難掩，松柏數庭景有餘。", "累世子孫傳孝義，一時旌表在門閭。", "要知感伏休徵處，次第鸞凰上碧虛。"]'),
('6b41d057-0b7b-421b-b0d7-f2ef91eed7dd','題義門胡氏華林書院','柳直','宋','宋诗','song-poetry','','[]','華林茂族藹青芬，族本重華遠裔孫。',64,'全唐诗/poet.song.1000.json','["華林茂族藹青芬，族本重華遠裔孫。", "弟姪聲光攀郤桂，君王恩渥表于閭。", "書幃月鑒琴橫席，吟閣雲殘村隔原。", "多感朝英寄詩什，永留風雅賁丘園。"]'),
('1e4692dd-f689-4b91-8903-41436f369eda','題義門胡氏華林書院','鄴雍','宋','宋诗','song-poetry','','[]','大易談餘慶，胡君世聚居。',48,'全唐诗/poet.song.1000.json','["大易談餘慶，胡君世聚居。", "家聲先孝弟，庭訓守詩書。", "百堵環堂宇，千箱助歲儲。", "榮逢平治日，天監表門閭。"]'),
('6195c2d9-6297-4c5c-ad94-b6f8d991851b','題義門胡氏華林書院','牧湜','宋','宋诗','song-poetry','','[]','門籍偏彰孝義名，書齋高啟集羣英。',64,'全唐诗/poet.song.1000.json','["門籍偏彰孝義名，書齋高啟集羣英。", "池光冷射縑緗帙，竹籟清含弦誦聲。", "養鶴庭連栽葯圃，駐僧居近煮茶鐺。", "江上勝地文章盛，歲歲人看出谷鶑。"]'),
('f6de4e2d-7569-4e28-8cc0-788fabfa7dbc','題司空山觀','李韶','宋','宋诗','song-poetry','','[]','梁代真人上紫微，水盤山脚五雲飛。',32,'全唐诗/poet.song.1000.json','["梁代真人上紫微，水盤山脚五雲飛。", "杉松老盡無消息，猶得千一年度歸。"]'),
('6cce91ce-1980-41de-9dc4-eccdc5dcd306','與孫氏','周默','宋','宋诗','song-poetry','','[]','五十衰翁二十妻，目昏髮白已頭低。',32,'全唐诗/poet.song.1000.json','["五十衰翁二十妻，目昏髮白已頭低。", "絳幃深處休論議，天外青鸞伴木鷄。"]'),
('ad5087c4-3098-4d91-9233-97c30437f96a','與周默','孫氏','宋','宋诗','song-poetry','','[]','雨集枯池時漸滿，藤籠老木一翻新。',32,'全唐诗/poet.song.1000.json','["雨集枯池時漸滿，藤籠老木一翻新。", "如今且悅目前景，粧點亭臺隨分春。"]'),
('ec4ecb31-2b3a-486c-a9ac-0b362548ef72','題南山池','梁藻','宋','宋诗','song-poetry','','[]','翡翠戲翻荷葉雨，鷺鷥飛破竹林烟。',32,'全唐诗/poet.song.1000.json','["翡翠戲翻荷葉雨，鷺鷥飛破竹林烟。", "時沽村酒臨軒酌，旋碾新茶靠石煎。"]'),
('2d727216-d970-4a9d-8ba4-7594487d074d','句  其一','釋清晤','宋','宋诗','song-poetry','','[]','鳥歸花影動，魚觸浪痕圓。',12,'全唐诗/poet.song.1000.json','["鳥歸花影動，魚觸浪痕圓。"]'),
('9f4d93b8-23c0-4940-a375-83a101f50a03','句  其二','釋清晤','宋','宋诗','song-poetry','','[]','疊波漾層漢，殘陽補斷霞。',12,'全唐诗/poet.song.1000.json','["疊波漾層漢，殘陽補斷霞。"]'),
('c13546e1-50d0-4d0f-aeac-e85354c0fa82','問詮禪師','釋某','宋','宋诗','song-poetry','','[]','覿面難逢處，如何顧鑒咦。',24,'全唐诗/poet.song.1000.json','["覿面難逢處，如何顧鑒咦。", "乞師垂半偈，免使後人疑。"]'),
('e74dc513-0442-469b-b2c9-77f3f8ccb6a9','送何水部蒙出牧袁州','戚維','宋','宋诗','song-poetry','','[]','又領親民任，星車別紫微。',48,'全唐诗/poet.song.1000.json','["又領親民任，星車別紫微。", "隼旟新命重，鶴髮故人稀。", "雲樹看如畫，風帆去似飛。", "鄉中諸父老，榮羨錦衣歸。"]'),
('e8b89428-143f-4707-82b0-717a1120d556','留題浯溪','王伸','宋','宋诗','song-poetry','','[]','湘川佳致有浯溪，元結雄文向此題。',32,'全唐诗/poet.song.1000.json','["湘川佳致有浯溪，元結雄文向此題。", "想得後人難以繼，高名常與白雲齊。"]'),
('0dcd854b-815d-4b80-ad94-42ab41277aa2','句','王伸','宋','宋诗','song-poetry','','[]','聲聲相勸教歸去，莫是陶潜化作君。',16,'全唐诗/poet.song.1000.json','["聲聲相勸教歸去，莫是陶潜化作君。"]'),
('21d303b2-cec9-43cf-b84a-a6b18b474915','送武補闕','襄陽妓','宋','宋诗','song-poetry','','[]','弄珠灘上欲銷魂，獨把離懷寄酒樽。',32,'全唐诗/poet.song.1000.json','["弄珠灘上欲銷魂，獨把離懷寄酒樽。", "無限烟花不留意，忍教芳草怨王孫。"]'),
('09921df5-0353-40a2-9b28-dcf490ef0c95','簡寂觀作','孫邁','宋','宋诗','song-poetry','','[]','松接朝天路，鐘聞賈客船。',24,'全唐诗/poet.song.1000.json','["松接朝天路，鐘聞賈客船。", "醮壇秋有月，丹井古無泉。"]'),
('fc240879-9498-4eed-b250-ddd40e762d84','齊山僧舍','孫邁','宋','宋诗','song-poetry','','[]','竹密通幽逕，橋橫逐澗斜。',48,'全唐诗/poet.song.1000.json','["竹密通幽逕，橋橫逐澗斜。", "陰崖聳圭璧，古蔓引龍蛇。", "寺僻虛僧磬，亭荒足兔罝。", "紫微今不見，著意採黄花。"]'),
('109620f5-8995-49c8-92b0-c1106d4045e6','游齊山寺尋陳鴻斷碑','孫邁','宋','宋诗','song-poetry','','[]','萬木參天繞寺籬，一聲孤磬徹江湄。',64,'全唐诗/poet.song.1000.json','["萬木參天繞寺籬，一聲孤磬徹江湄。", "樓邊已失陳鴻記，亭上猶存杜牧詩。", "細雨乍經巖溜響，嫩苔長積石橋危。", "知予好古心常切，僧與前山覓斷碑。"]'),
('a9e1e7fc-05c9-4ac4-b6d1-c37d4e7b8310','劉僊石詩','孫邁','宋','宋诗','song-poetry','','[]','珍重標前史，名教萬古存。',48,'全唐诗/poet.song.1000.json','["珍重標前史，名教萬古存。", "誰知劉越石，便是洞天門。", "變化終□測，神仙未易論。", "後人采扣處，白石又黄昏。"]'),
('b9599723-dfb4-4074-a43d-a11f1434c592','題義門胡氏華林書院','孫邁','宋','宋诗','song-poetry','','[]','潯陽風景接洪都，傳說胡君四世居。',64,'全唐诗/poet.song.1000.json','["潯陽風景接洪都，傳說胡君四世居。", "詩句滿朝皆誦詠，君王旌孝表門閭。", "數聞過客談多惠，幾欲憑僧去借書。", "若把公卿名刻石，共瞻駟馬慕相如。"]'),
('3fee9c8f-5352-4eb2-a743-1549d2f7ecaf','禁林讌會之什','王著','宋','宋诗','song-poetry','','[]','文明天子重詞臣，聖製褒揚日月新。',96,'全唐诗/poet.song.1000.json','["文明天子重詞臣，聖製褒揚日月新。", "宸翰特頒仙署額，皇風先發玉堂春。", "虯龍逸勢誠難伏，鸞鶴迴翔信得真。", "齊武任誇非入妙，漢章雖巧未通神。", "匪唯衒耀鼇宮客，兼是輝華鳳閣人。", "幸接英儒同讚詠，輒書狂斐繼清塵。"]'),
('4eff7535-5fb0-4559-a977-435ed2a764c2','句  其一','李度','宋','宋诗','song-poetry','','[]','全家離錦水，五月下瞿塘。',36,'全唐诗/poet.song.1000.json','["全家離錦水，五月下瞿塘。", "繡服青蛾女，雕鞍白面郎。", "纍纍輜重遠，杳杳路歧長。"]'),
('b83749eb-6532-46d1-bbb5-3cf8610810a7','句  其二','李度','宋','宋诗','song-poetry','','[]','醉輕浮世事，老重故鄉人。',12,'全唐诗/poet.song.1000.json','["醉輕浮世事，老重故鄉人。"]'),
('68541f53-b23b-43ed-8fcd-010a8e798e26','送李少和還山','夏侯嶠','宋','宋诗','song-poetry','','[]','暫來雙闕下，雅向九霞間。',48,'全唐诗/poet.song.1000.json','["暫來雙闕下，雅向九霞間。", "遂策雲中杖，言歸海上山。", "入林煮白石，服氣駐朱顔。", "自愧風塵客，瓊枝窅莫攀。"]'),
('e8dcf2be-a9d5-48b6-8767-70ed32a58b87','贈南嶽宣義大師英公','蘇德祥','宋','宋诗','song-poetry','','["\u8861\u5c71"]','學就書聞在道林，幾年辛苦用身心。',64,'全唐诗/poet.song.1000.json','["學就書聞在道林，幾年辛苦用身心。", "九霄雨露酬知早，百首風騷立意深。", "青白野雲閑裏卧，古今碑碣醉中尋。", "因何負此多般藝，可惜教師鬢雪侵。"]'),
('30d9a2b7-6648-4f2c-8b6b-9161171d2455','贈英公大師','穎贄','宋','宋诗','song-poetry','','[]','蠻牋象管少年時，幾賦簾前祝壽詩。',64,'全唐诗/poet.song.1000.json','["蠻牋象管少年時，幾賦簾前祝壽詩。", "三殿荷恩卿相看，兩朝承寵帝王知。", "尋窮太華高低景，念盡長安內外碑。", "可惜篆文今絕筆，李陽冰後只吾師。"]'),
('2e386915-455a-43d8-80ab-67198b090d07','新月應制','盧多遜','宋','宋诗','song-poetry','','[]','太液池邊看月時，好風吹動萬年枝。',32,'全唐诗/poet.song.1000.json','["太液池邊看月時，好風吹動萬年枝。", "誰家玉匣開新鏡，露出清光些子兒。"]'),
('825d9fdb-bbe4-46b8-b859-20b1c5233567','哀挽詩','盧多遜','宋','宋诗','song-poetry','','[]','軍門半掩槐花宅，每過猶聞哭臨聲。',48,'全唐诗/poet.song.1000.json','["軍門半掩槐花宅，每過猶聞哭臨聲。", "漸窮老僕慵看馬，著慘佳人懶按箏。", "詩侶酒徒消散盡，一場春夢越王城。"]'),
('2feda47e-da18-48ad-93e2-1a90cc09388d','南水村','盧多遜','宋','宋诗','song-poetry','','[]','珠崖風景水南村，山下人家林下門。',64,'全唐诗/poet.song.1000.json','["珠崖風景水南村，山下人家林下門。", "鸚鵡巢時椰結子，鷓鴣啼處竹生孫。", "漁鹽家給無虛市，禾黍年登有酒尊。", "遠客杖藜來往熟，却疑身世在桃源。"]'),
('bb226dea-b6f4-4298-a30f-3ba5dba36855','題越臺','張洎','宋','宋诗','song-poetry','','[]','我愛真人居，高臺倚寥泬。',72,'全唐诗/poet.song.1000.json','["我愛真人居，高臺倚寥泬。", "洞天開兩扉，邈爾與世絕。", "縹緲乘鸞女，華顔映綠髮。", "舉手拂烟虹，吹笙弄松月。", "森羅窺萬象，境異趣亦別。", "何必服金丹，飛身向蓬闕。"]'),
('1a188fb1-c676-4edb-8abf-20a4b213b990','暮春月內署書閣前海棠花盛開率爾七言八韻寄長卿諫議','張洎','宋','宋诗','song-poetry','','[]','去歲海棠花發日，曾將詩句詠芳妍。',128,'全唐诗/poet.song.1000.json','["去歲海棠花發日，曾將詩句詠芳妍。", "今來花發春依舊，君已雄飛玉案前。", "驟隔清塵樞要地，獨攀紅蘂豔陽天。", "疏枝高映銀臺月，嫩葉低含綺閣烟。", "花落花開懷勝賞，春來春去感流年。", "清辭早綴巴人唱，妙翰猶緘蜀國牋。", "共仰壯圖方赫耳，自嗟衰鬢轉皤然。", "因憑鶑蝶傳消息，莫望蓬萊有病仙。"]'),
('bf6e6971-f6bb-4e5e-8dd3-97af8e8c25b3','紀贈宣義大師夢英','張洎','宋','宋诗','song-poetry','','[]','幾憶湯師役夢魂，醉吟想在落花村。',64,'全唐诗/poet.song.1000.json','["幾憶湯師役夢魂，醉吟想在落花村。", "背塵事見尋常說，出格詩曾子細論。", "書信寄憑雖有路，笑談重約恨無門。", "今來鬢雪應多也，莫惜頻頻近酒罇。"]'),
('d10f52a3-9a50-46a0-89fd-891274461efd','句  其一','張洎','宋','宋诗','song-poetry','','[]','眼昏書字大，耳重覺聲高。',12,'全唐诗/poet.song.1000.json','["眼昏書字大，耳重覺聲高。"]'),
('0e66bb87-82af-493a-bf4d-f88d4776851f','句  其二','張洎','宋','宋诗','song-poetry','','[]','風物一堆灰。',6,'全唐诗/poet.song.1000.json','["風物一堆灰。"]'),
('42fa22af-c438-4187-96d2-7d0e90e2dff3','禁林讌會之什','柴成務','宋','宋诗','song-poetry','','[]','內署延賓宴玉堂，紫闈深啟會琳琅。',96,'全唐诗/poet.song.1000.json','["內署延賓宴玉堂，紫闈深啟會琳琅。", "雲霏寶額題宸翰，金錯瑶編勒御章。", "盤薦異羞羅彩翠，盞頌醇醴湛清光。", "柳當朱檻春先到，日過花磚影漸長。", "吟客盡容窺綺閣，棲禽應許託雕梁。", "觀榮共樂文明代，惟願登歌頌聖皇。"]'),
('d1c859cd-979d-490c-bef9-f89f38d27183','贈淳于公歸養','柴成務','宋','宋诗','song-poetry','','[]','九霄新命降絲綸，榮列青宮聽侍親。',64,'全唐诗/poet.song.1000.json','["九霄新命降絲綸，榮列青宮聽侍親。", "著□顯通天上籍，循陔重看海邊春。", "入爲鴛鷺行中客，歸作烟霞象外人。", "一自二疏東去後，唯公千載繼芳塵。"]'),
('001932eb-cbd8-46e9-8f69-189c829610d1','答內翰學士','舒雅','宋','宋诗','song-poetry','','[]','清貴無過近侍臣，多情猶憶舊交親。',64,'全唐诗/poet.song.1000.json','["清貴無過近侍臣，多情猶憶舊交親。", "金蓮燭下裁詩句，麟角峰前寄隠淪。", "和氣忽飄燕谷暖，好風徐起謝庭春。", "緘藏便是山家寶，留與兒孫世不貧。"]'),
('031dbce8-78bd-4904-a26e-c98f526eecd6','答錢少卿','舒雅','宋','宋诗','song-poetry','','[]','蓬萊閣下舊鄰居，偶別俄驚四載餘。',64,'全唐诗/poet.song.1000.json','["蓬萊閣下舊鄰居，偶別俄驚四載餘。", "每見寒葭思倚玉，忽臨秋水得雙魚。", "人間貴盛君誰及，物外優閑我自如。", "聞說歸艎向春渚，深知不與道情疏。"]'),
('69de8a2d-1624-43ef-b84c-683668907239','答劉學士','舒雅','宋','宋诗','song-poetry','','[]','往歲別京畿，棲山與衆違。',48,'全唐诗/poet.song.1000.json','["往歲別京畿，棲山與衆違。", "君心似松柏，雁足寄珠璣。", "學道情難篤，燒丹力尚微。", "雲中鷄犬在，祇候主人歸。"]'),
('41b176eb-8c49-4859-bf19-f996142d13ac','送僧歸護國寺','舒雅','宋','宋诗','song-poetry','','[]','偶思皇澤來丹闕，却爲禪齋返舊林。',64,'全唐诗/poet.song.1000.json','["偶思皇澤來丹闕，却爲禪齋返舊林。", "嶺上白雲終掛念，人間餘事不關心。", "澄潭雨過秋涵月，古檜風生夜對琴。", "聞道石橋多勝境，幾時相伴一閒尋。"]'),
('debcb7dc-fbd7-4dec-9fee-08da1b0d4a69','題義門胡氏華林書院','舒雅','宋','宋诗','song-poetry','','[]','江外力爲儒，榮華表里閭。',96,'全唐诗/poet.song.1000.json','["江外力爲儒，榮華表里閭。", "後生多折桂，數世必同居。", "築室寒留穀，穿池夏養魚。", "買山添勝境，移席講新書。", "竹鳥鄰僧剎，溪亭入野蔬。", "姓名喧魏闕，行止到公車。", "顧我曾遊此，多年尚憶諸。", "未能重得去，寄詠一躊躇。"]'),
('cf0a9f8a-e677-46af-a037-00a5cf875b61','太守王公植松因賦','舒雄','宋','宋诗','song-poetry','','[]','滁上分憂老外郎，昔年曾此典南漳。',48,'全唐诗/poet.song.1000.json','["滁上分憂老外郎，昔年曾此典南漳。", "雙旌引過題橋路，五里迎歸衣錦鄉。", "種是萬株松樹在，至今民喚作甘棠。"]'),
('308bdb65-9eb4-42d6-9862-dcf305c6f7aa','金乳池偈','釋定光','宋','宋诗','song-poetry','','[]','山礦生金乳，地官闢關門。',24,'全唐诗/poet.song.1000.json','["山礦生金乳，地官闢關門。", "石礦水直出，供養天心尊。"]'),
('dcf792af-49f8-46f0-92ad-4e2f3964e2f3','龍潭偈','釋定光','宋','宋诗','song-poetry','','[]','天風毗地勢，地水轉勢頭。',24,'全唐诗/poet.song.1000.json','["天風毗地勢，地水轉勢頭。", "沙石立來堆，水心主巨州。"]'),
('46733dc5-804b-46c8-99b5-4cfc4210ea7d','南安巖偈','釋定光','宋','宋诗','song-poetry','','[]','八龍歸順起峰端，虎嘯巖前左右迴。',32,'全唐诗/poet.song.1000.json','["八龍歸順起峰端，虎嘯巖前左右迴。", "好與子孫興徒衆，他時須降御書來。"]'),
('e8f88625-9769-40f7-beb2-19802a8cfeb8','句','釋定光','宋','宋诗','song-poetry','','[]','一峰獅子吼，十二子相隨。',12,'全唐诗/poet.song.1000.json','["一峰獅子吼，十二子相隨。"]'),
('d7e260ee-cbb5-4a7c-94f0-1bfc31d0413d','上清辭五首  其一','李九齡','宋','宋诗','song-poetry','','[]','入海浮生汗漫秋，紫皇高宴五雲樓。',32,'全唐诗/poet.song.1000.json','["入海浮生汗漫秋，紫皇高宴五雲樓。", "霓裳曲罷天風起，吹散仙香滿十洲。"]'),
('16aa6b42-f1d2-4883-bf57-0cbc8d29eecb','上清辭五首  其二','李九齡','宋','宋诗','song-poetry','','[]','樓鎖彤霞地絕塵，碧桃花發九天春。',32,'全唐诗/poet.song.1000.json','["樓鎖彤霞地絕塵，碧桃花發九天春。", "東皇近日慵遊宴，閒煞瑶池五色麟。"]'),
('b8623087-2136-42c8-be2b-22bc9251da36','上清辭五首  其三','李九齡','宋','宋诗','song-poetry','','[]','上清仙路有丹梯，影響行人到即迷。',32,'全唐诗/poet.song.1000.json','["上清仙路有丹梯，影響行人到即迷。", "不會無端箇漁父，阿誰教入武陵溪。"]'),
('94aa8cad-b9b5-4171-85af-1b6f9bb734eb','上清辭五首  其四','李九齡','宋','宋诗','song-poetry','','[]','本來方朔是真仙，偶別丹臺未得還。',32,'全唐诗/poet.song.1000.json','["本來方朔是真仙，偶別丹臺未得還。", "何事玉皇消息晚，忍教憔悴向人間。"]'),
('d29c6f31-ec09-4cf0-b7c4-801b56d7e472','上清辭五首  其五','李九齡','宋','宋诗','song-poetry','','[]','新拜天官上玉都，紫皇親授五靈符。',32,'全唐诗/poet.song.1000.json','["新拜天官上玉都，紫皇親授五靈符。", "羣仙箇箇來相問，人世風光似此無。"]'),
('0338e2f3-e364-458b-923a-dfebd976f111','讀三國志','李九齡','宋','宋诗','song-poetry','','[]','有國由來在得賢，莫言興廢是循環。',32,'全唐诗/poet.song.1000.json','["有國由來在得賢，莫言興廢是循環。", "武侯星落周瑜死，平蜀降吳似等閒。"]'),
('483b4d84-70f9-42ed-83c6-1b420f5d9425','山舍南溪小桃花','李九齡','宋','宋诗','song-poetry','','[]','一樹繁英奪眼紅，開時先合占東風。',32,'全唐诗/poet.song.1000.json','["一樹繁英奪眼紅，開時先合占東風。", "可憐地僻無人賞，拋擲深山亂木中。"]'),
('089395a2-a0bb-4c33-a97f-cf5c8747ceaf','春行遇雨','李九齡','宋','宋诗','song-poetry','','[]','夾路輕風撼柳條，雨侵春態動無憀。',32,'全唐诗/poet.song.1000.json','["夾路輕風撼柳條，雨侵春態動無憀。", "採香陌上誰家女，濕損釵頭翡翠翹。"]'),
('e7f750ab-7a19-481f-8ad8-3a9c960c6ee0','登樓寄遠','李九齡','宋','宋诗','song-poetry','','[]','滿城春色花如雪，極目烟光月似鉤。',32,'全唐诗/poet.song.1000.json','["滿城春色花如雪，極目烟光月似鉤。", "總是動人鄉思處，更堪容易上高樓。"]'),
('6209a594-4086-47c6-958a-0928693615e1','望思臺','李九齡','宋','宋诗','song-poetry','','[]','漢武年高慢帝圖，任人曾不問賢愚。',32,'全唐诗/poet.song.1000.json','["漢武年高慢帝圖，任人曾不問賢愚。", "直饒四老依前出，消得江充寵佞無。"]'),
('3508cb25-d6dd-4347-aa38-1d43219427ca','山舍偶題','李九齡','宋','宋诗','song-poetry','','[]','門掩松蘿一逕深，偶携藜杖出前林。',32,'全唐诗/poet.song.1000.json','["門掩松蘿一逕深，偶携藜杖出前林。", "誰知盡日看山坐，萬古興亡總在心。"]'),
('b827ee52-b40f-457d-b97d-4797d4646b0e','荆溪夜泊','李九齡','宋','宋诗','song-poetry','','[]','點點漁燈照浪清，水烟疏碧月朧明。',32,'全唐诗/poet.song.1000.json','["點點漁燈照浪清，水烟疏碧月朧明。", "小灘驚起鴛鴦處，一隻採蓮船過聲。"]'),
('b689cbb5-97ac-44fa-b531-45c21e45f838','旅舍卧病','李九齡','宋','宋诗','song-poetry','','[]','家隔西秦無遠信，身隨東洛度流年。',32,'全唐诗/poet.song.1000.json','["家隔西秦無遠信，身隨東洛度流年。", "病來旅館誰相問，牢落閒庭一樹蟬。"]'),
('ab1c6ef3-8b3d-4121-bea5-4023ff0fccc7','登昭福寺樓','李九齡','宋','宋诗','song-poetry','','[]','旅懷秋興正無涯，獨倚危樓四望賒。',32,'全唐诗/poet.song.1000.json','["旅懷秋興正無涯，獨倚危樓四望賒。", "谷變陵遷何處問，滿川空有舊烟霞。"]'),
('a9c49ddb-c2a2-4601-8a03-8e616e2c490f','代邊將','李九齡','宋','宋诗','song-poetry','','[]','雪凍陰河半夜風，戰回狂寇血漂紅。',32,'全唐诗/poet.song.1000.json','["雪凍陰河半夜風，戰回狂寇血漂紅。", "據鞍遥指長安路，須刻麟臺第一功。"]'),
('24573c28-2599-426d-9c60-1e8882bf4045','夜與張舒話別','李九齡','宋','宋诗','song-poetry','','[]','愁聽南樓角又吹，曉雞啼後更分離。',32,'全唐诗/poet.song.1000.json','["愁聽南樓角又吹，曉雞啼後更分離。", "如何銷得淒涼思，更勸燈前酒一巵。"]'),
('83bbde32-f71b-4718-8e99-8d3b75f4cccc','寒梅詞','李九齡','宋','宋诗','song-poetry','','[]','霜梅先拆嶺頭枝，萬卉千花凍不知。',32,'全唐诗/poet.song.1000.json','["霜梅先拆嶺頭枝，萬卉千花凍不知。", "留得和羹滋味在，任他風雪苦相欺。"]'),
('6671e4ba-ee59-49e0-bfd4-8e28881c9b6a','題靈泉寺','李九齡','宋','宋诗','song-poetry','','[]','入谷先生一陣香，異花奇木簇禪堂。',32,'全唐诗/poet.song.1000.json','["入谷先生一陣香，異花奇木簇禪堂。", "可憐門外高低路，萬轂千蹄日日忙。"]'),
('723e1605-6524-44bb-9950-642f2f547cc5','宿張正字別業','李九齡','宋','宋诗','song-poetry','','[]','茅屋蕭寥烟暗後，松窗寂歷月明初。',32,'全唐诗/poet.song.1000.json','["茅屋蕭寥烟暗後，松窗寂歷月明初。", "此時誰念孤吟客，唯有黄公一帙書。"]'),
('b0975dd3-1b24-403e-b7fb-8a799d8cb6f4','鶴','李九齡','宋','宋诗','song-poetry','','[]','天上瑶池覆五雲，玉麟金鳳好爲羣。',32,'全唐诗/poet.song.1000.json','["天上瑶池覆五雲，玉麟金鳳好爲羣。", "不須更飲人間水，直是清流也汙君。"]'),
('2f292369-a4e5-4d07-a539-f96408651c66','過相思谷','李九齡','宋','宋诗','song-poetry','','[]','悠悠信馬春山曲，芳草和烟鋪嫩綠。',32,'全唐诗/poet.song.1000.json','["悠悠信馬春山曲，芳草和烟鋪嫩綠。", "正被離愁著莫人，那堪更過相思谷。"]'),
('08943726-a202-4c22-baed-08f2c8b23a10','寫莊子','李九齡','宋','宋诗','song-poetry','','[]','聖澤安排當散地，賢侯優貸借新居。',32,'全唐诗/poet.song.1000.json','["聖澤安排當散地，賢侯優貸借新居。", "閒中亦有閒生計，寫得南華一部書。"]'),
('ac6fbde0-81d5-4e80-ab89-7bcba33e18ed','山中寄友人','李九齡','宋','宋诗','song-poetry','','[]','亂雲堆裏結茅廬，已共紅塵跡漸疏。',32,'全唐诗/poet.song.1000.json','["亂雲堆裏結茅廬，已共紅塵跡漸疏。", "莫問野人生計事，窗前流水枕前書。"]'),
('903eacba-847f-4824-b6cb-93a333790805','透明巖','李九齡','宋','宋诗','song-poetry','','[]','乍脫塵埃夢寐安，透明巖上一開顔。',48,'全唐诗/poet.song.1000.json','["乍脫塵埃夢寐安，透明巖上一開顔。", "晚霞雙處似聞雁，遠目盡時猶有山。", "仙跡不隨巖桂老，禪心長共嶺雲閑。"]'),
('7426b4db-d2b0-47d2-9b14-b7f981f1c5c6','贈馬道士','李九齡','宋','宋诗','song-poetry','','["\u534e\u5c71"]','水共逍遥雲共孤，混時言笑只佯愚。',64,'全唐诗/poet.song.1000.json','["水共逍遥雲共孤，混時言笑只佯愚。", "經年但醉宜城酒，千里惟擔華嶽圖。", "尋野鶴來空碧洞，覓琴僧去渡重湖。", "人間再見知何日，乞取先生石轆轤。"]'),
('45793517-db6f-43c8-86f0-f89908cdf9d9','贈譚先生','李九齡','宋','宋诗','song-poetry','','[]','古觀重重遶翠微，杉松深處掩雙扉。',64,'全唐诗/poet.song.1000.json','["古觀重重遶翠微，杉松深處掩雙扉。", "雲生萬壑投龍去，海隔三山放鶴歸。", "花洞宴遊春日永，石壇朝禮曙星稀。", "每聽高論長生理，擬向寰中便拂衣。"]'),
('bbc927bb-f384-44fa-9527-f43ff6f4924f','送王德明樞密之代州','郭守文','宋','宋诗','song-poetry','','[]','憐君千里別，新馬黑貂裘。',48,'全唐诗/poet.song.1000.json','["憐君千里別，新馬黑貂裘。", "白首辭鄉淚，黄雲入塞愁。", "月明沙磧夜，霜落雁門秋。", "去去燕然上，功名會見收。"]'),
('f15bb7e8-15d4-42d1-a125-41e166d4e54b','初春行宮侍宴','郭守文','宋','宋诗','song-poetry','','[]','青山園遠嶂，流水瀉鳴弦。',48,'全唐诗/poet.song.1000.json','["青山園遠嶂，流水瀉鳴弦。", "游豫王正月，謳歌帝萬年。", "草香吹輦路，鳥弄雜宮懸。", "霑醉堯尊酒，何由報所天。"]'),
('b5813eef-e5a1-4284-904e-7ad23da3c60b','贈李公','呂端','宋','宋诗','song-poetry','','[]','憶昔僦居明德坊，官資俱是校書郎。',64,'全唐诗/poet.song.1000.json','["憶昔僦居明德坊，官資俱是校書郎。", "青衫共直昭文館，白首同登政事堂。", "佐國廟謨君已展，避賢榮路我猶妨。", "主恩至重何時報，老眼相看淚兩行。"]'),
('fa9a847a-c350-47a8-9dd7-75bee15fd663','送英公大師歸終南','呂端','宋','宋诗','song-poetry','','[]','衡岳烟蘿紫閣雲，名高湖外晚遊秦。',64,'全唐诗/poet.song.1000.json','["衡岳烟蘿紫閣雲，名高湖外晚遊秦。", "清詞古學儒生業，圓笠方袍釋子身。", "竹杖拄歸山裏寺，篆書留與世間人。", "我疑簪組成爲縛，空仰吾師去路塵。"]'),
('9fb41897-212e-4444-abee-918429feb43b','句','呂端','宋','宋诗','song-poetry','','[]','愚臣鈎直難堪用，宜用濠梁結網人。',16,'全唐诗/poet.song.1000.json','["愚臣鈎直難堪用，宜用濠梁結網人。"]'),
('45debab2-dca4-4191-abf1-38d40b1e11cb','贈英公大師','釋永牙','宋','宋诗','song-poetry','','[]','吾宗何事獨稱雄，今昔名高繼古風。',64,'全唐诗/poet.song.1000.json','["吾宗何事獨稱雄，今昔名高繼古風。", "王右軍書傳智永，李陽冰篆付英公。", "墨研天電煤疑絕，硯琢端溪石欲空。", "珍重真蹤千載後，誰來三日看無窮。"]'),
('1cd280e6-404b-46a7-bda9-51ef3cda84bd','贈英公大師','釋玄寶','宋','宋诗','song-poetry','','[]','□愛王家草聖蹤，獨於小篆苦留功。',32,'全唐诗/poet.song.1000.json','["□愛王家草聖蹤，獨於小篆苦留功。", "何人會得師高意，欲把時風變古風。"]'),
('6430d475-4f68-436e-9428-330c31aa8ddb','奉次文爵兄韻','郭贄','宋','宋诗','song-poetry','','[]','京國相逢意盡傾，不須池草夢中生。',64,'全唐诗/poet.song.1000.json','["京國相逢意盡傾，不須池草夢中生。", "細將兩地行藏語，消盡幾番長短更。", "籬外黄花香共嗅，案頭易傳手中評。", "慚予才竭難爲弟，況復輸兄獨秀名。"]'),
('d1a36011-b20e-4371-b72c-ae6341f97090','寄劉延叟','郭贄','宋','宋诗','song-poetry','','[]','弱齡志登涉，壯即遠行遊。',72,'全唐诗/poet.song.1000.json','["弱齡志登涉，壯即遠行遊。", "名山忍偏歷，書劍多遲留。", "我思在錦水，木落巴山秋。", "願隨蛾眉月，影入平羌流。", "孤飛何處鶴，清唳寒雲愁。", "賞心隔歡愛，悵望烟巒稠。"]'),
('78d29449-baad-4733-9650-d5a151a0cc94','句','郭贄','宋','宋诗','song-poetry','','[]','高低草木芽爭發，多少龍蛇眼未開。',16,'全唐诗/poet.song.1000.json','["高低草木芽爭發，多少龍蛇眼未開。"]'),
('0cb2089c-d2b5-4eef-bb2e-17b026de8808','詠華林書院','黄夷簡','宋','宋诗','song-poetry','','[]','桐軒瀟灑遠塵機，伯始英風世不衰。',128,'全唐诗/poet.song.1000.json','["桐軒瀟灑遠塵機，伯始英風世不衰。", "千畝自封輕渭叟，五經同拜重宣尼。", "衣無常主門多義，倉有餘糧俗共熙。", "仁智眼前從所樂，利名身外更何思。", "琴清善召雲中鶴，床穩高蓍葉上龜。", "茶煮玉泉僧至日，酒蒭金蟻菊芳時。", "往來虛席賓朋盛，朝暮過堂子弟奇。", "萬卷詩書歸腹篋，地仙蹤跡少人知。"]'),
('fae4afdc-b9ac-4e02-9624-a98cb89dd32d','句  其一','黄夷簡','宋','宋诗','song-poetry','','[]','宿雨一番蔬甲嫩，春山幾焙茗旗香。',16,'全唐诗/poet.song.1000.json','["宿雨一番蔬甲嫩，春山幾焙茗旗香。"]'),
('57f15bb5-26dd-46c4-8849-faabd2903fc0','句  其二','黄夷簡','宋','宋诗','song-poetry','','[]','襟带巴連蜀，封疆楚接吳。',12,'全唐诗/poet.song.1000.json','["襟带巴連蜀，封疆楚接吳。"]'),
('dba70504-fb3d-421b-8209-54c988ebce50','寄宣義大師英公','范杲','宋','宋诗','song-poetry','','[]','西遊久不得師書，睹物相思展篆圖。',64,'全唐诗/poet.song.1000.json','["西遊久不得師書，睹物相思展篆圖。", "情厚未忘蓮社約，分深曾伴橘洲居。", "青雲作陣宜長卧，白酒資吟莫破除。", "見說近來揮彩筆，字皆飛動有功夫。"]'),
('f013a6f9-28d7-41a7-8c65-2777b1745b87','句','范杲','宋','宋诗','song-poetry','','[]','千里版圖來浙右，一聲金鼓下河東。',16,'全唐诗/poet.song.1000.json','["千里版圖來浙右，一聲金鼓下河東。"]'),
('eaa89632-9fc8-4499-aa43-47da8559a02b','遊南雁蕩','范旻','宋','宋诗','song-poetry','','[]','塵勞最是愛山居，借得丹臺半日餘。',64,'全唐诗/poet.song.1000.json','["塵勞最是愛山居，借得丹臺半日餘。", "黄雪糝來松徑滿，白雲飛去洞門虛。", "掃苔有客題詩句，滴露無人校道書。", "何日結巢依石室，早從湖海賦歸歟。"]'),
('7dfa44d4-8964-4422-87b3-5dc4676b0d26','秋夜坐','釋遇臻','宋','宋诗','song-poetry','','[]','秋庭肅肅風颾颾，寒星列空蟾魄高。',32,'全唐诗/poet.song.1000.json','["秋庭肅肅風颾颾，寒星列空蟾魄高。", "搘頤靜坐神不勞，鳥窠無端吹布毛。"]'),
('dc3109fd-1b66-4221-bd61-e30cdab79199','贈宣義大師英公','師頏','宋','宋诗','song-poetry','','[]','禪得玄機筆得精，孤雲光彩甚分明。',64,'全唐诗/poet.song.1000.json','["禪得玄機筆得精，孤雲光彩甚分明。", "毫端落紙堪爲寶，海內無人不重名。", "山約終歸雙履在，髭因凉剃一刀輕。", "何妨換取羣鵝了，却與迷徒指化城。"]'),
('4c477bbd-6adf-4763-8c89-c31920472350','辭衆偈','釋雲豁','宋','宋诗','song-poetry','','[]','天不高，地不厚，自是時人覷不透。',32,'全唐诗/poet.song.1000.json','["天不高，地不厚，自是時人覷不透。", "但看臘月二十五，依舊面南看北斗。"]'),
('f8ce4d46-6fb2-4d3b-b823-b94cc5ef9995','三句頌 函蓋乾坤','道禪師','宋','宋诗','song-poetry','','[]','乾坤並萬象，地獄及天堂。',24,'全唐诗/poet.song.1000.json','["乾坤並萬象，地獄及天堂。", "物物皆真見，頭頭用不傷。"]'),
('2f2746bf-ff67-4560-995d-675be38211a4','三句頌 截斷衆流','道禪師','宋','宋诗','song-poetry','','[]','堆山積嶽來，一一盡塵埃。',24,'全唐诗/poet.song.1000.json','["堆山積嶽來，一一盡塵埃。", "更擬論玄妙，冰消解瓦摧。"]'),
('39562755-5249-4f5f-b19a-323ab8590c3d','三句頌 隨波逐浪','道禪師','宋','宋诗','song-poetry','','[]','辯口利舌問，高低總不虧。',24,'全唐诗/poet.song.1000.json','["辯口利舌問，高低總不虧。", "還知應病藥，診候在臨時。"]'),
('26873b03-2b38-4f38-a100-70f802c32280','三句外','道禪師','宋','宋诗','song-poetry','','["\u8861\u5c71"]','當人如舉唱，三句豈能該。',24,'全唐诗/poet.song.1000.json','["當人如舉唱，三句豈能該。", "有問如何事，南嶽與天台。"]'),
('9588e9aa-eb07-4b00-a701-3444cdfd1716','擡薦商量','道禪師','宋','宋诗','song-poetry','','[]','相見不揚眉，君東我亦西。',24,'全唐诗/poet.song.1000.json','["相見不揚眉，君東我亦西。", "紅霞穿碧落，白日繞須彌。"]'),
('e7d55a80-af2c-4958-8f18-011a9718dd10','西來意頌','釋靈澄','宋','宋诗','song-poetry','','[]','因僧問我西來意，我話居山七八年。',64,'全唐诗/poet.song.1000.json','["因僧問我西來意，我話居山七八年。", "草履只栽三箇耳，麻衣曾補兩番肩。", "東庵每見西庵雪，下澗長流上澗泉。", "半夜白雲消散後，一輪明月到床前。"]'),
('5e9bed9c-900e-47fb-b6d6-a69826aa50b0','頌','釋智同','宋','宋诗','song-poetry','','[]','雲門透法身，法身何許人。',24,'全唐诗/poet.song.1000.json','["雲門透法身，法身何許人。", "雁回沙塞北，鸚鵡慕西秦。"]'),
('f71b3085-bbcf-417f-822d-65c4df84d4eb','偈','釋光祚','宋','宋诗','song-poetry','','[]','東家李四婆，西家來乞火。',60,'全唐诗/poet.song.1000.json','["東家李四婆，西家來乞火。", "門外立少時，嗔他停滯我。", "惡發走歸家，虛心屋裏坐。", "可憐羣小兒，終日受饑餓。", "有眼不點睛，空鎖髑髏破。"]'),
('4ec8e314-34fe-45b4-b70c-8a01c464cf0f','呈洞山初禪師','釋良雅','宋','宋诗','song-poetry','','[]','五彩畫牛頭，黄金爲點額。',36,'全唐诗/poet.song.1000.json','["五彩畫牛頭，黄金爲點額。", "春晴二月初，農人皆取則。", "寒食賀新正，鐵錢三五百。"]'),
('0dfb3a85-abe8-449d-855e-ffa6f5ffecb1','偈','釋宗盛','宋','宋诗','song-poetry','','[]','鐘聲清，鼓聲響，早晚相聞休妄想。',32,'全唐诗/poet.song.1000.json','["鐘聲清，鼓聲響，早晚相聞休妄想。", "薦得徒勞別問津，莫道山僧無伎倆。"]'),
('1b3a6c0e-6293-4a73-b188-91ebb5ae0049','示僧','釋慧遠','宋','宋诗','song-poetry','','[]','兩箇童兒舁木鼓，左邊打了右邊舞。',32,'全唐诗/poet.song.1000.json','["兩箇童兒舁木鼓，左邊打了右邊舞。", "剎那變現百千般，分明示君君記取。"]'),
('8f77e662-a067-4a27-9771-7566cfe7c0e6','頌','釋慧遠','宋','宋诗','song-poetry','','[]','雪霽長空，迥野飛鴻。',20,'全唐诗/poet.song.1000.json','["雪霽長空，迥野飛鴻。", "段雲片片，向西向東。"]'),
('1646db0e-52a0-4bf1-91df-3491c2ce0131','呈大德禪師','尹輔','宋','宋诗','song-poetry','','[]','支遁行藏惠遠才，幾年嵩少避浮埃。',64,'全唐诗/poet.song.1000.json','["支遁行藏惠遠才，幾年嵩少避浮埃。", "八行丹詔雲間落，一對紫衣天上來。", "誦律夜窗寒月皎，閉門秋渚白蓮開。", "名高自達帝王聽，就降殊恩不假媒。"]'),
('7b272b0d-2b16-45dc-bf83-ae8583ebe8f6','宮詞  其一','宋白','宋','宋诗','song-poetry','','[]','千官朝謁五門前，一路春風蠟燭烟。',32,'全唐诗/poet.song.1000.json','["千官朝謁五門前，一路春風蠟燭烟。", "宮漏乍停班已定，紫雲開處望堯天。"]'),
('cbf5ac7a-cfa9-4360-8d08-f30b78319121','宮詞  其二','宋白','宋','宋诗','song-poetry','','[]','萬國車書一太平，宮花無數管弦聲。',32,'全唐诗/poet.song.1000.json','["萬國車書一太平，宮花無數管弦聲。", "近臣入奏新祥瑞，昨夜黄河徹底清。"]'),
('5dfd365c-faee-41d7-801c-d010da54a061','宮詞  其三','宋白','宋','宋诗','song-poetry','','[]','律管飛灰報早春，壽陽梅淡落香裀。',32,'全唐诗/poet.song.1000.json','["律管飛灰報早春，壽陽梅淡落香裀。", "詞人競進新詩入，俊思無過白舍人。"]'),
('4a873131-9408-4ab6-9dec-d379f7b27a96','宮詞  其四','宋白','宋','宋诗','song-poetry','','[]','十二樓前御柳垂，九重城裏百花時。',32,'全唐诗/poet.song.1000.json','["十二樓前御柳垂，九重城裏百花時。", "宣州恰進紅絲毯，便遣宮娥舞柘枝。"]'),
('91693906-53cb-4d69-837c-5cc4a5619c08','宮詞  其五','宋白','宋','宋诗','song-poetry','','[]','彤廷立仗雪初銷，仙樂空懸讌百寮。',32,'全唐诗/poet.song.1000.json','["彤廷立仗雪初銷，仙樂空懸讌百寮。", "齊指終南稱萬壽，遠平香案碧岧嶢。"]'),
('2f252abf-1ab5-4fc9-91cc-c74027866f24','宮詞  其六','宋白','宋','宋诗','song-poetry','','[]','樓前宣赦掣金雞，大禮新成彩仗歸。',32,'全唐诗/poet.song.1000.json','["樓前宣赦掣金雞，大禮新成彩仗歸。", "萬歲聲高天地喜，慶雲飛上衮龍衣。"]'),
