('ad43ec89-1ca7-4e2e-a92e-393cad2609e0','宮詞  其九七','宋白','宋','宋诗','song-poetry','','[]','繡額珠簾窣地重，微風吹動牡丹枝。',32,'全唐诗/poet.song.1000.json','["繡額珠簾窣地重，微風吹動牡丹枝。", "金籠鸚鵡耽春睡，忘却新教御製詩。"]'),
('f4746ac6-f0f3-4658-9b83-5fe381e81cf8','宮詞  其九八','宋白','宋','宋诗','song-poetry','','[]','便殿沉沉永巷秋，宮中擊拂最風流。',32,'全唐诗/poet.song.1000.json','["便殿沉沉永巷秋，宮中擊拂最風流。", "參差玉指和花數，恰到君王自得頭。"]'),
('ee9ad967-e37a-459b-a059-e5e347413325','宮詞  其九九','宋白','宋','宋诗','song-poetry','','[]','宮棋初罷請銀笙，合曲偏宜鈿面箏。',32,'全唐诗/poet.song.1000.json','["宮棋初罷請銀笙，合曲偏宜鈿面箏。", "未伏延年花下唱，金錢百萬賞新聲。"]'),
('5570178c-05ef-4b50-b6b9-05d818cf1040','宮詞  其一○○','宋白','宋','宋诗','song-poetry','','[]','春營小殿號披香，宣借天孫作學堂。',32,'全唐诗/poet.song.1000.json','["春營小殿號披香，宣借天孫作學堂。", "李白宮詞多好句，側書紅壁兩三行。"]'),
('efee370a-0172-46ba-a0b8-2a57546fd978','嘉州','宋白','宋','宋诗','song-poetry','','[]','嘉陽信美郡，風物眷多奇。',24,'全唐诗/poet.song.1000.json','["嘉陽信美郡，風物眷多奇。", "有湖題明月，有樓名荔枝。"]'),
('198561a6-8599-479a-b982-32a23870683b','普賢寺','宋白','宋','宋诗','song-poetry','','[]','菩薩悲深居此地，峨眉名重鎮南州。',32,'全唐诗/poet.song.1000.json','["菩薩悲深居此地，峨眉名重鎮南州。", "不知立處高多少，只見星辰在下頭。"]'),
('838e2175-9d3e-4ca0-a8a8-19d4b9c9d716','七夕','宋白','宋','宋诗','song-poetry','','[]','纖吹浮雲薦，非因散巧樓。',24,'全唐诗/poet.song.1000.json','["纖吹浮雲薦，非因散巧樓。", "靈儔不可覿，仙溪泛悠悠。"]'),
('c2987b92-415e-4a9e-80b5-cccccae61ebb','中秋感懷  其一','宋白','宋','宋诗','song-poetry','','[]','去年今夜此堂前，人正清歌月正圓。',32,'全唐诗/poet.song.1000.json','["去年今夜此堂前，人正清歌月正圓。", "今夜秋來人且散，不如雲霧蔽青天。"]'),
('05eac997-669a-41e0-b538-6b826a90e1fb','中秋感懷  其二','宋白','宋','宋诗','song-poetry','','[]','雲彩冰光似去年，去年人月兩嬋娟。',32,'全唐诗/poet.song.1000.json','["雲彩冰光似去年，去年人月兩嬋娟。", "今宵不辨連明坐，拚醉抽身黑處眠。"]'),
('b595aeae-84fa-45e2-961c-4ff17f8d2abc','九日  其一','宋白','宋','宋诗','song-poetry','','[]','霜冷風清九月九，茱萸黄菊家園有。',32,'全唐诗/poet.song.1000.json','["霜冷風清九月九，茱萸黄菊家園有。", "何時玉殿接千官，稱觴共進南山壽。"]'),
('b969b38d-edd6-45f0-8f02-facb02074408','九日  其二','宋白','宋','宋诗','song-poetry','','[]','陶家籬落菊花開，醉擬西風立釣臺。',32,'全唐诗/poet.song.1000.json','["陶家籬落菊花開，醉擬西風立釣臺。", "一座良交皆不見，數聲燕雁戛雲來。"]'),
('8c83ad34-2be0-4149-a50b-e149301e777d','九日  其三','宋白','宋','宋诗','song-poetry','','[]','秋色蕭蕭野水邊，茱萸時節菊花天。',32,'全唐诗/poet.song.1000.json','["秋色蕭蕭野水邊，茱萸時節菊花天。", "明時未達青雲晚，惆悵登高又一年。"]'),
('d0d6cf5f-87b1-4e95-9e46-0f0879505e08','贈麻仲英','宋白','宋','宋诗','song-poetry','','[]','宣毫歙墨川箋紙，寄與麻家小秀才。',32,'全唐诗/poet.song.1000.json','["宣毫歙墨川箋紙，寄與麻家小秀才。", "七歲能吟天骨異，前生應折桂枝來。"]'),
('68836cc8-328b-4d1f-8a35-dd6418fb524f','中酒','宋白','宋','宋诗','song-poetry','','[]','中酒事俱妨，偷眠就黑房。',48,'全唐诗/poet.song.1000.json','["中酒事俱妨，偷眠就黑房。", "靜嫌鸚鵡鬧，渴憶荔枝香。", "病與慵相續，心和夢尚狂。", "從今改題品，不號醉爲鄉。"]'),
('e408f9ea-7abd-434a-8606-d393b553d0b2','雲','宋白','宋','宋诗','song-poetry','','[]','化作奇形隨物態，散成文錦自天機。',64,'全唐诗/poet.song.1000.json','["化作奇形隨物態，散成文錦自天機。", "紅堆遠嶠日初上，碧滿長空人未歸。", "逸興狂來連海闊，高情間甚出山飛。", "須知深處藏雷雨，不獨江邊遶釣磯。"]'),
('ba976d7f-6f35-4efd-81b6-617f0371138c','一春','宋白','宋','宋诗','song-poetry','','[]','一春情調淡悠悠，閒倚書窗背小樓。',64,'全唐诗/poet.song.1000.json','["一春情調淡悠悠，閒倚書窗背小樓。", "暖日只添中酒睡，晚風頻動惜花愁。", "鶑衝舞蝶侵人過，絮逐天絲觸處遊。", "已爲韶光發惆悵，可堪家近白蘋洲。"]'),
('797b1af0-9455-4cca-9a23-eaa3679ee1fd','春','宋白','宋','宋诗','song-poetry','','[]','隔岸黄鸝語，當軒白鳥斜。',24,'全唐诗/poet.song.1000.json','["隔岸黄鸝語，當軒白鳥斜。", "晚來風緊處，飛絮滿人家。"]'),
('5b4a5794-b0e6-4d55-a40d-7cf06f9123dc','花','宋白','宋','宋诗','song-poetry','','[]','誰將枝葉染還裁，却使馨香次第來。',64,'全唐诗/poet.song.1000.json','["誰將枝葉染還裁，却使馨香次第來。", "春柄定教三月主，天心合與一齊開。", "如何零露方滋菊，豈得東風不爲梅。", "低蹙艷容愁似語，也疑由命不由才。"]'),
('20b27397-40f2-4428-a8bd-3674d269c3ef','惜別詩','宋白','宋','宋诗','song-poetry','','[]','年來又惜別清塵，故國榮過喜風新。',64,'全唐诗/poet.song.1000.json','["年來又惜別清塵，故國榮過喜風新。", "竹葉莫辭千日酒，梅花惟寄一枝春。", "苦心曾未拋黄卷，得路終期近紫宸。", "不待政成迎風詔，頌聲洋溢桂州人。"]'),
('7de9b237-b552-4ced-8183-12ced4ec138f','寄蔡崑','宋白','宋','宋诗','song-poetry','','[]','却憶醉相逢，雲深太白東。',48,'全唐诗/poet.song.1000.json','["却憶醉相逢，雲深太白東。", "離別經臘雪，魂夢又春風。", "芳草晴天闊，黄鸝細雨中。", "倚筇愁望處，烟樹遠濛籠。"]'),
('8fc5a4a0-3f66-4625-a63b-a4ff542b0708','黄陵二妃廟','宋白','宋','宋诗','song-poetry','','[]','重瞳天子狩南荒，二女音容已渺茫。',64,'全唐诗/poet.song.1000.json','["重瞳天子狩南荒，二女音容已渺茫。", "靜聽瑶琴當皓月，再聞珠淚灑幽篁。", "松愁老鶴清無夢，水映疏螢冷放光。", "一夜遼遼千古意，香魂依約遶瀟湘。"]'),
('cbfb152d-a2c0-4fff-af3e-0e4f9cecdd49','送陳堯叟赴廣西漕','宋白','宋','宋诗','song-poetry','','[]','莫辭征騎去迢迢，盡瀉純誠許聖朝。',64,'全唐诗/poet.song.1000.json','["莫辭征騎去迢迢，盡瀉純誠許聖朝。", "北闕皇恩從此布，南方沴氣必然銷。", "爲詩自可怡情性，服藥嘗聞助攝調。", "仙館粉闈官職好，定期騫翥上烟霄。"]'),
('407d52af-352c-4435-b8ed-4bce7c2b84e5','狂吟八韻送英公暫歸故鄉遷殯二親','宋白','宋','宋诗','song-poetry','','[]','十八般書四海傳，長安話別已多年。',128,'全唐诗/poet.song.1000.json','["十八般書四海傳，長安話別已多年。", "今來帝里重相見，轉覺師心更自然。", "下筆入神皆得法，出言成句盡通玄。", "花時乘興先行樂，月夜忘機靜坐禪。", "到處僧俗爭識面，滿朝英俊贈佳篇。", "長沙母葬彰純孝，八水人思有善緣。", "衡嶽醉投秋雨寺，漢江吟渡夕陽舡。", "前期指在春三月，迴首東風好著鞭。"]'),
('7e630ba9-e43c-45ed-ab6a-97f853a9cbd9','牡丹詩十首  其一','宋白','宋','宋诗','song-poetry','','[]','□應春處即□春，粉面□相□番新。',64,'全唐诗/poet.song.1000.json','["□應春處即□春，粉面□相□番新。", "語得必傳天上事，摘來真是掌中身。", "百花推戴教爲主，□日妖□欲□人。", "無可奈何□愛惜，少偷金蘂咽芳津。"]'),
('fb6a77d6-a830-4bf5-b58b-b0759066026a','牡丹詩十首  其二','宋白','宋','宋诗','song-poetry','','[]','日華鮮麗露華濃，梳流香朝競□容。',64,'全唐诗/poet.song.1000.json','["日華鮮麗露華濃，梳流香朝競□容。", "來在夢中甘化蝶，入伊心裏不如蜂。", "宮娥捧擁西施醉，天樂喧闐虢國風。", "高拗浮□須繼燭，玳簪分載酒千鍾。"]'),
('d03cd518-9bf6-47de-ab8f-9b1c7baec3b9','牡丹詩十首  其三','宋白','宋','宋诗','song-poetry','','[]','春心相惜最相親，湘葉忩忩換翠裙。',64,'全唐诗/poet.song.1000.json','["春心相惜最相親，湘葉忩忩換翠裙。", "雙蒂喜如嬪二女，一枝愁似寡文君。", "艷繁誰卷真珠看，香好曾歌琥珀聞。", "深染鮫綃籠玉檻，莫教飛去作卿雲。"]'),
('f330e21a-78b6-44fd-85e2-e3211d9890f7','牡丹詩十首  其四','宋白','宋','宋诗','song-poetry','','[]','烟容粉態傍歌樓，半似窺人半似羞。',64,'全唐诗/poet.song.1000.json','["烟容粉態傍歌樓，半似窺人半似羞。", "把筆乍題先巧笑，憑欄微喚不迴頭。", "吹乾玉笛香猶在，槌破靈鼉愛未休。", "更得黄鸝將粉蝶，東西南北說風流。"]'),
('288be20f-7186-444a-9cba-552ee30bb4f8','牡丹詩十首  其五','宋白','宋','宋诗','song-poetry','','[]','澹黄容止間深檀，妥媠香紅露未乾。',64,'全唐诗/poet.song.1000.json','["澹黄容止間深檀，妥媠香紅露未乾。", "和淚似嫌春漸老，向人如說夜來寒。", "粧成有樣教天媛，禮絕無心下國蘭。", "針繡筆描俱未是，好風相倚笑邊鸞。"]'),
('ec4b8ceb-5e64-4132-bd1a-5308b0bd72be','牡丹詩十首  其六','宋白','宋','宋诗','song-poetry','','[]','錦爲行障繡爲衾，不殺猩猩色已深。',64,'全唐诗/poet.song.1000.json','["錦爲行障繡爲衾，不殺猩猩色已深。", "花譜揚名居一品，藥欄纔見賞千金。", "誰忘正爲褰珠箔，得意惟能挑玉琴。", "洛水橋南三月裏，兩無言語各知心。"]'),
('aa95d2c0-1206-4469-86b0-27b654d4a20a','牡丹詩十首  其七','宋白','宋','宋诗','song-poetry','','[]','風排香陣拂瑶墀，御苑新晴爛漫時。',64,'全唐诗/poet.song.1000.json','["風排香陣拂瑶墀，御苑新晴爛漫時。", "十五素娥羞水色，三千紅面洗胭脂。", "宮腰暎酒思輕舞，檀口偎牋欲詠詩。", "鐵石心腸爲君變，多情多恨一枝枝。"]'),
('df62e1ea-7f2d-40a4-b070-aa38eaaa502b','牡丹詩十首  其八','宋白','宋','宋诗','song-poetry','','[]','水精冠葉鏤春冰，巧思鎸研仿未能。',64,'全唐诗/poet.song.1000.json','["水精冠葉鏤春冰，巧思鎸研仿未能。", "風砑紅綃光點血，暖銷金鏤細含稜。", "韶容旖旎終無比，晚艷低佪更可憎。", "戲脫仙衣親手覆，香身柔軟力難勝。"]'),
('ac5af077-f1f9-4d15-a9ca-7f00346a10e1','牡丹詩十首  其九','宋白','宋','宋诗','song-poetry','','[]','春風平地謫花仙，紅裊生香下九天。',64,'全唐诗/poet.song.1000.json','["春風平地謫花仙，紅裊生香下九天。", "艷欲背身垂玉筯，動如移步索金蓮。", "含情待去爲雲雨，忍笑佯來聽管弦。", "朧月輕寒應不慣，夜深渾擬傍藂眠。"]'),
('88c50ed5-5445-43bb-8d40-cfabdcab908b','牡丹詩十首  其一○','宋白','宋','宋诗','song-poetry','','[]','許多顔色泥春嬌，就裏輕紅最□饒。',64,'全唐诗/poet.song.1000.json','["許多顔色泥春嬌，就裏輕紅最□饒。", "生處地須名紫府，落時魂想返青霄。", "霞英散焰燒纖手，藥粉飄香著步摇。", "輕剪自憐支節痛，倚烟啼露一無憀。"]'),
('bfc05720-c4ee-4520-baeb-6bb1d85e7472','題義門胡氏華林書院','宋白','宋','宋诗','song-poetry','','[]','君家仙館带村塘，氣象清鮮雅趣長。',64,'全唐诗/poet.song.1000.json','["君家仙館带村塘，氣象清鮮雅趣長。", "千里客來如海納，一樓書靜透山光。", "門閭旌表芝泥貴，科篇聯翩桂籍香。", "帝里詞人多景慕，謾題詩句滿修篁。"]'),
('8b592671-ae1d-422a-b0e8-43b598873456','句  其一','宋白','宋','宋诗','song-poetry','','[]','吉音來碧落，帖子報紅牋。',36,'全唐诗/poet.song.1000.json','["吉音來碧落，帖子報紅牋。", "清夜驚神王，朧明到省前。", "風中宮漏盡，日出榜繩懸。"]'),
('ccbff741-87c2-4d78-9712-e1ca5706b09b','句  其二','宋白','宋','宋诗','song-poetry','','[]','勞君贈我古風詩，逋翁所謂撲凸奇。',16,'全唐诗/poet.song.1000.json','["勞君贈我古風詩，逋翁所謂撲凸奇。"]'),
('6ecd2e74-6624-42b3-ab7f-487fe94edb02','句  其三','宋白','宋','宋诗','song-poetry','','[]','宋朝歸聖主，潘閬是詩人。',12,'全唐诗/poet.song.1000.json','["宋朝歸聖主，潘閬是詩人。"]'),
('e23f822e-4b0b-4ba3-85a1-0fc9a59c9465','句  其四','宋白','宋','宋诗','song-poetry','','[]','凌晨走退蝦蟆鼻，幾日飛經灩澦堆。',16,'全唐诗/poet.song.1000.json','["凌晨走退蝦蟆鼻，幾日飛經灩澦堆。"]'),
('1f17348f-35c6-48b7-8871-1375fe2c4b51','句  其五','宋白','宋','宋诗','song-poetry','','[]','春風麥隴連蠻芊，細雨梨花問海棠。',16,'全唐诗/poet.song.1000.json','["春風麥隴連蠻芊，細雨梨花問海棠。"]'),
('ba6791e2-21b4-4063-8a4d-7210ee7b7898','句  其六','宋白','宋','宋诗','song-poetry','','[]','竹底衙人吏，花間押簿書。',12,'全唐诗/poet.song.1000.json','["竹底衙人吏，花間押簿書。"]'),
('331f3fb0-3390-46a3-98b0-89aeca364c72','句  其七','宋白','宋','宋诗','song-poetry','','[]','峨眉多雨雅江秋，溢岸清波入郡流。',16,'全唐诗/poet.song.1000.json','["峨眉多雨雅江秋，溢岸清波入郡流。"]'),
('01c9f706-f3f8-4f47-8cab-f6de768b2163','句  其八','宋白','宋','宋诗','song-poetry','','[]','最念春風嘗酒處，梅酸笋翠後溪頭。',16,'全唐诗/poet.song.1000.json','["最念春風嘗酒處，梅酸笋翠後溪頭。"]'),
('3b1ea09a-aa7d-4fe4-9606-6d0cf7d4b854','句  其九','宋白','宋','宋诗','song-poetry','','[]','玉津縣裏三年悶，金粟山前九月愁。',16,'全唐诗/poet.song.1000.json','["玉津縣裏三年悶，金粟山前九月愁。"]'),
('33563c2f-6611-4239-bbbd-9956249bb4fa','句  其一○','宋白','宋','宋诗','song-poetry','','[]','梅雪初銷臘酒香，嘉州屬縣且尋芳。',16,'全唐诗/poet.song.1000.json','["梅雪初銷臘酒香，嘉州屬縣且尋芳。"]'),
('fbf903fa-3eff-4d37-894f-e3052bae18c5','句  其一一','宋白','宋','宋诗','song-poetry','','[]','道出嘉陽正西指，一带靈峰如湧起。',16,'全唐诗/poet.song.1000.json','["道出嘉陽正西指，一带靈峰如湧起。"]'),
('3cbb2889-fc78-42a1-90a7-d7cd36207373','句  其一二','宋白','宋','宋诗','song-poetry','','[]','回眸已覺三山近，滿壁潛驚五月寒。',16,'全唐诗/poet.song.1000.json','["回眸已覺三山近，滿壁潛驚五月寒。"]'),
('8bc895df-cbd5-41a1-8f13-d507e245d6c0','句  其一三','宋白','宋','宋诗','song-poetry','','[]','昔日曾爲尺木階，今朝真是青雲友。',16,'全唐诗/poet.song.1000.json','["昔日曾爲尺木階，今朝真是青雲友。"]'),
('8719106f-9703-455e-a36e-ec53e87d50e4','平望蚊','錢儼','宋','宋诗','song-poetry','','[]','安得神仙術，試爲施康濟。',24,'全唐诗/poet.song.1000.json','["安得神仙術，試爲施康濟。", "使此平望村，如吾江子匯。"]'),
('072aef4f-5fb0-41c5-bfb3-3585dd637ca6','禁林讌會之什','潘慎修','宋','宋诗','song-poetry','','[]','紅藥深嚴肅廣筵，嘉招仍許厠羣仙。',96,'全唐诗/poet.song.1000.json','["紅藥深嚴肅廣筵，嘉招仍許厠羣仙。", "忽窺宸翰雲龍動，乍揭天辭日月懸。", "散作楷模爭寶惜，永刊金石共流傳。", "况當枚馬從容地，仍集班揚侍從賢。", "敢竊休明爲盛觀，願陳風詠播薰弦。", "不辭勝引承歡醉，長洽昇平億萬年。"]'),
('0dd983ff-8fd9-47e8-b341-b0a4201bee42','句','潘慎修','宋','宋诗','song-poetry','','[]','如今縱得仙翁術，也怯君王四路饒。',16,'全唐诗/poet.song.1000.json','["如今縱得仙翁術，也怯君王四路饒。"]'),
('37760d32-4a5f-47e1-af01-f1ac5ec496eb','題義門胡氏華林書院','何蒙','宋','宋诗','song-poetry','','[]','滿眼烟霞與宅連，義高孝弟代相傳。',160,'全唐诗/poet.song.1000.json','["滿眼烟霞與宅連，義高孝弟代相傳。", "彤庭召對曾承詔，內府頒書特奉宣。", "學古一門遵法度，禮賓羣僕盡精賢。", "竺齋月夜招琴客，花院春風恣飲筵。", "乘興訪僧因掛褐，傍秋買鶴不爭錢。", "半空山色長供望，徹曉清泉緩醒眠。", "殘暑就溪開敞檻，晚凉觀稼入平川。", "神仙藥術親留寫，朝達詩牌自把懸。", "携手漫思爲好伴，此身方恨未歸田。", "憶君幾度西南望，遥想情風寄一篇。"]'),
('653deb07-48bc-4aad-9185-575189d08f9a','句','何蒙','宋','宋诗','song-poetry','','[]','塞日穿痕斷，邊雲背影飛。',24,'全唐诗/poet.song.1000.json','["塞日穿痕斷，邊雲背影飛。", "縹緲隨黄屋，陰沈護御衣。"]'),
('0e28f2bd-ebdc-42bf-bda0-4d9884406900','遊古陌吟','王處厚','宋','宋诗','song-poetry','','[]','誰言今古事難窮，大抵榮枯總是空。',64,'全唐诗/poet.song.1000.json','["誰言今古事難窮，大抵榮枯總是空。", "算得生前隨夢蝶，爭如雲外指冥鴻。", "暗添雪色眉根白，旋落花光臉上紅。", "惆悵荒原懶回首，暮林蕭索起悲風。"]'),
('e3087818-74fe-420c-a375-19012a973e59','贈英公大師','李頌','宋','宋诗','song-poetry','','[]','篆高神品，秀爽天骨。',80,'全唐诗/poet.song.1000.json','["篆高神品，秀爽天骨。", "敏搆機先，談深理窟。", "濬極蒼源，玄臻籀闥。", "玉無疵瑕，車有輗軏。", "達識圓明，靈襟洞豁。", "粹稟飛星，胸挂流月。", "大飲陶陶，閑遊兀兀。", "肯如常人，名利乾沒。"]'),
('b5c7b5a4-8584-4605-a14f-2caf428912f2','送英公大師歸終南','盧岳','宋','宋诗','song-poetry','','[]','擬息游方興，蘿龕近翠微。',48,'全唐诗/poet.song.1000.json','["擬息游方興，蘿龕近翠微。", "幾程勞夜夢，一錫向秋歸。", "月彩籠清磬，嵐光潤紫衣。", "重尋溪上路，楓葉下巖扉。"]'),
('b26e0ee8-3ddc-4dda-9e60-7a55c9c1c3cd','贈英公大師','許道寧','宋','宋诗','song-poetry','','[]','業就携筇別五湖，御簾香暖幾曾趨。',64,'全唐诗/poet.song.1000.json','["業就携筇別五湖，御簾香暖幾曾趨。", "精搜象外吟情逸，玄達禪中惠性殊。", "江塢秋思霜橘美，雲房高寄海峰孤。", "白蓮共結他年約，還放疏慵入社無。"]'),
('71bcadec-4205-459e-a8cc-d7fbc0159e3b','禁林讌會之什','畢士安','宋','宋诗','song-poetry','','[]','好文英主古難齊，寵重詞臣意弗低。',96,'全唐诗/poet.song.1000.json','["好文英主古難齊，寵重詞臣意弗低。", "睿藻清新刊翠琰，神蹤飛動在璇題。", "芸籤許效蓬萊閣，花檻容模罨畫溪。", "樂聖朋儕開綺席，愛君誠抱挂金閨。", "買臣晚遇知多幸，犬子端憂思轉稽。", "天地恩私無以報，只將兢慎對芝泥。"]'),
('ecdc35b8-b872-4563-943b-8555aae53033','楊照承議蘆雁枕屏','畢士安','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','畫師不肯傳風蝶，故作枯乾逞奇絕。',176,'全唐诗/poet.song.1000.json','["畫師不肯傳風蝶，故作枯乾逞奇絕。", "清秋未合結繁陰，深戶何從灑飛雪。", "雪裏鴨兒苦耐寒，眠沙枕浦白雲團，黄蘆槭槭枝葉乾。", "江頭鳴雁恰飛起，恍如身到瀟湘間。", "瀟相洞庭雲水隔，山路坡陁斷行客。", "從來冬景畫已難，况有翎毛似崔白。", "已覺冰漫稻粱少，更疑水宿溪垠窄。", "生平有道付滄洲，今日床頭動行色。", "屏風主人家近遠，我昔曾過潯陽縣，田蘆野雁嘗親見。", "出門解榻定相逢，借我家鄉令對面。"]'),
('40cb579b-97b4-4b5e-9442-160025ca063a','國清寺','畢士安','宋','宋诗','song-poetry','','[]','三四百年寺，今來國又清。',48,'全唐诗/poet.song.1000.json','["三四百年寺，今來國又清。", "若非逢聖祚，徒自有嘉名。", "月殿五峰色，風松十里聲。", "不緣君命束，便好脫塵纓。"]'),
('73d80e34-0146-4860-9ae9-546847d4f32d','答王黄門寄密蒙花','畢士安','宋','宋诗','song-poetry','','[]','多病眼昏書懶寄，煩君遠寄密蒙花。',32,'全唐诗/poet.song.1000.json','["多病眼昏書懶寄，煩君遠寄密蒙花。", "愁無內史兼詞翰，爲寫真方到海涯。"]'),
('814919a5-2393-4510-bde6-084bd829724f','遊七星巖','張去華','宋','宋诗','song-poetry','','[]','桂林平地起山尖，獨此奇峰個個圓。',64,'全唐诗/poet.song.1000.json','["桂林平地起山尖，獨此奇峰個個圓。", "上應星辰三四點，中藏空洞幾千年。", "乘槎客子頻相訪，騎鶴仙人竟不還。", "多少南來驄馬客，品題詩句細磨鎸。"]'),
('f7c606c9-4e6e-49c3-a625-2b16385e995d','上陳文惠','楊朴','宋','宋诗','song-poetry','','[]','昨夜西風爛漫秋，今朝東岸獨垂鈎。',32,'全唐诗/poet.song.1000.json','["昨夜西風爛漫秋，今朝東岸獨垂鈎。", "紫袍不識蓑衣客，曾對君王十二旒。"]'),
('983d24b7-8f7b-4793-95a3-40ed48befd99','村居感興','楊朴','宋','宋诗','song-poetry','','[]','一壺村酒膠牙酸，十數胡皴徹骨乾。',32,'全唐诗/poet.song.1000.json','["一壺村酒膠牙酸，十數胡皴徹骨乾。", "隨著四婆裙子後，杖頭挑去賽蠶官。"]'),
('037ecc29-0e2a-469f-a4ec-28355b4edbff','七夕','楊朴','宋','宋诗','song-poetry','','["\u4e03\u5915\u60c5\u4eba\u8282", "\u4e03\u5915\u8282"]','未會牽牛意若何，須邀織女弄金梭。',32,'全唐诗/poet.song.1000.json','["未會牽牛意若何，須邀織女弄金梭。", "年年乞與人間巧，不道人間巧已多。"]'),
('27406cea-f300-4c28-9eb2-f79bbafc8d47','秋日閑居','楊朴','宋','宋诗','song-poetry','','[]','忽聞高柳噪新蟬，厭暑情懷頓豁然。',64,'全唐诗/poet.song.1000.json','["忽聞高柳噪新蟬，厭暑情懷頓豁然。", "庭檻夜凉風撼竹，池塘香散水摇蓮。", "鱸魚鱠憶奔江浦，焦尾琴思換蜀弦。", "莫遣金樽空對月，滿斟高唱混流年。"]'),
('61138729-94bc-4d60-8893-2028f7575ddf','莎衣','楊朴','宋','宋诗','song-poetry','','[]','軟綠柔藍著勝衣，倚船吟釣正相宜。',64,'全唐诗/poet.song.1000.json','["軟綠柔藍著勝衣，倚船吟釣正相宜。", "蒹葭影裏和烟卧，菡萏香中带雨披。", "狂脫酒家春醉後，亂堆漁舍晚晴時。", "直饒紫綬金章貴，未肯輕輕博換伊。"]'),
('79ccfe86-a0fe-49f5-9b96-35e2c0c7d2f7','詩一首','楊朴','宋','宋诗','song-poetry','','[]','更無落魄耽盃酒，更莫猖狂愛詠詩。',32,'全唐诗/poet.song.1000.json','["更無落魄耽盃酒，更莫猖狂愛詠詩。", "今日捉將官裏去，這回斷送老頭皮。"]'),
('6ab9d266-9e3a-4dde-a975-d6609d2d931a','句','楊朴','宋','宋诗','song-poetry','','[]','就客飲時擔酒去，見鱼遊處撥萍開。',16,'全唐诗/poet.song.1000.json','["就客飲時擔酒去，見鱼遊處撥萍開。"]'),
('f89ace01-eecb-4db3-9226-70f37ce6a9bf','題汶川村居','滕白','宋','宋诗','song-poetry','','[]','種茶巖接紅霞塢，灌稻泉生白石根。',32,'全唐诗/poet.song.1000.json','["種茶巖接紅霞塢，灌稻泉生白石根。", "皤腹老翁眉似雪，海棠花下戲兒孫。"]'),
('d3cb4306-26d4-4af6-a9f4-55eb3167d314','燕','滕白','宋','宋诗','song-poetry','','[]','短羽新來別海陽，真珠高捲語雕梁。',32,'全唐诗/poet.song.1000.json','["短羽新來別海陽，真珠高捲語雕梁。", "佳人未必全聽爾，正把金針繡鳳凰。"]'),
('a552c5f0-c442-4bd3-85db-2442e28bf6b3','山行','滕白','宋','宋诗','song-poetry','','[]','馬頭閒覺入從容，疊嶂清秋度百重。',64,'全唐诗/poet.song.1000.json','["馬頭閒覺入從容，疊嶂清秋度百重。", "長見孤雲能作雨，未應片水不藏龍。", "花村幾處連修竹，澗石誰家倚瘦松。", "本若無心許明代，好尋巢許此韜蹤。"]'),
('13490e9e-5325-4972-9665-ead9fb86132a','七絕三首  其一','滕白','宋','宋诗','song-poetry','','[]','稻穗登場穀滿車，家家雞犬更桑麻。',32,'全唐诗/poet.song.1000.json','["稻穗登場穀滿車，家家雞犬更桑麻。", "謾栽木槿成籬落，已得清陰又得花。"]'),
('9ed5aaaf-0243-4a3a-9044-0719044c7624','七絕三首  其二','滕白','宋','宋诗','song-poetry','','[]','周遭圩岸繚山城，一眼圩田翠不分。',32,'全唐诗/poet.song.1000.json','["周遭圩岸繚山城，一眼圩田翠不分。", "行到秋苗初熟處，翠茸錦上織黄雲。"]'),
('1221a217-83b9-4677-91a3-367713b0d165','七絕三首  其三','滕白','宋','宋诗','song-poetry','','[]','古來圩岸護隄防，岸岸圩圩種綠楊。',32,'全唐诗/poet.song.1000.json','["古來圩岸護隄防，岸岸圩圩種綠楊。", "歲久樹根無寸土，綠楊走入水中央。"]'),
('9b62d301-32d3-48bd-9729-5f8eb56a51cd','題嚴君觀','王嵒','宋','宋诗','song-poetry','','[]','寒雲古木罩星臺，凡骨仙蹤信可哀。',32,'全唐诗/poet.song.1000.json','["寒雲古木罩星臺，凡骨仙蹤信可哀。", "二十年前曾此到，一千年內未歸來。"]'),
('94c1212e-7e16-4ab7-9f82-6a9c51bbb953','山中有所思','王嵒','宋','宋诗','song-poetry','','[]','零零夜雨漬愁根，觸物傷離好斷魂。',32,'全唐诗/poet.song.1000.json','["零零夜雨漬愁根，觸物傷離好斷魂。", "莫怪杜鵑飛去盡，紫微花裏有啼猿。"]'),
('fbbce014-c563-483e-91db-0141a008e86b','燕','王嵒','宋','宋诗','song-poetry','','[]','一巢功績破春光，絮落花殘兩翅狂。',32,'全唐诗/poet.song.1000.json','["一巢功績破春光，絮落花殘兩翅狂。", "月樹風枝不棲去，强來言語泥雕梁。"]'),
('e2946c2a-f275-48b8-9bfc-4034480b46f9','貧女','王嵒','宋','宋诗','song-poetry','','[]','難把菱花照素顔，試臨春水插花看。',32,'全唐诗/poet.song.1000.json','["難把菱花照素顔，試臨春水插花看。", "木蘭船上遊春子，笑指荆釵下遠灘。"]'),
('cda10708-ba4a-40b4-b79a-4812ad268c93','杪春寄友人','王嵒','宋','宋诗','song-poetry','','[]','何處相逢萬事忙，卓家樓上百淘香。',32,'全唐诗/poet.song.1000.json','["何處相逢萬事忙，卓家樓上百淘香。", "明朝漸近山僧寺，更爲殘花醉一場。"]'),
('c8f7b965-7f58-4df9-a100-09ea9834ad48','回舊山','王嵒','宋','宋诗','song-poetry','','[]','庾家樓上謝家池，處處風烟少舊知。',32,'全唐诗/poet.song.1000.json','["庾家樓上謝家池，處處風烟少舊知。", "明日落花誰共醉，野溪猿鳥恨歸遲。"]'),
('82d60e05-3cf6-450a-876a-7494d1241463','殘冬客次資陽江','王嵒','宋','宋诗','song-poetry','','[]','淡雲殘雪簇江天，策蹇遲回客興闌。',64,'全唐诗/poet.song.1000.json','["淡雲殘雪簇江天，策蹇遲回客興闌。", "持鉢老僧來咒水，倚船商女待搬灘。", "沙翹白鷺非真靜，竹映繁梅奈苦寒。", "阮籍莫嗟歧路異，舊山溪畔有漁竿。"]'),
('bf0eaf00-59b0-474b-bc23-fc40cce4fcc4','句  其一','王嵒','宋','宋诗','song-poetry','','[]','何人輕大厦，放爾偃深雲。',12,'全唐诗/poet.song.1000.json','["何人輕大厦，放爾偃深雲。"]'),
('b6c2a7b7-7d59-4aa2-8fe2-48bde6018afe','句  其二','王嵒','宋','宋诗','song-poetry','','[]','高僧慣來看，踏破綠苔紋。',12,'全唐诗/poet.song.1000.json','["高僧慣來看，踏破綠苔紋。"]'),
