('893ce537-fcab-4998-8cbf-5b699aee97dc','題龍華山','郭震','宋','宋诗','song-poetry','','[]','昔年曾到此山來，百鳥聲中酒一盃。',32,'全唐诗/poet.song.1000.json','["昔年曾到此山來，百鳥聲中酒一盃。", "最好寺邊開眼處，段文昌有讀書臺。"]'),
('3e648904-6393-4a19-88fb-b668e9899953','紙窗','郭震','宋','宋诗','song-poetry','','[]','偏宜酥壁稱閑情，白似溪雲薄似冰。',32,'全唐诗/poet.song.1000.json','["偏宜酥壁稱閑情，白似溪雲薄似冰。", "不是野人嫌月色，免教風弄讀書燈。"]'),
('94bfdb43-044c-44c0-981d-277cfee90ec7','聞蛩','郭震','宋','宋诗','song-poetry','','[]','愁殺離家未達人，一聲聲到枕前聞。',32,'全唐诗/poet.song.1000.json','["愁殺離家未達人，一聲聲到枕前聞。", "苦吟莫入朱門裏，滿耳笙歌不聽君。"]'),
('843cfefd-09df-412f-8575-e1f54d553f83','東郊賦詩','郭震','宋','宋诗','song-poetry','','[]','今日出東郊，東郊好春色。',24,'全唐诗/poet.song.1000.json','["今日出東郊，東郊好春色。", "青青原上草，莫放征馬食。"]'),
('d845df92-dbd0-402f-b3bc-88a575fefc52','漁者','郭震','宋','宋诗','song-poetry','','[]','江柳弄風顰翠黛，山光著雨濕臙脂。',32,'全唐诗/poet.song.1000.json','["江柳弄風顰翠黛，山光著雨濕臙脂。", "却收短棹拈長笛，一葉舟中仰面吹。"]'),
('3fdf4eea-285c-4d4c-9c5b-382b3285adff','老卒','郭震','宋','宋诗','song-poetry','','[]','老來弓劍喜離身，說著沙場更愴神。',32,'全唐诗/poet.song.1000.json','["老來弓劍喜離身，說著沙場更愴神。", "任使將軍全得勝，歸時須少去時人。"]'),
('3b9c77d2-8fe5-4945-9a0b-70b1bcc9ac0f','雲','郭震','宋','宋诗','song-poetry','','[]','聚散虛空去復還，野人閑處倚筇看。',32,'全唐诗/poet.song.1000.json','["聚散虛空去復還，野人閑處倚筇看。", "不知身是無根物，蔽月遮星作萬端。"]'),
('14b970ed-65ef-490a-a681-cc8a4d82ce06','螢','郭震','宋','宋诗','song-poetry','','[]','秋風凜凜月依依，飛過高梧影裏時。',32,'全唐诗/poet.song.1000.json','["秋風凜凜月依依，飛過高梧影裏時。", "處暗若教同衆類，世間爭得有人知。"]'),
('dd433fce-bf0b-4578-b0d4-3318f560ba88','野井','郭震','宋','宋诗','song-poetry','','[]','縱無汲引味清澄，冷浸寒空月一輪。',32,'全唐诗/poet.song.1000.json','["縱無汲引味清澄，冷浸寒空月一輪。", "鑿處若教當要路，爲君常濟往來人。"]'),
('56e37236-b8d6-44b2-932d-f81cc1fced96','米囊花','郭震','宋','宋诗','song-poetry','','[]','開花空道勝於草，結實何曾濟得民。',32,'全唐诗/poet.song.1000.json','["開花空道勝於草，結實何曾濟得民。", "却笑野田禾與黍，不聞弦管過青春。"]'),
('278553bf-3d6c-4c71-a33a-0e4172e7e358','惜花','郭震','宋','宋诗','song-poetry','','[]','艷拂衣襟蕊拂杯，遶枝閒共蝶徘徊。',32,'全唐诗/poet.song.1000.json','["艷拂衣襟蕊拂杯，遶枝閒共蝶徘徊。", "春風滿目還惆悵，半欲離披半未開。"]'),
('8982cd7f-a302-499f-ab1d-e8e8afc6a13d','蓮花','郭震','宋','宋诗','song-poetry','','[]','臉膩香薰似有情，世間何物比輕盈。',32,'全唐诗/poet.song.1000.json','["臉膩香薰似有情，世間何物比輕盈。", "湘妃雨後來池看，碧玉盤中弄水晶。"]'),
('59b654cd-8786-4abd-9ece-0a59b270edfd','海棠','郭震','宋','宋诗','song-poetry','','[]','又隨桃李一時榮，不逐東風處處生。',32,'全唐诗/poet.song.1000.json','["又隨桃李一時榮，不逐東風處處生。", "疑是四方嫌不種，教於蜀地獨垂名。"]'),
('1b657f77-e499-4f9c-98bc-24d4b264b60f','宿漁家','郭震','宋','宋诗','song-poetry','','[]','幾代生涯傍海涯，兩三間屋蓋蘆花。',32,'全唐诗/poet.song.1000.json','["幾代生涯傍海涯，兩三間屋蓋蘆花。", "燈前笑說歸來夜，明月隨船送到家。"]'),
('eb8a5313-e81b-4303-9fde-64ff14724ad7','詩二首  其一','郭震','宋','宋诗','song-poetry','','[]','流落天涯與海涯，舊山終日恨歸遲。',32,'全唐诗/poet.song.1000.json','["流落天涯與海涯，舊山終日恨歸遲。", "思量却得蹉跎力，會盡人間一肚皮。"]'),
('0fad0936-51a0-496d-b504-cb72786d3f17','詩二首  其二','郭震','宋','宋诗','song-poetry','','[]','江樓四面立屏風，到此詩家合用功。',32,'全唐诗/poet.song.1000.json','["江樓四面立屏風，到此詩家合用功。", "沽酒店藏花影內，打漁村在浪聲中。"]'),
('bdf18a9f-82b3-4c22-8c75-518a0510f24d','句  其一','郭震','宋','宋诗','song-poetry','','[]','人世幾番更面目，仙山依舊鎖烟霞。',16,'全唐诗/poet.song.1000.json','["人世幾番更面目，仙山依舊鎖烟霞。"]'),
