('7cf13e5d-0b95-4fdf-8e4a-661fa73bec69','示執坐禪者','釋省澄','宋','宋诗','song-poetry','','[]','大道分明絕點塵，何須枯坐始相親。',32,'全唐诗/poet.song.1000.json','["大道分明絕點塵，何須枯坐始相親。", "杖藜日涉谿山趣，便是烟霞物外人。"]'),
('49a22494-2cd3-4c26-a04a-6fe935a817e6','句  其一','劉能','宋','宋诗','song-poetry','','[]','窗外秋聲湘瑟怨，檻前竹色楚帆飛。',16,'全唐诗/poet.song.1000.json','["窗外秋聲湘瑟怨，檻前竹色楚帆飛。"]'),
('b73053fa-2a8a-406b-a62e-65291b3386d9','句  其二','劉能','宋','宋诗','song-poetry','','[]','懶向九嶷歧路望，渡頭雲雨正霏霏。',16,'全唐诗/poet.song.1000.json','["懶向九嶷歧路望，渡頭雲雨正霏霏。"]'),
('f105f09c-34e8-4fd5-8873-7dbc031dca79','贈李營丘','劉鼇','宋','宋诗','song-poetry','','[]','六幅冰綃挂翠庭，危峰疊嶂鬭崢嶸。',32,'全唐诗/poet.song.1000.json','["六幅冰綃挂翠庭，危峰疊嶂鬭崢嶸。", "却因一夜芭蕉雨，疑是巖前瀑布聲。"]'),
('b5752701-2d26-4386-8307-834bcbe3dbcb','句','賀亢','宋','宋诗','song-poetry','','[]','但存方寸地，留與子孫耕。',12,'全唐诗/poet.song.1000.json','["但存方寸地，留與子孫耕。"]'),
('65e67f83-2059-4e67-8892-84c53376c559','句  其一','高元矩','宋','宋诗','song-poetry','','[]','硯貯寒泉碧，庭堆敗葉紅。',12,'全唐诗/poet.song.1000.json','["硯貯寒泉碧，庭堆敗葉紅。"]'),
('1b1ea78e-d758-4ecd-b861-032896d270bf','句  其二','高元矩','宋','宋诗','song-poetry','','[]','鳥掠琴弦穿靜院，吏收詩草下閒庭。',16,'全唐诗/poet.song.1000.json','["鳥掠琴弦穿靜院，吏收詩草下閒庭。"]'),
('91764150-4df3-4165-9b8f-a01f88a88b88','逍遥詠  其一','宋太宗','宋','宋诗','song-poetry','','[]','逍遥知語默，境外見真空。',48,'全唐诗/poet.song.1000.json','["逍遥知語默，境外見真空。", "有位皆玄感，無緣不用功。", "義說三才理，幽深萬事通。", "因依堪法則，答謝向旻穹。"]'),
('9cf96e94-6c8d-4653-8b06-ba6d0229a1b0','逍遥詠  其二','宋太宗','宋','宋诗','song-poetry','','[]','大道虛無境，信之則有靈。',48,'全唐诗/poet.song.1000.json','["大道虛無境，信之則有靈。", "幽深玄妙理，運轉幾曾停。", "拘束從何益，周通靜杳冥。", "真空非作相，善應保安寧。"]'),
('4f52b1af-b2ab-419c-8419-83604d14856f','逍遥詠  其三','宋太宗','宋','宋诗','song-poetry','','[]','我自常安樂，凡情勿笑耶。',48,'全唐诗/poet.song.1000.json','["我自常安樂，凡情勿笑耶。", "雲生諸洞府，棘不放仙花。", "地卑三光照，天開五色霞。", "未知何所是，善願理交加。"]'),
('a3e662e5-d661-4827-a9a6-3742fcc9f757','逍遥詠  其四','宋太宗','宋','宋诗','song-poetry','','[]','我達逍遥理，陰陽運五行。',48,'全唐诗/poet.song.1000.json','["我達逍遥理，陰陽運五行。", "道從初一變，德合混三清。", "聖境堪依仗，狐疑事不成。", "異端違雅淡，返禍自輕生。"]'),
('eedbea8e-eb83-4656-98be-897401f788fb','逍遥詠  其五','宋太宗','宋','宋诗','song-poetry','','[]','逍遥人控鶴，碧落壓天津。',48,'全唐诗/poet.song.1000.json','["逍遥人控鶴，碧落壓天津。", "達理通含識，虛無即是真。", "河車誰肯信，鉛汞本相親。", "造化皆如此，今緣論宿因。"]'),
('1d732153-3e22-4edd-bea3-5dc27b5b51ba','逍遥詠  其六','宋太宗','宋','宋诗','song-poetry','','[]','何處堪依仗，經心便皺眉。',129,'全唐诗/poet.song.1000.json','["何處堪依仗，經心便皺眉。", "世情多詭詐，業重信愚癡。", "取次招他謗，違非不自知。", "貌恭無德行，禍福在修持。", "小人以小善爲無益而弗爲也，以小惡爲無傷而弗去也，此正在改過修持爾。", "虛無知大道，極意思悠然。", "摩日雲中雁，瀟湘水似天。", "孤峰高遠近，寶月瑩團圓。", "信解明開悟，青霄在目前。"]'),
('981ceecf-f828-4684-ac36-c9f1e71c0641','逍遥詠  其七','宋太宗','宋','宋诗','song-poetry','','[]','逍遥名有理，得一便知空。',48,'全唐诗/poet.song.1000.json','["逍遥名有理，得一便知空。", "道本皆深邃，凡爲不易窮。", "品流才雅淡，格致意潜通。", "救世傳相益，因成順八風。"]'),
('ae8e1b6b-957b-4b34-a526-d567f7d00041','逍遥詠  其八','宋太宗','宋','宋诗','song-poetry','','[]','誰測玄機聖，天功地久長。',48,'全唐诗/poet.song.1000.json','["誰測玄機聖，天功地久長。", "羣生皆是性，道德有圓方。", "妍醜隨情意，於戲細酌量。", "達人知淡泊，默默見非常。"]'),
('46b3f673-2d0f-4a0e-ab9c-dbc2ac6da6ea','逍遥詠  其九','宋太宗','宋','宋诗','song-poetry','','[]','道德誰分別，逍遥我自由。',48,'全唐诗/poet.song.1000.json','["道德誰分別，逍遥我自由。", "時情人不達，深理少相投。", "己是終無益，非他作逗留。", "奈何爲各異，未定復還休。"]'),
('674be52d-2bee-4e9c-b3b4-1fcc40796557','逍遥詠  其一○','宋太宗','宋','宋诗','song-poetry','','[]','奧義通玄化，精微妙入神。',48,'全唐诗/poet.song.1000.json','["奧義通玄化，精微妙入神。", "功程隨志願，貶降背於真。", "靜默堪爲法，無言事可親。", "逢師傳口訣，金玉變埃塵。"]'),
('c9e14a5b-89e7-4173-86e0-ea3acc2f5f67','逍遥詠  其一一','宋太宗','宋','宋诗','song-poetry','','[]','清靜真空理，不無解者難。',48,'全唐诗/poet.song.1000.json','["清靜真空理，不無解者難。", "縱橫依見性，廓落智中觀。", "坦蕩歸仁德，辛勤久遠看。", "勿教爲逆順，平地入雲端。"]'),
('6db490c5-a497-44bd-badd-9d1843424c5b','逍遥詠  其一二','宋太宗','宋','宋诗','song-poetry','','[]','乾坤常運轉，兀兀見衆生。',48,'全唐诗/poet.song.1000.json','["乾坤常運轉，兀兀見衆生。", "利物終相應，施爲願要精。", "身慵何隠遁，舌辯謾縱橫。", "種性歸真理，因緣有重輕。"]'),
('c420c97e-f216-4422-b636-0e88f461b332','逍遥詠  其一三','宋太宗','宋','宋诗','song-poetry','','[]','仙經無限意，龍虎返丹砂。',48,'全唐诗/poet.song.1000.json','["仙經無限意，龍虎返丹砂。", "採綴陰陽理，終期歲月賒。", "求來皆有應，不信固難誇。", "忙說閑清境，真誠悟幾家。"]'),
('a50407f0-7ad5-4b5d-9a09-c230b3418cf8','逍遥詠  其一四','宋太宗','宋','宋诗','song-poetry','','[]','陽與陰和合，須從一字求。',48,'全唐诗/poet.song.1000.json','["陽與陰和合，須從一字求。", "分明皆是象，作相不能投。", "舉措先真實，精麤各自柔。", "恒持通覺悟，萬派水東流。"]'),
('eb8a5353-be57-4d24-9cf5-728885316b09','逍遥詠  其一五','宋太宗','宋','宋诗','song-poetry','','[]','鉛汞精修鍊，陰陽協物情。',48,'全唐诗/poet.song.1000.json','["鉛汞精修鍊，陰陽協物情。", "花開黄道正，藥就紫烟輕。", "海嶠浮雲合，神光照室明。", "彩霞高麗日，細意話長生。"]'),
('87f7bfbb-fbd4-4d39-9678-3568757b7fba','逍遥詠  其一六','宋太宗','宋','宋诗','song-poetry','','[]','照然明道德，萬象有其端。',48,'全唐诗/poet.song.1000.json','["照然明道德，萬象有其端。", "變化疑誰信，超凡入聖看。", "幽玄深自在，眇邈就中難。", "但味風塵裏，方知宇宙寬。"]'),
('67594cd8-81b7-4db6-8315-96155cb46ddc','逍遥詠  其一七','宋太宗','宋','宋诗','song-poetry','','[]','世界無窮盡，論之遠更深。',48,'全唐诗/poet.song.1000.json','["世界無窮盡，論之遠更深。", "陰陽分皂白，瓦礫變黄金。", "報應終還有，邪求不易尋。", "忩忙誰正定，須是合天心。"]'),
('03458ecb-7d6e-4a72-a133-04146ed19517','逍遥詠  其一八','宋太宗','宋','宋诗','song-poetry','','[]','世利貪拘束，欺心自不知。',48,'全唐诗/poet.song.1000.json','["世利貪拘束，欺心自不知。", "一真求意在，四敘絕參差。", "頓悟超諸聖，娛情改換癡。", "生前如似夢，願重細推之。"]'),
('2c2506ca-3d00-4642-aa86-4358bb9d49b2','逍遥詠  其一九','宋太宗','宋','宋诗','song-poetry','','[]','愚癡常似醉，何異夢中人。',48,'全唐诗/poet.song.1000.json','["愚癡常似醉，何異夢中人。", "欲達終無見，懷疑道豈親。", "非爲貪閉口，那是益於身。", "先生堪寂默，種福不傳因。"]'),
('1adac7ad-6e7d-430e-9d7d-94d59af0ac14','逍遥詠  其一','宋太宗','宋','宋诗','song-poetry','','[]','人救眼前急，何曾利益心。',48,'全唐诗/poet.song.1000.json','["人救眼前急，何曾利益心。", "愚迷終淺見，達者智高深。", "苦行須知應，餘憂力不任。", "經書無限意，稽古便同今。"]'),
('bec93f5f-a71c-4a26-b1fe-cf4610eee8ad','逍遥詠  其二','宋太宗','宋','宋诗','song-poetry','','[]','逍遥安且定，但信莫懷疑。',48,'全唐诗/poet.song.1000.json','["逍遥安且定，但信莫懷疑。", "大海波中水，狂風樹擺枝。", "樂天分造化，慧眼細觀之。", "方寸無諸惡，恒將利益持。"]'),
('d206bb2f-316c-44ce-b431-f98a6df52c2b','逍遥詠  其三','宋太宗','宋','宋诗','song-poetry','','[]','恍惚人難曉，天仙語默玄。',48,'全唐诗/poet.song.1000.json','["恍惚人難曉，天仙語默玄。", "修心無道理，終日自忙然。", "我命真中趣，長生認宿緣。", "機權饒使用，聖事不虛傳。"]'),
('79557da2-89cf-432d-ad2f-cdf1bfaaf4cc','逍遥詠  其四','宋太宗','宋','宋诗','song-poetry','','[]','清虛閑靜得，奉道見真歸。',48,'全唐诗/poet.song.1000.json','["清虛閑靜得，奉道見真歸。", "契合皆堪用，因緣事好依。", "精誠求諦信，須有是兼非。", "豁達幽深遠，奧妙入玄機。"]'),
('22287c39-d159-4bdf-9505-bdfd67b88da7','逍遥詠  其五','宋太宗','宋','宋诗','song-poetry','','[]','清靜人安樂，恒持要久長。',48,'全唐诗/poet.song.1000.json','["清靜人安樂，恒持要久長。", "秋天澄皓色，春日發輝光。", "一氣從初立，三才位不忙。", "羣生如似夢，甚處得馨香。"]'),
('0351e526-a253-4811-ba51-dae223b699dc','逍遥詠  其六','宋太宗','宋','宋诗','song-poetry','','[]','道者强名立，清虛隠顯深。',48,'全唐诗/poet.song.1000.json','["道者强名立，清虛隠顯深。", "欲行千里路，別探一般心。", "景象空天遠，何勞意馬尋。", "玄談通智慧，曩劫至從今。"]'),
('35dcad9e-3fd9-47bb-aaf2-0a35325b6d46','逍遥詠  其七','宋太宗','宋','宋诗','song-poetry','','[]','冥搜多景趣，悟則頓神清。',48,'全唐诗/poet.song.1000.json','["冥搜多景趣，悟則頓神清。", "拘束終難得，沖和入道情。", "知微通理性，滋味好研精。", "妙用天然法，陰功藴大名。"]'),
('3e40b877-cd3e-4c89-b42a-2df4f58a8a88','逍遥詠  其八','宋太宗','宋','宋诗','song-poetry','','[]','氣類須相假，陰陽造化成。',48,'全唐诗/poet.song.1000.json','["氣類須相假，陰陽造化成。", "離凡知有聖，得外更求精。", "先秘庚辛理，後傳戊己名。", "真鉛歸一體，交感自長生。"]'),
('5ee8dd7b-ec82-4985-94fa-77b7943f7976','逍遥詠  其九','宋太宗','宋','宋诗','song-poetry','','[]','天界殊勝理，凡愚不易知。',48,'全唐诗/poet.song.1000.json','["天界殊勝理，凡愚不易知。", "曩因誰可究，淺近故懷疑。", "的實歸真性，區邪入正持。", "樂耶親大道，報應自然之。"]'),
('bd50c6e9-ab4d-4bce-85e0-ee24e3db0a94','逍遥詠  其一○','宋太宗','宋','宋诗','song-poetry','','[]','知之修鍊法，便是聖中人。',48,'全唐诗/poet.song.1000.json','["知之修鍊法，便是聖中人。", "有象虛無境，邪緣不見真。", "恒持功行益，響應甚平均。", "渾然天地理，大道徧乾坤。"]'),
('ef43d92d-f229-43fb-823e-3a3e7cd720bb','逍遥詠  其一一','宋太宗','宋','宋诗','song-poetry','','[]','伏藏終不見，巧拙是兼非。',48,'全唐诗/poet.song.1000.json','["伏藏終不見，巧拙是兼非。", "至道光懷古，周通隠聖機。", "清天何物性，濁地故相依。", "修鍊真堪惜，疏慵有順違。"]'),
('98f1c7d9-3134-4221-8cfe-556e570182e6','逍遥詠  其一二','宋太宗','宋','宋诗','song-poetry','','[]','夢寐其中物，常人何得知。',48,'全唐诗/poet.song.1000.json','["夢寐其中物，常人何得知。", "陰寒三數變，陽暖兩相宜。", "宿世終皆有，無緣勿强爲。", "真鉛歸至道，龍虎笑華池。"]'),
('2d58ddd8-5283-455c-8509-a52c74842a8e','逍遥詠  其一三','宋太宗','宋','宋诗','song-poetry','','[]','形影隨人得，精修道不迷。',48,'全唐诗/poet.song.1000.json','["形影隨人得，精修道不迷。", "研窮深理路，造化隠端倪。", "雲引龍吟穴，風生虎嘯溪。", "少知愚豈解，南北與東西。"]'),
('8f905838-536f-4e29-88ac-23b898aa56c3','逍遥詠  其一四','宋太宗','宋','宋诗','song-poetry','','[]','燕雀不生鳳，陰陽一氣全。',48,'全唐诗/poet.song.1000.json','["燕雀不生鳳，陰陽一氣全。", "無窮深可及，境象理推遷。", "奚益其形化，平章語默玄。", "終身何所役，道本豈私焉。"]'),
('b1310e76-9c5a-462e-938a-cb4691fc27c4','逍遥詠  其一五','宋太宗','宋','宋诗','song-poetry','','[]','自在無拘束，逍遥裏外安。',48,'全唐诗/poet.song.1000.json','["自在無拘束，逍遥裏外安。", "頑情終不見，聖境類乎端。", "機智將何用，幽深大道寬。", "區分能解意，四季一周看。"]'),
('29b31f1a-a1ba-4044-baf9-a79987531440','逍遥詠  其一六','宋太宗','宋','宋诗','song-poetry','','[]','求得真宗一，深知萬象清。',48,'全唐诗/poet.song.1000.json','["求得真宗一，深知萬象清。", "自然通感應，意外別長生。", "學古身何措，輝華日瑩明。", "誰窮天地理，去住兩無成。"]'),
('896b373c-20f5-4e50-9b08-dc3892f2b5a4','逍遥詠  其一七','宋太宗','宋','宋诗','song-poetry','','[]','不醉迷如醉，猶貪巨鼎扛。',48,'全唐诗/poet.song.1000.json','["不醉迷如醉，猶貪巨鼎扛。", "通玄求得一，清靜更無雙。", "鸞鳳栖瑶渚，天津壓漢江。", "欲窮何所似，夜月透雲窗。"]'),
('3781c22c-994d-489d-bfb9-c01869371809','逍遥詠  其一八','宋太宗','宋','宋诗','song-poetry','','[]','利鈍猶根性，無緣枉用心。',48,'全唐诗/poet.song.1000.json','["利鈍猶根性，無緣枉用心。", "邪求皆是相，正定理玄深。", "巧拙高含識，輕浮力不任。", "大乘通語默，稽古便知今。"]'),
('3f41515c-65f3-4cc2-a9f2-639746638261','逍遥詠  其一九','宋太宗','宋','宋诗','song-poetry','','[]','笑盡人間事，到頭總不知。',48,'全唐诗/poet.song.1000.json','["笑盡人間事，到頭總不知。", "信心終是實，如日瑩無欺。", "舉措持恒久，貪生却似癡。", "善緣銷惡趣，惠愛廣將施。"]'),
('3a6aca70-5ce4-4347-b5e6-1d980ff4b064','逍遥詠  其二○','宋太宗','宋','宋诗','song-poetry','','[]','五金并八石，一一注仙經。',48,'全唐诗/poet.song.1000.json','["五金并八石，一一注仙經。", "雅有深仁行，無非不暫停。", "日華精汞法，月魄鍊砂靈。", "入聖超凡骨，變化本真形。"]'),
('8fbcdd7d-bffc-4b4d-880b-4ecfbd24a54e','逍遥詠  其一','宋太宗','宋','宋诗','song-poetry','','[]','逍遥心自樂，清浄保長生。',48,'全唐诗/poet.song.1000.json','["逍遥心自樂，清浄保長生。", "至道歸玄理，真空造化成。", "輝華揚日彩，偃仰順風聲。", "裏外有何物，剛柔鍊始精。"]'),
('2cde1aef-ff46-499f-ac67-ea0fe063d45d','逍遥詠  其二','宋太宗','宋','宋诗','song-poetry','','[]','遁跡深巖谷，身閑未是閑。',48,'全唐诗/poet.song.1000.json','["遁跡深巖谷，身閑未是閑。", "研窮堪語默，寂靜杳冥間。", "秘密逢邪見，難開大道關。", "金丹無效用，弗可返童顔。"]'),
('450c874f-23f3-44ed-bcdc-524d45f070b7','逍遥詠  其三','宋太宗','宋','宋诗','song-poetry','','[]','金鼎精須鍊，華池水火紅。',48,'全唐诗/poet.song.1000.json','["金鼎精須鍊，華池水火紅。", "坎離能匹配，男女自相逢。", "曩劫知因果，生前道不窮。", "若修方寸是，發意便周通。"]'),
('2409e281-bff5-4878-b802-438b4925bd78','逍遥詠  其四','宋太宗','宋','宋诗','song-poetry','','[]','修鍊求真一，沖和本自然。',48,'全唐诗/poet.song.1000.json','["修鍊求真一，沖和本自然。", "希夷光滿月，響應真如弦。", "苦學周知易，難窮語默玄。", "成功兼積德，別有洞中天。"]'),
('38c29d5d-c2f2-4686-b055-d4d9b3399aca','逍遥詠  其五','宋太宗','宋','宋诗','song-poetry','','[]','一法從何有，三皇五帝前。',48,'全唐诗/poet.song.1000.json','["一法從何有，三皇五帝前。", "周知多異境，猛利要精專。", "我命須依道，陰功及物緣。", "善心通感應，動靜理深玄。"]'),
('27ee72a6-770f-4855-824d-089eb0b53e75','逍遥詠  其六','宋太宗','宋','宋诗','song-poetry','','[]','日照光文彩，周通無不關。',48,'全唐诗/poet.song.1000.json','["日照光文彩，周通無不關。", "天恩功最大，地載莫休閑。", "絕頂孤松老，飛雲野鶴還。", "玄珠名隠奧，杳靄路岐間。"]'),
('95c16036-da17-4648-9c2a-51ea08942561','逍遥詠  其七','宋太宗','宋','宋诗','song-poetry','','[]','清靜常清靜，緣來盡可行。',48,'全唐诗/poet.song.1000.json','["清靜常清靜，緣來盡可行。", "道高麋鹿性，庸識歲年輕。", "日昃相依勢，花開觸處明。", "是非論巧拙，達外福蒼生。"]'),
('96ccddc8-6387-432e-a774-ab6b5d8b792c','逍遥詠  其八','宋太宗','宋','宋诗','song-poetry','','[]','真境堪依仗，周遷四敘移。',48,'全唐诗/poet.song.1000.json','["真境堪依仗，周遷四敘移。", "人忙閑聖跡，心達罷狐疑。", "俊造皆流品，逢能即是師。", "二從寒暑變，龍浴鳳皇池。"]'),
('121d4866-684e-4f6f-99fe-fe9f2ab09205','逍遥詠  其九','宋太宗','宋','宋诗','song-poetry','','[]','戶牖常開閉，升沈倏忽中。',48,'全唐诗/poet.song.1000.json','["戶牖常開閉，升沈倏忽中。", "龍吟深邃理，虎嘯語言通。", "南北思長遠，東西道不窮。", "炎光收月魄，桂樹發花紅。"]'),
('76704ffb-8999-47be-b39c-952dae84d00c','逍遥詠  其一○','宋太宗','宋','宋诗','song-poetry','','[]','鼎內蓮花出，如塵發絳紅。',48,'全唐诗/poet.song.1000.json','["鼎內蓮花出，如塵發絳紅。", "坎鉛將匹配，離火好相逢。", "陰散何優劣，陽歸自合同。", "消停方可信，輝華大道雄。"]'),
('714610b7-24b4-48af-9ed6-a535461e496b','逍遥詠  其一一','宋太宗','宋','宋诗','song-poetry','','[]','虎龍本屬木，白虎作華池。',48,'全唐诗/poet.song.1000.json','["虎龍本屬木，白虎作華池。", "水火恒爲則，陰陽造化遲。", "清心常積德，凡眼豈能知。", "君子聽吾喻，神明勿闇欺。"]'),
('a6640918-4959-4310-b5bc-da1daad6aa5a','逍遥詠  其一二','宋太宗','宋','宋诗','song-poetry','','[]','萬靈通有感，臧否在名人。',48,'全唐诗/poet.song.1000.json','["萬靈通有感，臧否在名人。", "志誠昭明德，清浄見於真。", "奉道惟恭謹，修持願本因。", "廣將求利益，苦樂救生民。"]'),
('593f8bd0-e9eb-45a4-9b79-e03f78e96385','逍遥詠  其一三','宋太宗','宋','宋诗','song-poetry','','[]','頂戴尊天地，聰明識見高。',48,'全唐诗/poet.song.1000.json','["頂戴尊天地，聰明識見高。", "無爲通理性，猛利豈虛勞。", "出沒終難認，因緣不可逃。", "中原多聖境，四海湧滔滔。"]'),
('9ad67ec3-fc72-4b2a-a5e1-b417e8d5ed77','逍遥詠  其一四','宋太宗','宋','宋诗','song-poetry','','[]','世界諸方聖，如同在眼前。',48,'全唐诗/poet.song.1000.json','["世界諸方聖，如同在眼前。", "其於通要妙，便見理深玄。", "法教窮難盡，周知本自然。", "信誠含萬象，秘隠口親宣。"]'),
('c5632abc-3022-435d-82ba-36ad6edfff38','逍遥詠  其一五','宋太宗','宋','宋诗','song-poetry','','[]','隨緣心不見，性各本來真。',48,'全唐诗/poet.song.1000.json','["隨緣心不見，性各本來真。", "惡事誇脣頰，愚癡似醉人。", "忙忙何物有，急急利名親。", "入定觀浮世，蒼生業感因。"]'),
('7736f086-b292-4240-9fa6-31594b4a37b9','逍遥詠  其一六','宋太宗','宋','宋诗','song-poetry','','[]','善念銷嗔恚，無差本自然。',48,'全唐诗/poet.song.1000.json','["善念銷嗔恚，無差本自然。", "花開凡葉木，水打急風舡。", "拘執恒如縛，能仁學昔賢。", "神明皆正定，消息更深玄。"]'),
('3afa2340-905f-4f56-bf5c-2eda38115c1d','逍遥詠  其一七','宋太宗','宋','宋诗','song-poetry','','[]','逍遥賢聖樂，我悶俗情愚。',48,'全唐诗/poet.song.1000.json','["逍遥賢聖樂，我悶俗情愚。", "鄙俚何堪數，斟量解卷舒。", "惡緣須盡去，善事好相於。", "忙急真如夢，乾坤造化殊。"]'),
('29f828f0-1b85-4932-84f2-70a13d48f216','逍遥詠  其一八','宋太宗','宋','宋诗','song-poetry','','[]','宿願通賢聖，貪心勿强爲。',48,'全唐诗/poet.song.1000.json','["宿願通賢聖，貪心勿强爲。", "眼前銷惡趣，天鑒故無私。", "如夢何光景，明神所在知。", "精修觀出離，解脫影相隨。"]'),
('ee441a37-d962-4625-ba38-cfaa69ebdc63','逍遥詠  其一九','宋太宗','宋','宋诗','song-poetry','','[]','不爭多氣力，容易可成功。',48,'全唐诗/poet.song.1000.json','["不爭多氣力，容易可成功。", "意馬須調伏，如塵幻夢中。", "任持從雅淡，樂道定雌雄。", "修鍊知勤苦，因緣自合同。"]'),
('76956548-706c-4fb1-96af-c988625780d2','逍遥詠  其二○','宋太宗','宋','宋诗','song-poetry','','[]','一受諸同氣，熙和理道平。',48,'全唐诗/poet.song.1000.json','["一受諸同氣，熙和理道平。", "乘雲無滯礙，大樹種而生。", "塵垢勿教染，江河順不爭。", "機智潜棄用，方顯貴佳名。"]'),
('1d6a6887-32ac-4231-ad5e-896f2168bda1','逍遥詠  其一','宋太宗','宋','宋诗','song-poetry','','[]','白日衆生見，幾來得意人。',48,'全唐诗/poet.song.1000.json','["白日衆生見，幾來得意人。", "萍蓬如似夢，丹鼎妙清神。", "紅樹非花影，青松壓海津。", "入玄龍虎伏，大道許相親。"]'),
('208e12a5-3c6d-46cc-af0e-6e8ecd04c002','逍遥詠  其二','宋太宗','宋','宋诗','song-poetry','','[]','雅澹玄中得，常人故不知。',48,'全唐诗/poet.song.1000.json','["雅澹玄中得，常人故不知。", "幽深無遠近，道外細推之。", "碧落神仙境，烟霞日月隨。", "參詳寰宇內，邪正豈相離。"]'),
('75744f90-0511-4dd1-a14a-b749dd9cf697','逍遥詠  其三','宋太宗','宋','宋诗','song-poetry','','[]','逍遥通物性，大道有圓方。',48,'全唐诗/poet.song.1000.json','["逍遥通物性，大道有圓方。", "山谷高深淺，人心自短長。", "陰陽窮豈竭，造化入無疆。", "塵埃飛作垢，驚雁不成行。"]'),
('7b8f828a-2e3e-4ebd-a102-47e953ba79ea','逍遥詠  其四','宋太宗','宋','宋诗','song-poetry','','[]','羣生各自意，未有一般般。',48,'全唐诗/poet.song.1000.json','["羣生各自意，未有一般般。", "名利貪嗔賊，愚迷道路寬。", "避煩如雨散，清靜入雲端。", "善想因緣理，經窮子細看。"]'),
('417c21b8-ac65-4c43-9e7f-008bd39a63db','逍遥詠  其五','宋太宗','宋','宋诗','song-poetry','','[]','皇天無不照，福業重來輕。',48,'全唐诗/poet.song.1000.json','["皇天無不照，福業重來輕。", "背正堪何益，歸真道自成。", "本元宗一體，功行錄三清。", "幾許解吾意，慈悲利益平。"]'),
('4207d4d4-7d8e-4be8-a9b6-10606cc2fb7f','逍遥詠  其六','宋太宗','宋','宋诗','song-poetry','','[]','得道超凡聖，逍遥本是緣。',48,'全唐诗/poet.song.1000.json','["得道超凡聖，逍遥本是緣。", "羣迷難解會，我且不虛傳。", "但信恒無斷，精窮用意專。", "審聽明譬諭，勿被俗情牽。"]'),
('950a54f4-a1db-4826-bef7-35e3b877f26d','逍遥詠  其七','宋太宗','宋','宋诗','song-poetry','','[]','物情通萬象，達者便忘機。',48,'全唐诗/poet.song.1000.json','["物情通萬象，達者便忘機。", "各具含靈性，狐疑有是非。", "知天修福惠，如日瑩光輝。", "認取好歧路，惡去善相依。"]'),
('7c6130c9-d628-481e-8660-9da067c0ff20','逍遥詠  其八','宋太宗','宋','宋诗','song-poetry','','[]','經心玄妙理，道德念陰符。',48,'全唐诗/poet.song.1000.json','["經心玄妙理，道德念陰符。", "九轉金丹鼎，三才玉匱書。", "恒常皆隠秘，達者見清虛。", "倏忽神明意，先賢覺自愚。"]'),
('c820d7b1-6808-49e1-872f-909dc4856495','逍遥詠  其九','宋太宗','宋','宋诗','song-poetry','','[]','天地含清泰，陰陽道所成。',48,'全唐诗/poet.song.1000.json','["天地含清泰，陰陽道所成。", "沖和玄妙術，勿訝說長生。", "起信何疑誤，迷來却謗輕。", "攝心歸正念，淡薄惡銷聲。"]'),
('c718529b-50b2-4d87-99d0-3c9db886c981','逍遥詠  其一○','宋太宗','宋','宋诗','song-poetry','','[]','混沌初分後，陰陽辨濁清。',48,'全唐诗/poet.song.1000.json','["混沌初分後，陰陽辨濁清。", "三才皆備位，萬物有長生。", "罔象精通感，淳和道可明。", "但求方寸是，剖判應非輕。"]'),
('148b5018-74dd-4e5d-8bd7-a17f95194a53','逍遥詠  其一一','宋太宗','宋','宋诗','song-poetry','','[]','五色雲銷黯，方知大道深。',48,'全唐诗/poet.song.1000.json','["五色雲銷黯，方知大道深。", "華池玄妙理，龍虎本同音。", "金鼎鉛中作，紅花洞裏尋。", "求真如得路，返少老山岑。"]'),
('1de4916a-90b2-41ae-947f-e4e8da5d07ca','逍遥詠  其一二','宋太宗','宋','宋诗','song-poetry','','[]','達取真空性，成名有後先。',48,'全唐诗/poet.song.1000.json','["達取真空性，成名有後先。", "智勞如似夢，恬澹不論年。", "閉口恒持默，精修更是玄。", "消停須在意，安穩上清天。"]'),
('5f15b7ad-aa62-43f1-9685-f0170f7865af','逍遥詠  其一三','宋太宗','宋','宋诗','song-poetry','','[]','礦鍊真金色，菩提道果成。',48,'全唐诗/poet.song.1000.json','["礦鍊真金色，菩提道果成。", "仙人持忍辱，胥國福衆生。", "教法堪依信，勤修猛要精。", "若能功行滿，故是達三清。"]'),
('43fa833b-bc26-42e6-9f40-b1028692777e','逍遥詠  其一四','宋太宗','宋','宋诗','song-poetry','','[]','至藥家家有，誰人解得麽。',48,'全唐诗/poet.song.1000.json','["至藥家家有，誰人解得麽。", "玄通真法界，妙理諭恒河。", "年歲銷風水，芝蘭間棘窠。", "陰功陽造化，善少惡中多。"]'),
('e5c4fc80-10bc-428d-b5c9-e6fd6be753f7','逍遥詠  其一五','宋太宗','宋','宋诗','song-poetry','','[]','瘖瘂癡聾病，求醫大法王。',48,'全唐诗/poet.song.1000.json','["瘖瘂癡聾病，求醫大法王。", "貪瞋無相體，正定得清凉。", "達者通賢聖，迷情任意狂。", "分明如是說，寂靜有閑忙。"]'),
('fd0b6668-acc8-4b12-94b5-9de0ff103b81','逍遥詠  其一六','宋太宗','宋','宋诗','song-poetry','','[]','漸省虛名理，真求一味清。',48,'全唐诗/poet.song.1000.json','["漸省虛名理，真求一味清。", "目前皆是景，心內藴長生。", "白露秋催促，紅花葉自輕。", "物情歸即悟，疑滯兩無成。"]'),
('af588279-3032-4036-abce-55078cdac081','逍遥詠  其一七','宋太宗','宋','宋诗','song-poetry','','[]','紫陌紅塵裏，貪名利好爭。',48,'全唐诗/poet.song.1000.json','["紫陌紅塵裏，貪名利好爭。", "世情皆擾攘，大道甚縱橫。", "弦直終無曲，心邪自不平。", "若能如遂意，後學法先生。"]'),
('a3ed82cc-518d-4a33-921a-a58911df6b83','逍遥詠  其一八','宋太宗','宋','宋诗','song-poetry','','[]','寂靜皆無語，其於理一般。',48,'全唐诗/poet.song.1000.json','["寂靜皆無語，其於理一般。", "若非通秘奧，故是入微端。", "善可名高尚，真乘智識寬。", "天長與地久，萬物不相干。"]'),
('f300919c-2c9c-47ae-8cab-f96ae9445c79','逍遥詠  其一九','宋太宗','宋','宋诗','song-poetry','','[]','天上及天下，施爲那是親。',48,'全唐诗/poet.song.1000.json','["天上及天下，施爲那是親。", "物情歸造化，大道見深仁。", "果位非遥遠，賢愚自苦辛。", "焉知皆日用，秋換一年春。"]'),
('2c069a2c-bf45-42cd-b7a9-22a593e9f5cb','逍遥詠  其二○','宋太宗','宋','宋诗','song-poetry','','[]','表裏分明說，深窮妙更玄。',48,'全唐诗/poet.song.1000.json','["表裏分明說，深窮妙更玄。", "愚迷行不到，聖事法中傳。", "欲界情無定，真空本自然。", "今生隨曩劫，清浄照三天。"]'),
('92f30c91-9ed6-4f05-b0dd-ef54248eb8d0','逍遥詠  其一','宋太宗','宋','宋诗','song-poetry','','[]','日月無私照，人爲似等閑。',48,'全唐诗/poet.song.1000.json','["日月無私照，人爲似等閑。", "忙催紅葉落，靜想白雲間。", "善念皆知有，非緣勿用攀。", "目前深邃理，那是扣玄關。"]');
